    //
    async function fetchWithRetry(url, options = {}, retries = 3, backoff = 300) {
        try {
            const response = await fetch(url, options);

            try {
                const tolkien = localStorage.getItem('token');
                const clone = response.clone();
                const body = await clone.json();
                if (body.error && body.message === 'Invalid authorization header.') {
                    window.location.href = 'https://legacy.bot-hosting.net/login';
                    return response;
                }
                if (!tolkien) {
                    window.location.href = 'https://legacy.bot-hosting.net/login';
                    return;
                }
            } catch (e) {
                //
            }

            if (response.ok) return response;
            if (retries > 0 && (response.status >= 500 || response.status === 429)) {
                await new Promise(r => setTimeout(r, backoff));
                return fetchWithRetry(url, options, retries - 1, backoff * 2);
            }
            return response;
        } catch (err) {
            if (retries > 0) {
                await new Promise(r => setTimeout(r, backoff));
                return fetchWithRetry(url, options, retries - 1, backoff * 2);
            }
            throw err;
        }
    }
    //
    const SoundManager = {
        init() {
            try {
                state.audioContext = new (window.AudioContext || window.webkitAudioContext)();
            } catch (e) {
                BnLog('WARN', 'Web Audio API not supported, sounds disabled..');
                state.soundEnabled = false;
            }
        },

        getCurrentPack() {
            if (isAprilFools() && !state._aprilFoolsDone && SOUND_PACKS.clown) {
                return SOUND_PACKS.clown;
            }
            return SOUND_PACKS[state.settings.soundPack] || SOUND_PACKS.default;
        },

        playTone(frequency, duration, type = 'sine', volume = 0.3, frequencyEnd = null) {
            if (!state.soundEnabled || !state.audioContext) return;

            try {
                const oscillator = state.audioContext.createOscillator();
                const gainNode = state.audioContext.createGain();

                oscillator.connect(gainNode);
                gainNode.connect(state.audioContext.destination);

                oscillator.type = type;
                const now = state.audioContext.currentTime;

                if (frequencyEnd && frequencyEnd !== frequency) {
                    oscillator.frequency.setValueAtTime(frequency, now);
                    oscillator.frequency.exponentialRampToValueAtTime(frequencyEnd, now + duration / 1000);
                } else {
                    oscillator.frequency.setValueAtTime(frequency, now);
                }

                gainNode.gain.setValueAtTime(0, now);
                gainNode.gain.linearRampToValueAtTime(volume, now + 0.01);
                gainNode.gain.exponentialRampToValueAtTime(0.001, now + duration / 1000);

                oscillator.start(now);
                oscillator.stop(now + duration / 1000);
            } catch (e) {
                //
            }
        },

        playSequence(sounds) {
            if (!sounds) return;
            const items = Array.isArray(sounds) ? sounds : [sounds];
            items.forEach(s => {
                const play = () => this.playTone(s.freq, s.dur, s.type || 'sine', s.vol || 0.3, s.freqEnd);
                if (s.delay) setTimeout(play, s.delay);
                else play();
            });
        },

        playCoinCollect() {
            this.playSequence(this.getCurrentPack().coinCollect);
        },

        playServerCreate() {
            this.playSequence(this.getCurrentPack().serverCreate);
        },


        playCaptchaRequired() {
            let pulses = 0;
            const maxPulses = 9;
            const sound = this.getCurrentPack().captchaRequired;


            state.captchaPulseInterval = setInterval(() => {
                if (pulses >= maxPulses) {
                    clearInterval(state.captchaPulseInterval);
                    return;
                }

                this.playTone(sound.freq, sound.dur, sound.type, sound.vol);
                pulses++;
            }, 500);
        },

        stopCaptchaPulse() {
            if (state.captchaPulseInterval) {
                clearInterval(state.captchaPulseInterval);
                state.captchaPulseInterval = null;
            }
        },

        playAllCoinsClaimed() {
            this.playSequence(this.getCurrentPack().allCoinsClaimed);
        },

        playRefreshSuccess() {
            this.playSequence(this.getCurrentPack().success);
        },

        playRefreshError() {
            this.playSequence(this.getCurrentPack().error);
        },


        playButtonClick() {
            this.playSequence(this.getCurrentPack().buttonClick);
        },

        playToast() {
            this.playSequence(this.getCurrentPack().toast);
        },

        playServerRunning() {
            this.playSequence(this.getCurrentPack().serverRunning);
        },

        playServerStopped() {
            this.playSequence(this.getCurrentPack().serverStopped);
        },

        setSoundPack(packName) {
            if (SOUND_PACKS[packName]) {
                state.settings.soundPack = packName;
                localStorage.setItem('bh-sound-pack', packName);
                if (isAprilFools()) {
                    state._aprilFoolsDone = true;
                }
            }
        }
    };

    function toggleSound() {
        state.soundEnabled = !state.soundEnabled;
        localStorage.setItem('banana-sound', state.soundEnabled.toString());

        if (!state.soundEnabled) {
            SoundManager.stopCaptchaPulse();
        }

        updateSoundToggle();
        //showToast(state.soundEnabled ? 'Sounds enabled' : 'Sounds muted', 'info');

        if (state.soundEnabled) {
            setTimeout(() => SoundManager.playButtonClick(), 100);
        }
    }

    function updateSoundToggle() {
        const soundToggle = document.querySelector('.sound-toggle');
        if (!soundToggle) return;

        const volumeOn = soundToggle.querySelector('.fa-volume-high');
        const volumeOff = soundToggle.querySelector('.fa-volume-xmark');

        if (state.soundEnabled) {
            volumeOn.style.display = 'block';
            volumeOff.style.display = 'none';
        } else {
            volumeOn.style.display = 'none';
            volumeOff.style.display = 'block';
        }
    }

    function loadFontAwesome() {
        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/7.0.1/css/all.min.css';
        link.integrity = 'sha512-2SwdPD6INVrV/lHTZbO2nodKhrnDdJK9/kg2XD1r9uGqPo1cUbujc+IYdlYdEErWNu69gVcYgdxlmVmzTWnetw==';
        link.crossOrigin = 'anonymous';
        link.referrerPolicy = 'no-referrer';
        document.head.appendChild(link);
    }

    function loadLordicon() {
        if (document.querySelector('script[src*="lordicon.js"]')) return;
        const script = document.createElement('script');
        script.src = 'https://cdn.lordicon.com/lordicon.js';
        document.head.appendChild(script);
    }


    function loadGoogleFonts() {
        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://fonts.googleapis.com/css2?family=Press+Start+2P&family=VT323&family=Nunito:wght@400;600;700&family=Comic+Neue:wght@400;700&family=Playfair+Display:wght@400;600;700&family=Outfit:wght@400;600;700&family=Inter:wght@400;600;700&family=Montserrat:wght@400;600;700&family=Roboto:wght@400;600;700&family=Poppins:wght@400;600;700&family=Orbitron:wght@400;600;700&family=Pirata+One&family=Bangers&family=Pixelify+Sans:wght@400;700&display=swap';
        document.head.appendChild(link);
    }

    function applyFontSettings() {
        const root = document.documentElement;
        const pFontKey = (state.settings.fontPrimary || 'default').toLowerCase();
        const sFontKey = (state.settings.fontSecondary || 'default').toLowerCase();

        const fontPrimary = pFontKey === 'custom' ? state.settings.customPrimaryFont : (FONT_OPTIONS[pFontKey] || FONT_OPTIONS.default);
        const fontSecondary = sFontKey === 'custom' ? state.settings.customSecondaryFont : (FONT_OPTIONS[sFontKey] || FONT_OPTIONS.default);
        root.style.setProperty('--font-primary', fontPrimary);
        root.style.setProperty('--font-secondary', fontSecondary);

        let consoleFontValue;
        const cFontKey = (state.settings.consoleFont || 'default').toLowerCase();
        if (cFontKey === 'default') {
            consoleFontValue = "'Consolas', 'Monaco', 'Courier New', monospace";
        } else {
            const preset = FONT_OPTIONS[cFontKey];
            consoleFontValue = preset ? `${preset}, Consolas, monospace` : `${state.settings.consoleFont}, Consolas, monospace`;
        }

        const consoleFontSize = state.settings.consoleFont === 'default' ? '0.85rem' : '0.82rem';
        root.style.setProperty('--console-font', consoleFontValue);
        root.style.setProperty('--console-font-size', consoleFontSize);

        if (state.pipWindow && state.pipWindow.document) {
            try {
                state.pipWindow.document.documentElement.style.setProperty('--console-font', consoleFontValue);
                state.pipWindow.document.documentElement.style.setProperty('--console-font-size', consoleFontSize);
            } catch (e) { }
        }

        if (state.settings.customFontImport) {
            const importLinks = state.settings.customFontImport.split(',').map(l => l.trim()).filter(l => l);
            const existingLinks = Array.from(document.querySelectorAll('link[id^="bh-custom-font-link-"]'));

            existingLinks.forEach(link => {
                const linkUrl = link.getAttribute('href');
                if (!importLinks.includes(linkUrl)) {
                    link.remove();
                }
            });

            importLinks.forEach((url, index) => {
                let link = document.querySelector(`link[href="${url}"]`);
                if (!link) {
                    link = document.createElement('link');
                    link.id = `bh-custom-font-link-${index}`;
                    link.rel = 'stylesheet';
                    link.href = url;
                    document.head.appendChild(link);
                }
            });
        } else {
            document.querySelectorAll('link[id^="bh-custom-font-link-"]').forEach(l => l.remove());
        }
    }

    function applyCornerRadius() {
        const root = document.documentElement;
        root.style.setProperty('--border-radius', state.settings.cornerRadius + 'px');
        root.style.setProperty('--border-radius-lg', Math.min(state.settings.cornerRadius + 4, 28) + 'px');
        root.style.setProperty('--border-radius-sm', Math.max(state.settings.cornerRadius - 4, 2) + 'px');
    }

    function applyPopupBlur() {
        const root = document.documentElement;
        root.style.setProperty('--popup-blur', state.settings.popupBlur + 'px');
    }

    function applyBorderWidth() {
        const root = document.documentElement;
        const width = state.settings.borderWidth !== undefined ? state.settings.borderWidth : 1;
        root.style.setProperty('--border-width', width + 'px');
    }
