    function applyAllSettings() {
        applyFontSettings();
        applyCornerRadius();
        applyPopupBlur();
        applyBorderWidth();
        updateThemeTitle();
        applyThemeBackground();
        applyToastColors();
        applyCursorGlow();
        injectCursorGlowStyles();
        loadLordicon();
        //applyFavicon();
    }

    function applyFavicon() {
        let link = document.querySelector("link[rel*='icon']");
        if (!link) {
            link = document.createElement('link');
            link.rel = 'shortcut icon';
            document.head.appendChild(link);
        }
        link.href = CONFIG.FAVICON_URL;
    }

    function updateThemeTitle() {
        const titleEl = document.querySelector('.logo-text h1');
        if (titleEl) {
            titleEl.textContent = state.settings.themeTitle || 'BananaBurner 2979';
        }
    }

    function applyToastColors() {
        if (!state.settings.toastColors) return;
        const root = document.documentElement;
        Object.entries(state.settings.toastColors).forEach(([type, value]) => {
            root.style.setProperty(`--toast-${type}`, value);
        });
    }

    function applyThemeBackground() {
        if (state.settings.themeBackgroundImage) {
            document.documentElement.style.setProperty('--theme-bg-image', `url("${state.settings.themeBackgroundImage}")`);
            document.body.classList.add('has-bg-image');
        } else {
            document.documentElement.style.removeProperty('--theme-bg-image');
            document.body.classList.remove('has-bg-image');
        }
    }
    //
    function applyCursorGlow() {
        const root = document.documentElement;
        if (state.settings.cursorGlow) {
            root.style.setProperty('--cursor-glow-color', state.settings.cursorGlowColor);
            document.body.classList.add('cursor-glow-enabled');
        } else {
            document.body.classList.remove('cursor-glow-enabled');
        }
    }
    //
    function initCursorGlowTracker() {
        let rafPending = false;
        window.addEventListener('mousemove', (e) => {
            if (!state.settings.cursorGlow || rafPending) return;
            rafPending = true;
            requestAnimationFrame(() => {
                rafPending = false;
                const { clientX: x, clientY: y } = e;
                const selectors = `
          .stat-card, .module-card, .bh-container, .nav-item, .action-btn, 
          .recent-activity, .quick-actions, 
          .server-item, .activity-item, .plan-card, .module-header,
          .form-input, .form-select, .btn, .user-profile, .setting-item,
          .sftp-current, .modal-container, .profile-tab, .quick-action-card
        `.split(',').map(s => s.trim()).join(', ');

                const elements = document.querySelectorAll(selectors);

                elements.forEach(el => {
                    const rect = el.getBoundingClientRect();
                    const posX = x - rect.left;
                    const posY = y - rect.top;

                    el.style.setProperty('--mouse-x', `${posX}px`);
                    el.style.setProperty('--mouse-y', `${posY}px`);
                });
            });
        });
    }
