    const TOAST_DURATION = 4000;
    const TOAST_ANIMATION_DURATION = 400;
    const MAX_CONCURRENT_TOASTS = 4;
    const TOAST_GAP = 12;
    const TOAST_HEIGHT = 60;

    function repositionToasts() {
        const groups = {};
        document.querySelectorAll('.bh-toast').forEach(t => {
            const pos = t.dataset.position || 'bottom-right';
            if (!groups[pos]) groups[pos] = [];
            groups[pos].push(t);
        });

        Object.entries(groups).forEach(([pos, toasts]) => {
            const isTop = pos.startsWith('top');
            const isRight = pos.includes('right');

            toasts.forEach((toast, index) => {
                const offset = 20 + (index * (TOAST_HEIGHT + TOAST_GAP));

                if (isTop) {
                    toast.style.top = `${offset}px`;
                    toast.style.bottom = 'auto';
                } else {
                    toast.style.bottom = `${offset}px`;
                    toast.style.top = 'auto';
                }

                if (isRight) {
                    toast.style.right = '20px';
                    toast.style.left = 'auto';
                } else {
                    toast.style.left = '20px';
                    toast.style.right = 'auto';
                }
            });
        });
    }

    function showToast(msg, type = 'info') {
        const existing = document.querySelector('.toast-container');
        if (existing) existing.remove();
        const colors = {
            info: 'var(--toast-info)',
            success: 'var(--toast-success)',
            error: 'var(--toast-error)',
            warn: 'var(--toast-warn)',
            coins: 'var(--toast-coins)',
            banana: 'var(--toast-banana)'
        };

        const icons = {
            info: 'fas fa-info-circle',
            success: 'fas fa-check-circle',
            error: 'fas fa-exclamation-circle',
            warn: 'fas fa-exclamation-triangle',
            coins: 'fas fa-coins',
            banana: 'fas fa-star'
        };

        state.toastQueue.push({ msg, type, colors, icons });
        processToastQueue();
    }

    function processToastQueue() {
        if (state.showingToasts >= MAX_CONCURRENT_TOASTS || state.toastQueue.length === 0) {
            return;
        }

        const { msg, type, colors, icons } = state.toastQueue.shift();
        state.showingToasts++;

        const position = state.settings.notifications.position || 'bottom-right';
        const isTop = position.startsWith('top');
        const isRight = position.includes('right');

        const toast = document.createElement('div');
        toast.className = `bh-toast bh-toast-${type}`;
        toast.dataset.position = position;

        DOMUpdater.render(`
      <div class="toast-icon">
        <i class="${icons[type]}"></i>
      </div>
      <div class="toast-content">
        <div class="toast-message">${sanitizeHTML(msg)}</div>
      </div>
      <button class="toast-close">
        <i class="fas fa-times"></i>
      </button>
    `, toast);

        const existingInCorner = Array.from(document.querySelectorAll('.bh-toast'))
            .filter(t => (t.dataset.position || 'bottom-right') === position);

        const offset = 20 + (existingInCorner.length * (TOAST_HEIGHT + TOAST_GAP));

        Object.assign(toast.style, {
            position: 'fixed',
            [isTop ? 'top' : 'bottom']: `${offset}px`,
            [isRight ? 'right' : 'left']: '20px',
            background: colors[type],
            color: '#fff',
            padding: '10px 14px',
            borderRadius: '10px',
            boxShadow: '0 4px 20px rgba(0,0,0,0.25)',
            opacity: '0',
            transform: isRight ? 'translateX(100px)' : 'translateX(-100px)',
            transition: `all ${TOAST_ANIMATION_DURATION}ms cubic-bezier(0.68, -0.6, 0.32, 1.6), top 200ms ease, bottom 200ms ease`,
            zIndex: '10000',
            display: 'flex',
            alignItems: 'center',
            gap: '10px',
            maxWidth: '340px',
            minWidth: '260px',
            backdropFilter: 'blur(12px)',
            border: '1px solid rgba(255,255,255,0.15)',
            fontFamily: 'var(--font-primary, system-ui), sans-serif',
            fontSize: '0.875rem'
        });

        document.body.appendChild(toast);

        const closeBtn = toast.querySelector('.toast-close');
        closeBtn.style.cssText = `
      background: none;
      border: none;
      color: inherit;
      cursor: pointer;
      padding: 4px;
      border-radius: 4px;
      display: flex;
      align-items: center;
      justify-content: center;
      opacity: 0.7;
      transition: opacity 0.2s, background 0.2s;
      margin-left: auto;
      flex-shrink: 0;
      width: 22px;
      height: 22px;
      font-size: 11px;
    `;

        closeBtn.onclick = () => {
            removeToast();
        };

        closeBtn.addEventListener('mouseenter', () => {
            closeBtn.style.opacity = '1';
            closeBtn.style.background = 'rgba(255,255,255,0.15)';
        });

        closeBtn.addEventListener('mouseleave', () => {
            closeBtn.style.opacity = '0.7';
            closeBtn.style.background = 'none';
        });

        requestAnimationFrame(() => {
            toast.style.opacity = '1';
            toast.style.transform = 'translateX(0)';
        });

        const removeToast = () => {
            toast.style.opacity = '0';
            toast.style.transform = isRight ? 'translateX(100px)' : 'translateX(-100px)';
            setTimeout(() => {
                if (toast.parentNode) {
                    toast.parentNode.removeChild(toast);
                }
                state.showingToasts--;
                repositionToasts();
                if (state.toastQueue.length > 0) {
                    processToastQueue();
                }
            }, TOAST_ANIMATION_DURATION);
        };

        setTimeout(() => {
            if (toast.parentNode && document.body.contains(toast)) {
                removeToast();
            }
        }, TOAST_DURATION);

        setTimeout(processToastQueue, 80);
    }

    function handleUnauthorizedState() {
        state.controlPanelStatus = 'unauthorized';
        if (!state.mainAppInitialized) {
            state.pendingAuthAlert = 'login_required';
        } else if (!state.authPopupDismissed) {
            showLoginRequiredModal();
        }
    }

    async function checkControlPanelStatus() {
        if (state.statusCheckInProgress) return;
        state.statusCheckInProgress = true;

        try {
            const timeout = state.settings.lazyLoad ? 10000 : 6500;
            const probePromise = callProxyFetch(`https://control.bot-hosting.net/api/client?count=1&_t=${Date.now()}`, {
                method: 'GET',
                headers: getControlPanelHeaders()
            });
            const response = await Promise.race([
                probePromise,
                new Promise((_, reject) => setTimeout(() => reject(new Error('Link timeout')), timeout))
            ]);

            if (response && response.ok) {
                state.controlPanelStatus = 'up';
                state.controlPanelWasUp = true;
            } else {
                if (response && (response.status === 401 || response.status === 403)) {
                    handleUnauthorizedState();
                } else {
                    state.controlPanelStatus = 'down';
                }

                if (state.controlPanelWasUp && state.controlPanelStatus === 'down') {
                    showToast('Control panel is unreachable. Some features may not work.', 'warn');
                }
            }
        } catch (error) {
            if (error.message === 'Link timeout') {
                state.controlPanelStatus = 'no_link';
                if (localStorage.getItem('OSRC') === 'true') {
                    BnLog('WARN', 'OSRC: Link timeout detected, retrying in 10s..');
                    setTimeout(checkControlPanelStatus, 10000);
                }
                BnLog('WARN', 'Extension link not found (timeout)');
            } else {
                BnLog('WARN', 'Control panel probe failed:', error.message);
                state.controlPanelStatus = 'down';
            }
        } finally {
            state.statusCheckInProgress = false;
            updateServerManagement();
            updateServerCreatorUI();
        }
    }


    async function checkApiStatus() {
        const prevStatus = state.apiStatus;
        try {
            const response = await fetchWithRetry('/api/servers?count=1&page=0', {
                method: 'GET',
                headers: getHeaders()
            });

            if (response.ok) {
                state.apiStatus = 'up';
            } else {
                state.apiStatus = 'down';
            }
        } catch (error) {
            BnLog('ERROR', 'API status check failed:', error);
            state.apiStatus = 'down';
        }

        if (state.apiStatus !== prevStatus) {
            updateServerManagement();
        }
    }

    function formatTimeUntilReset(milliseconds) {
        if (!milliseconds || milliseconds <= 0) return '...';

        const totalSeconds = Math.floor(milliseconds / 1000);
        const hours = Math.floor(totalSeconds / 3600);
        const minutes = Math.floor((totalSeconds % 3600) / 60);
        const seconds = totalSeconds % 60;

        if (hours > 0) {
            return `in ${hours}h ${minutes}m ${seconds}s`;
        } else if (minutes > 0) {
            return `in ${minutes}m ${seconds}s`;
        } else {
            return `in ${seconds}s`;
        }
    }

    function ansiToHtml(str) {
        if (!str) return '';
        const colors = {
            '30': '#1e293b', '31': '#ef4444', '32': '#22c55e', '33': '#eab308',
            '34': '#3b82f6', '35': '#a855f7', '36': '#06b6d4', '37': '#f8fafc',
            '90': '#64748b', '91': '#f87171', '92': '#4ade80', '93': '#fbbf24',
            '94': '#60a5fa', '95': '#c084fc', '96': '#22d3ee', '97': '#ffffff'
        };

        let isOverwrite = /[\r\b]/.test(str);

        let result = str
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;')
            .replace(/[\r\b]/g, '<br>');

        result = result.replace(/^(\[(\d{1,2}:\d{2}:\d{2}\s+(?:AM|PM))\])\s*/i, (match, p1) => {
            return `<span style="color: #64748b; font-weight: 500;">${p1}</span> `;
        });

        if (str.includes('[dotenv@')) {
            result = result.replace(/^((?:<span[^>]*>.*?<\/span>\s*)?)(\[dotenv@[\d.]+\])(.*)/i, (match, p1, p2, p3) => {
                return `${p1}<span style="color: #94a3b8; font-family: 'Inter', system-ui, sans-serif; font-size: 0.9em; opacity: 0.85;"><span style="font-weight: 600;">${p2}</span>${p3}</span>`;
            });
        }

        if (!str.includes('\x1B[')) {
            result = result.replace(/^((?:<span[^>]*>.*?<\/span>\s*)?)(FATAL|ERROR|WARN|WARNING):/i, (match, p1, p2) => {
                const upper = p2.toUpperCase();
                let color = '#a32d2dff';
                if (upper === 'WARN' || upper === 'WARNING') color = '#be9415ff';
                return `${p1}<span style="color: ${color}; font-weight: bold;">${upper}:</span>`;
            });
        }

        result = result.replace(/\x1B\[(\d+)?([A-K|G|H])/g, '');

        const ansiRegex = /\x1B\[(?:(\d+);)?(\d*)m/g;
        let openSpan = false;

        result = result.replace(ansiRegex, (match, p1, p2) => {
            let css = '';
            if (p2 === '0') {
                const out = openSpan ? '</span>' : '';
                openSpan = false;
                return out;
            }

            const code = p2 || '0';
            if (colors[code]) {
                css += `color: ${colors[code]};`;
            }
            if (p1 === '1') css += 'font-weight: bold;';

            const out = (openSpan ? '</span>' : '') + `<span style="${css}">`;
            openSpan = true;
            return out;
        });

        result = result.replace(/\[(\d+)?([mK])/g, '');

        if (openSpan) result += '</span>';

        result = result.replace(/^([\|/\-\\])+/, '').replace(/([\|/\-\\])+$/, '');

        let isNoise = false;
        const trimmed = str.trim();
        if (/^(\[.*\]\s*)?([\|/\-\\]|`|\\)+$/.test(trimmed)) isNoise = true;
        if (!isNoise && result.trim().length === 1 && /[\|/\-\\]/.test(result.trim())) isNoise = true;

        return { html: result, isOverwrite, isNoise };
    }

    function formatRelativeTime(timestamp) {
        if (!timestamp) return '–';
        const now = Date.now();
        let t = new Date(timestamp).getTime();

        if (isNaN(t) && typeof timestamp === 'string' && /^\d+$/.test(timestamp)) {
            const num = parseInt(timestamp);
            if (!isNaN(num)) {
                t = (num < 10000000000) ? num * 1000 : num;
            }
        }

        if (isNaN(t)) return '–';

        const diff = now - t;
        const seconds = Math.floor(diff / 1000);
        const minutes = Math.floor(seconds / 60);
        const hours = Math.floor(minutes / 60);
        const days = Math.floor(hours / 24);
        const months = Math.floor(days / 30);
        const years = Math.floor(days / 365);

        if (years > 0) return years === 1 ? '1 year ago' : `${years} years ago`;
        if (months > 0) return months === 1 ? '1 month ago' : `${months} months ago`;
        if (days > 0) return days === 1 ? '1 day ago' : `${days} days ago`;
        if (hours > 0) return hours === 1 ? '1 hour ago' : `${hours} hours ago`;
        if (minutes > 0) return minutes === 1 ? '1 minute ago' : `${minutes} minutes ago`;
        return 'Just now';
    }

    function startResetTimer() {
        if (state.coinCollector.resetTimerInterval) {
            clearInterval(state.coinCollector.resetTimerInterval);
        }

        state.coinCollector.resetTimerInterval = setInterval(() => {
            if (state.coinCollector.timeUntilReset > 1000) {
                state.coinCollector.timeUntilReset -= 1000;
                updateCoinCollectorUI();
            } else {
                state.coinCollector.timeUntilReset = 0;
                clearInterval(state.coinCollector.resetTimerInterval);
                state.coinCollector.resetTimerInterval = null;
                updateCoinCollectorUI();
                if (state.currentView === 'coins') {
                    checkCoinStatus(true);
                }
            }
        }, 1000);
    }

