    async function showSplashScreen(onProgress) {

        if (state.splashShown) return;
        state.splashShown = true;

        const urlParams = new URLSearchParams(window.location.search);
        const isSyncing = urlParams.has('telemetryToken');
        if (isSyncing && onProgress) {
            onProgress('Syncing Identity with Marketplace...');
            await new Promise(r => setTimeout(r, 450));
        }

        document.body.style.overflow = 'hidden';
        document.documentElement.style.overflow = 'hidden';
        document.body.style.position = 'fixed';
        document.body.style.width = '100%';
        document.body.style.height = '100%';

        addbananaaSplashStyles();

        const splash = document.createElement('div');
        splash.id = 'bh-splash';
        if (state.settings.splashV2) splash.classList.add('splash-v2');

        DOMUpdater.render(`
      ${!state.settings.splashV2 ? `
        <div class="splash-background">
          <div class="gradient-orbs">
            <div class="orb orb-1"></div>
            <div class="orb orb-2"></div>
            <div class="orb orb-3"></div>
          </div>
          <div class="grid-lines"></div>
          <div class="floating-particles">
            <div class="particle"></div><div class="particle"></div><div class="particle"></div>
            <div class="particle"></div><div class="particle"></div><div class="particle"></div>
          </div>
        </div>
      ` : '<div class="splash-v2-overlay"></div>'}
      <div class="splash-container">
        <div class="splash-content">
          ${!state.settings.splashV2 ? `
            <div class="main-logo">
              <div class="logo-circle">
                <div class="logo-inner"><span class="logo-icon">${getBananaAsset(128)}</span></div>
                <div class="logo-ring"></div>
                <div class="logo-glow"></div>
              </div>
            </div>
            <h1 class="splash-title">
              <span class="title-text">BananaBurner</span>
              <span class="version-badge">2979</span>
            </h1>
            <p class="splash-subtitle">OOOO OOOO AAA AAA!!!! 🐒</p>
            <div class="splash-progress">
              <div class="progress-container">
                <div class="progress-bar"><div class="progress-fill"></div><div class="progress-shine"></div></div>
              </div>
              <div class="progress-text">Initializing</div>
            </div>
          ` : `
            <div class="splash-v2-center">
              <div class="v2-circle-wrapper">
                <svg class="v2-progress-svg" viewBox="0 0 120 120">
                  <circle class="v2-progress-bg" cx="60" cy="60" r="54"></circle>
                  <circle class="v2-progress-bar" cx="60" cy="60" r="54"></circle>
                </svg>
                <div class="v2-banana">${getBananaAsset(128)}</div>
              </div>
              <div class="v2-text">Initializing</div>
            </div>
          `}
        </div>
      </div>
    `, splash);

        document.body.appendChild(splash);

        createMainOverlay();
        const mainOverlay = document.getElementById('bh-overlay');
        if (mainOverlay) mainOverlay.style.opacity = '0';

        if (mainOverlay) {
            mainOverlay.style.opacity = '0';
        }

        splash.offsetHeight;

        (async () => {
            while (!state.mainAppInitialized || state.isRedirectingToAuth) {
                await new Promise(r => setTimeout(r, 100));
            }

            if (state.isRedirectingToAuth) return;

            const progressText = splash.querySelector(state.settings.splashV2 ? '.v2-text' : '.progress-text');
            const progressFill = splash.querySelector('.progress-fill');
            if (progressFill) progressFill.style.width = '100%';

            await new Promise(r => setTimeout(r, 600));

            if (state.settings.splashV2) {
                const circle = splash.querySelector('.v2-circle-wrapper');
                const text = splash.querySelector('.v2-text');
                const banana = splash.querySelector('.v2-banana');
                const svg = splash.querySelector('.v2-progress-svg');

                if (text) text.style.opacity = '0';
                if (banana) {
                    banana.style.transition = 'opacity 0.4s ease';
                    banana.style.opacity = '0';
                }
                if (svg) {
                    svg.style.transition = 'opacity 0.4s ease';
                    svg.style.opacity = '0';
                }

                await new Promise(r => setTimeout(r, 450));

                if (circle) {
                    circle.classList.add('expand-v2');
                    setTimeout(() => {
                        if (mainOverlay) mainOverlay.style.opacity = '1';
                        if (typeof window.playAllLordiconIntros === 'function') window.playAllLordiconIntros();
                    }, 400);
                }
            } else {
                if (mainOverlay) mainOverlay.style.opacity = '1';
                if (typeof window.playAllLordiconIntros === 'function') window.playAllLordiconIntros();
            }

            setTimeout(() => {
                splash.style.opacity = '0';
                setTimeout(() => {
                    if (splash.parentNode) splash.parentNode.removeChild(splash);
                    document.body.style.overflow = '';
                    if (state.pendingAuthAlert === 'login_required' && !state.authPopupDismissed) {
                        showLoginRequiredModal();
                    } else if (state.pendingAuthAlert === 'cloudflare_verify') {
                        showToast('Make sure Cloudflare check is passed at Control Panel.', 'warn', 8000);
                    }
                    document.documentElement.style.overflow = '';
                    document.body.style.position = '';
                    document.body.style.width = '';
                    document.body.style.height = '';
                    setupLordiconListeners();
                }, 600);
            }, state.settings.splashV2 ? 800 : 600);
        })();
    }

