    async function initializeMainApp(onProgress) {
        const osrc = localStorage.getItem('OSRC') === 'true';
        await StartupCleanup();
        SoundManager.init();
        loadCoinProgress();
        applyTheme(state.theme);
        setupKeyboardNavigation();
        setupEasterEggs();
        initAprilFools();
        setupShortcutListeners();

        if (state.coinCollector.bananaMode) {
            document.body.classList.add('banana-mode');
            applyBananaModeStyles();
            updateBananaIcons();
        }

        if (onProgress) onProgress('Verifying Extension Link...');
        if (state.settings.lazyLoad) {
            checkControlPanelStatus();
        } else {
            await checkControlPanelStatus();
        }

        if (state.controlPanelStatus === 'unauthorized') {

            state.pendingAuthAlert = 'login_required';
        } else if (state.controlPanelStatus === 'up') {
            /*const cloudf = document.cookie.split('; ').find(row => row.startsWith('cf_clearance='))?.split('=')[1];
            if (!cloudf) {
              state.pendingAuthAlert = 'cloudflare_verify';
            }*/
        }

        if (onProgress) onProgress('Connecting to Bothosting API...');

        if (onProgress) onProgress('Thonking...');
        await new Promise(r => setTimeout(r, 150));

        if (onProgress) onProgress('Fetching User Profile...');
        await fetchUserData(!!onProgress);

        if (onProgress) onProgress('STEALING BANANAS!');
        await new Promise(r => setTimeout(r, 150));

        if (onProgress) onProgress('Loading Server List...');
        await fetchServers(!!onProgress);

        const syncCP = async () => {
            try {
                await Promise.race([
                    fetchControlPanelServers(),
                    new Promise(r => setTimeout(r, 5000))
                ]);
            } catch (e) {
                BnLog('ERROR', 'Control Panel sync failed, continuing:', e);
            }
        };
        if (state.settings.lazyLoad) {
            syncCP();
        } else {
            if (onProgress) onProgress('Syncing with Control Panel...');
            await syncCP();
        }

        if (onProgress) onProgress('Injecting bananas into core...');
        await new Promise(r => setTimeout(r, 150));

        if (onProgress) onProgress('Synchronizing Transactions...');
        loadActivityCache();
        if (state.settings.lazyLoad) {
            fetchTransactions(true);
        } else {
            await fetchTransactions(true);
        }



        const backgroundInterval = osrc ? 30000 : 120000;
        const resourcesInterval = osrc ? 45000 : 120000;
        const transactionsInterval = osrc ? 30000 : 60000;

        setInterval(() => {
            if (state.editorActive) return;
            checkControlPanelStatus();
        }, backgroundInterval);
        if (onProgress) onProgress('Loading plugins...');
        await migrateLegacyInstalls();
        await autoLoadPlugins();
        checkVersionAndShowChangelog();

        setInterval(() => {
            if (state.editorActive) return;
            checkApiStatus();
        }, backgroundInterval);
        if (osrc) {
            setInterval(() => {
                if (state.editorActive) return;
                fetchUserData();
            }, backgroundInterval);
            setInterval(() => {
                if (state.editorActive) return;
                fetchServers();
            }, backgroundInterval);
        }
        setInterval(() => {
            if (state.editorActive) return;
            fetchTransactions();
        }, transactionsInterval);
        setInterval(() => {
            if (state.editorActive) return;
            fetchAllControlPanelResources();
        }, resourcesInterval);
        setInterval(async () => {
            if (state.editorActive) return;
            try {
                const res = await callProxyFetch('https://control.bot-hosting.net/api/client', { method: 'GET', headers: getControlPanelHeaders() });
                state.controlPanelStatus = res && res.ok ? 'up' : 'down';
                const modal = document.getElementById('bh-server-details-modal');
                if (modal) {
                    const serverId = state.controlPanel.selectedServerId;
                    const details = state.serverDetailsCache[serverId]?.data;
                    const isSuspended = details ? (!!details.suspended) : false;
                    if (details?.identifier && !isSuspended) refreshServerDetailsModalResources(details.identifier);
                }
            } catch (e) { state.controlPanelStatus = 'down'; }
        }, 30000);

        if (onProgress) onProgress('Creating Marketplace session...');
        if (await bbAuth(onProgress)) return;
        //showToast('BananaBurner 2979 ready!', 'success');
        if (onProgress) onProgress('Banana-core READY!!!');
        if (window.__bh_pending_toast) {
            showToast(window.__bh_pending_toast, 'error');
            delete window.__bh_pending_toast;
        }
        await new Promise(r => setTimeout(r, 150));
    }

    function getHeaders() {
        const token = localStorage.getItem('token') || '';
        const sanitizedToken = typeof token === 'string' ? token.replace(/[^\x20-\x7E]/g, '') : '';
        return {
            'Authorization': sanitizedToken,
            'Content-Type': 'application/json',
            'Accept': 'application/json'
        };
    }

    function getControlPanelHeaders() {
        const xsrfToken = document.cookie.split('; ').find(row => row.startsWith('XSRF-TOKEN='))?.split('=')[1];
        const decodedToken = xsrfToken ? decodeURIComponent(xsrfToken) : '';
        return {
            'Accept': 'application/json',
            'Content-Type': 'application/json',
            'X-XSRF-TOKEN': decodedToken,
            'X-Requested-With': 'XMLHttpRequest'
        };
    }

    function isServerOwner() {
        const serverId = state.controlPanel.selectedServerId;
        const details = state.serverDetailsCache[serverId]?.data;

        if (details?.server_owner === true) return true;

        if (details?.identifier && state.controlPanel.servers?.length) {
            const pteroServer = state.controlPanel.servers.find(
                s => (s.attributes?.identifier || s.identifier) === details.identifier
            );
            if (pteroServer) {
                const isOwner = pteroServer.attributes?.server_owner ?? pteroServer.server_owner;
                if (isOwner === true) {
                    details.server_owner = true;
                    return true;
                }
            }
        }

        return false;
    }

    function getServerPermissions(serverId) {
        if (isServerOwner()) return ['*'];

        const details = state.serverDetailsCache[serverId]?.data;
        let perms = null;

        const findInObj = (obj) => {
            if (!obj) return null;
            if (obj.meta && Array.isArray(obj.meta.user_permissions)) return obj.meta.user_permissions;
            if (obj.attributes?.meta && Array.isArray(obj.attributes.meta.user_permissions)) return obj.attributes.meta.user_permissions;

            if (Array.isArray(obj.user_permissions)) return obj.user_permissions;
            if (obj.attributes && Array.isArray(obj.attributes.user_permissions)) return obj.attributes.user_permissions;

            if (Array.isArray(obj.permissions)) return obj.permissions;
            if (obj.attributes && Array.isArray(obj.attributes.permissions)) return obj.attributes.permissions;

            if (obj.meta && Array.isArray(obj.meta.permissions)) return obj.meta.permissions;
            if (obj.attributes?.meta && Array.isArray(obj.attributes.meta.permissions)) return obj.attributes.meta.permissions;

            return null;
        };

        perms = findInObj(details);

        if (!perms) {
            const allCP = [...(state.controlPanel.servers || []), ...(state.controlPanel.sharedServers || [])];
            const cpServer = allCP.find(s =>
                s.attributes?.identifier === serverId || s.identifier === serverId ||
                (details && (s.attributes?.identifier === details.identifier || s.identifier === details.identifier))
            );
            if (cpServer) {
                perms = findInObj(cpServer);
            }
        }

        if (CONFIG.DEBUG) {
            BnLog('AUTH', `Permission Lookup for ${serverId}:`, {
                found: !!perms,
                perms: perms,
                detailsHasMetaPerms: !!(details?.meta?.user_permissions || details?.meta?.permissions),
                serverType: details?.is_shared ? 'shared' : 'owned'
            });
        }

        return perms || [];
    }

    function hasPermission(perm) {
        const serverId = state.controlPanel.selectedServerId;
        const perms = getServerPermissions(serverId);

        if (perms.includes('*')) return true;

        if (perm === 'file.write' && (perms.includes('file.update') || perms.includes('file.create'))) return true;
        if (perm === 'file.read' && perms.includes('file.read-content')) return true;
        if (perm === 'file.read-content' && perms.includes('file.read')) return true;

        return perms.includes(perm);
    }

