    async function callProxyFetch(url, options = {}) {
        return new Promise((resolve, reject) => {
            const requestId = Math.random().toString(36).substring(7);
            const handler = (event) => {
                if (event.data.source === 'banana-burner-response' && event.data.requestId === requestId) {
                    window.removeEventListener('message', handler);
                    if (event.data.response.success) {
                        resolve(event.data.response);
                    } else {
                        reject(new Error(event.data.response.error));
                    }
                }
            };
            window.addEventListener('message', handler);

            const proxyOptions = { ...options };
            if (proxyOptions.signal) {
                if (proxyOptions.signal.aborted) {
                    window.removeEventListener('message', handler);
                    return reject(new Error('Proxy fetch aborted'));
                }
                delete proxyOptions.signal;
            }

            window.postMessage({
                source: 'banana-burner',
                nonce: resolveBridgeNonce(),
                action: 'proxyFetch',
                requestId,
                url,
                options: proxyOptions
            }, '*');

            setTimeout(() => {
                window.removeEventListener('message', handler);
                reject(new Error('Proxy fetch timeout'));
            }, 30000);
        });
    }

    async function getExtensionStatus() {
        return new Promise(async (resolve) => {
            let nonce = resolveBridgeNonce();
            if (!nonce) {
                for (let i = 0; i < 10; i++) {
                    await new Promise(r => setTimeout(r, 100));
                    nonce = resolveBridgeNonce();
                    if (nonce) break;
                }
            }

            const requestId = Math.random().toString(36).substring(7);
            const handler = (event) => {
                if (event.data.source === 'banana-burner-response' && event.data.requestId === requestId) {
                    window.removeEventListener('message', handler);
                    resolve(event.data.response || {});
                }
            };
            window.addEventListener('message', handler);
            window.postMessage({
                source: 'banana-burner',
                nonce: nonce,
                action: 'getStatus',
                requestId
            }, '*');
            setTimeout(() => {
                window.removeEventListener('message', handler);
                resolve({});
            }, 5000);
        });
    }

    async function fetchControlPanelServers(page = 1) {
        if (state.controlPanelStatus !== 'up' && !state.settings.lazyLoad) return;
        try {
            const response = await callProxyFetch(`https://control.bot-hosting.net/api/client?page=${page}`, {
                method: 'GET',
                headers: getControlPanelHeaders()
            });

            if (response.ok) {
                const data = response.data;
                if (page === 1) state.controlPanel.servers = [];

                const servers = data.data || [];
                state.controlPanel.servers = [...state.controlPanel.servers, ...servers];

                const meta = data.meta?.pagination;
                if (meta && meta.current_page < meta.total_pages) {
                    await fetchControlPanelServers(meta.current_page + 1);
                } else {
                    state.controlPanel.lastFetch = Date.now();

                    try {
                        const ownedIdentifiers = new Set();
                        for (const server of state.serverCreator.servers) {
                            const cached = state.serverDetailsCache?.[server.serverid]?.data;
                            if (cached?.identifier) ownedIdentifiers.add(cached.identifier);
                        }
                        const ownedNames = new Set(state.serverCreator.servers.map(s => s.name));
                        state.controlPanel.sharedServers = state.controlPanel.servers.filter(s => {
                            const attr = s.attributes;
                            if (!attr) return false;
                            if (attr.server_owner === true) return false;
                            if (ownedIdentifiers.has(attr.identifier)) return false;
                            if (ownedNames.has(attr.name)) return false;
                            return true;
                        });
                    } catch (e) {
                        BnLog('ERROR', 'Failed to compute shared servers:', e);
                        state.controlPanel.sharedServers = [];
                    }

                    updateQuickActionsGrid();
                    updateServerManagement();
                    emitPluginEvent('serversUpdated', state.controlPanel.servers);
                }
                return true;
            } else if (response.status === 401 || response.status === 403) {
                handleUnauthorizedState();
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch control panel servers:', error);
        }
        return false;
    }

    async function fetchServerResources(identifier) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(`https://control.bot-hosting.net/api/client/servers/${identifier}/resources`, {
                method: 'GET',
                headers: getControlPanelHeaders()
            });

            if (response && response.ok) {
                const data = response.data;
                if (data && data.attributes) {
                    const res = data.attributes.resources;
                    state.controlPanel.resources[identifier] = {
                        data: data.attributes,
                        timestamp: Date.now()
                    };
                    return data.attributes;
                }
            } else if (response && response.status === 409) {
                const serverId = state.controlPanel.selectedServerId;
                if (serverId && state.serverDetailsCache[serverId]) {
                    const details = state.serverDetailsCache[serverId].data;
                    const attrs = details.attributes || (details.data && details.data.attributes) || details;
                    const finalAttrs = attrs.attributes || attrs;
                    if (finalAttrs && typeof finalAttrs === 'object') {
                        finalAttrs.is_installing = true;
                    }
                }
                const mockResources = { resources: { cpu_absolute: 0, memory_bytes: 0, disk_bytes: 0, uptime: 0 }, is_installing: true };
                state.controlPanel.resources[identifier] = { data: { attributes: mockResources }, timestamp: Date.now() };
                return mockResources;
            } else if (response && (response.status === 401 || response.status === 403)) {
                handleUnauthorizedState();
            }
        } catch (error) {
            BnLog('ERROR', `Failed to fetch resources for ${identifier}:`, error);
        }
        return null;
    }

    async function fetchPterodactylServerDetails(identifier) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(`https://control.bot-hosting.net/api/client/servers/${identifier}`, {
                method: 'GET',
                headers: getControlPanelHeaders()
            });

            if (response && response.ok) {
                return response.data;
            }
        } catch (error) {
            BnLog('ERROR', `Failed to fetch Pterodactyl details for ${identifier}:`, error);
        }
        return null;
    }

    function getServerStatus(resources) {
        if (!resources) return 'pending';

        if (resources.is_installing || resources.current_state === 'installing') return 'pending';
        if (resources.is_transferring) return 'transferring';

        let status = resources.current_state;

        if (status === 'offline' || status === 'stopping' || status === 'stopped') {
            return 'stopped';
        }

        if (status === 'starting') {
            return 'starting';
        }

        if (status === 'running') {
            return 'running';
        }

        if (status === null || status === undefined || status === 'unknown') {
            const cpu = resources.resources?.cpu_absolute || 0;
            const ram = resources.resources?.memory_bytes || 0;
            if (cpu > 0 || ram > 0) return 'running';
            if (cpu === 0 && ram === 0) return 'stopped';
            return 'pending';
        }

        return status || 'stopped';
    }

    async function fetchAllControlPanelResources() {
        if (state.controlPanelStatus !== 'up') return;
        const servers = state.serverCreator.servers;
        const sharedServers = state.controlPanel.sharedServers || [];
        if ((!servers || servers.length === 0) && sharedServers.length === 0) return;

        const isModalStale = document.getElementById('bh-server-details-modal') && window.__modalOpenTimestamp && (Date.now() - window.__modalOpenTimestamp > 45000);

        for (const server of servers) {
            const serverid = server.serverid;
            const details = state.serverDetailsCache[serverid]?.data;
            const isSuspended = details ? (!!details.suspended) : false;

            if (details?.identifier && !isSuspended) {
                if (!isModalStale || serverid === state.controlPanel.selectedServerId) {
                    await fetchServerResources(details.identifier);
                }
            }
        }

        for (const server of sharedServers) {
            const attr = server.attributes;
            if (attr && attr.identifier && !attr.is_suspended) {
                if (!isModalStale || attr.identifier === state.controlPanel.selectedServerId) {
                    await fetchServerResources(attr.identifier);
                }
            }
        }

        if (state.currentView === 'manage') {
            updateServerManagement();
        }

        const modal = document.getElementById('bh-server-details-modal');
        if (modal && modal.classList.contains('visible') && state.controlPanel.selectedServerId) {
            setTimeout(() => {
                const serverId = state.controlPanel.selectedServerId;
                const details = state.serverDetailsCache[serverId]?.data;
                if (details?.identifier) {
                    refreshServerDetailsModalResources(details.identifier);
                }
            }, 100);
        }
    }

    function formatUptime(ms) {
        if (!ms || ms <= 0) return '0s';
        const seconds = Math.floor(ms / 1000);
        const minutes = Math.floor(seconds / 60);
        const hours = Math.floor(minutes / 60);
        const days = Math.floor(hours / 24);

        if (days > 0) return `${days}d ${hours % 24}h`;
        if (hours > 0) return `${hours}h ${minutes % 60}m`;
        if (minutes > 0) return `${minutes}m ${seconds % 60}s`;
        return `${seconds}s`;
    }
    // 
    const WSManager = {
        connect: async function (identifier) {
            if (state.controlPanelStatus !== 'up') return false;
            state.controlPanel.websocket.wasManuallyDisconnected = false;
            if (state.controlPanel.websocket.isConnecting) return false;

            if (state.controlPanel.websocket.autoCloseTimeout) {
                clearTimeout(state.controlPanel.websocket.autoCloseTimeout);
                state.controlPanel.websocket.autoCloseTimeout = null;
            }
            if (state.controlPanel.websocket.instance && state.controlPanel.websocket.connected && state.controlPanel.websocket.identifier === identifier) {
                const modal = document.getElementById('bh-server-details-modal');
                const flagsContainer = modal ? modal.querySelector('.pullout-flags') : null;
                if (flagsContainer) {
                    flagsContainer.style.opacity = '1';
                    flagsContainer.style.pointerEvents = 'auto';
                    flagsContainer.classList.remove('waiting-for-console');
                    flagsContainer.classList.add('visible');
                }
                return true;
            }
            if (state.controlPanel.websocket.instance) this.close();

            state.controlPanel.websocket.isConnecting = true;
            refreshServerDetailsModalResources(identifier);

            const details = await fetchWebsocketDetails(identifier);
            if (!details || !details.socket || !details.token) return false;

            return new Promise((resolve) => {
                const modal = document.getElementById('bh-server-details-modal');
                const flags = modal ? modal.querySelectorAll('.pullout-flag') : [];
                flags.forEach(f => f.classList.add('animating-in'));

                const completeConnection = (success) => {
                    state.controlPanel.websocket.isConnecting = false;
                    const flagsContainer = modal ? modal.querySelector('.pullout-flags') : null;
                    if (flagsContainer) {
                        flagsContainer.style.opacity = '1';
                        flagsContainer.style.pointerEvents = 'auto';
                        flagsContainer.classList.remove('waiting-for-console');
                        flagsContainer.classList.add('domino-effect');
                        flagsContainer.classList.add('visible');
                    }
                    flags.forEach(f => f.classList.remove('animating-in'));
                    refreshServerDetailsModalResources(identifier);
                    resolve(success);
                };

                const timeout = setTimeout(() => {
                    WSManager.close();
                    completeConnection(false);
                }, 10000);

                try {
                    let socketUrl = details.socket;
                    if (socketUrl && !socketUrl.startsWith('ws')) {
                        socketUrl = 'wss://' + socketUrl;
                    }

                    if (socketUrl && socketUrl.includes('?')) {
                        socketUrl = socketUrl.split('?')[0];
                    }

                    if (CONFIG.DEBUG) BnLog('WS', `Handshaking with ${socketUrl}`);
                    const ws = new WebSocket(socketUrl);
                    state.controlPanel.websocket.instance = ws;
                    state.controlPanel.websocket.identifier = identifier;

                    ws.onopen = () => {
                        BnLog('WS', `Connection Established for ${identifier}`);
                        ws.send(JSON.stringify({ event: 'auth', args: [details.token] }));
                    };

                    ws.onmessage = (event) => {
                        try {
                            const data = JSON.parse(event.data);
                            WSManager.handleMessage(data, identifier);
                            if (data.event === 'auth success') {
                                clearTimeout(timeout);
                                state.controlPanel.websocket.connected = true;
                                state.controlPanel.websocket.reconnectAttempts = 0;

                                const currentRes = state.controlPanel?.resources[identifier]?.data;
                                const isOffline = currentRes && (currentRes.current_state === 'offline' || currentRes.current_state === 'stopped');

                                if (isOffline) {
                                    const historyKey = `bh-console-lines-${identifier}`;
                                    const historyLines = _ls.json(historyKey, []);
                                    if (historyLines.length > 0) {
                                        const truncationNotice = '<span style="color: #64748b; font-style: italic; opacity: 0.7;">...Saved history truncated...</span>';
                                        state.controlPanel.websocket.logs = [truncationNotice, ...historyLines];
                                        if (document.querySelector('.console-body')) {
                                            const cb = document.querySelector('.console-body');
                                            DOMUpdater.render('', cb);
                                            state.controlPanel.websocket.logs.forEach(line => {
                                                const el = document.createElement('div');
                                                el.className = 'console-line notranslate';
                                                DOMUpdater.render(line, el);
                                                cb.appendChild(el);
                                            });
                                        }
                                    }
                                }

                                ws.send(JSON.stringify({ event: 'send logs', args: [] }));
                                ws.send(JSON.stringify({ event: 'send stats', args: [] }));

                                completeConnection(true);
                            }
                        } catch (e) { BnLog('ERROR', 'WS Parse Error:', e); }
                    };

                    ws.onerror = (err) => {
                        BnLog('ERROR', `WS Error: ${err.message || err}`);
                        clearTimeout(timeout);
                        WSManager.close();
                        completeConnection(false);
                    };

                    ws.onclose = () => {
                        clearTimeout(timeout);
                        state.controlPanel.websocket.connected = false;
                        state.controlPanel.websocket.instance = null;
                        state.controlPanel.websocket.isConnecting = false;
                        if (state.pipWindow) {
                            state.pipWindow.close();
                            state.pipWindow = null;
                        }

                        if (state.settings.autoConnectConsole && state.controlPanel.selectedServerId && !state.controlPanel.websocket.wasManuallyDisconnected) {
                            const selectedDetails = state.serverDetailsCache[state.controlPanel.selectedServerId]?.data;
                            const selectedIdentifier = selectedDetails?.identifier || selectedDetails?.attributes?.identifier;

                            if (selectedIdentifier === identifier) {
                                const attempts = state.controlPanel.websocket.reconnectAttempts || 0;
                                if (attempts < 10) {
                                    state.controlPanel.websocket.reconnectAttempts = attempts + 1;
                                    const delay = Math.min(1000 * Math.pow(1.5, attempts), 15000);
                                    BnLog('WS', `Reconnecting in ${delay}ms (Attempt ${attempts + 1}/10)`);
                                    setTimeout(() => {
                                        if (state.controlPanel.selectedServerId && !state.controlPanel.websocket.connected && !state.controlPanel.websocket.wasManuallyDisconnected) {
                                            WSManager.connect(identifier);
                                        }
                                    }, delay);
                                } else {
                                    showToast('WebSocket connection repeatedly lost.', 'warn');
                                }
                            }
                        }
                        refreshServerDetailsModalResources(identifier);
                    };
                } catch (e) {
                    clearTimeout(timeout);
                    resolve(false);
                }
            });
        },

        send: function (event, args) {
            const ws = state.controlPanel.websocket.instance;
            if (ws && state.controlPanel.websocket.connected) {
                ws.send(JSON.stringify({ event, args: Array.isArray(args) ? args : [args] }));
            }
        },

        handleMessage: function (data, identifier) {
            if (state.controlPanel.websocket.identifier !== identifier) return;

            if (CONFIG.DEBUG) BnLog('DEBUG', `WS Message: ${data.event}`);
            switch (data.event) {
                case 'stats': {
                    try {
                        const stats = JSON.parse(data.args[0]);

                        state.controlPanel.resources[identifier] = {
                            data: {
                                current_state: state.controlPanel.resources[identifier]?.data?.current_state || 'unknown',
                                resources: {
                                    ...stats,
                                    network_rx_bytes: stats.network_rx_bytes || stats.rx_bytes || stats.rx || stats.network_rx || state.controlPanel.resources[identifier]?.data?.resources?.network_rx_bytes || 0,
                                    network_tx_bytes: stats.network_tx_bytes || stats.tx_bytes || stats.tx || stats.network_tx || state.controlPanel.resources[identifier]?.data?.resources?.network_tx_bytes || 0
                                },
                                is_installing: false,
                                is_transferring: false
                            },
                            timestamp: Date.now()
                        };
                        refreshServerDetailsModalResources(identifier);
                    } catch (e) { }
                    break;
                }
                case 'status': {
                    const status = data.args[0];
                    if (state.controlPanel.resources[identifier]) {
                        const oldStatus = state.controlPanel.resources[identifier].data.current_state;
                        state.controlPanel.resources[identifier].data.current_state = status;

                        if (oldStatus && oldStatus !== status) {
                            if (status === 'running') {
                                SoundManager.playServerRunning();
                            } else if (status === 'offline' || status === 'stopped') {
                                SoundManager.playServerStopped();
                            }
                        }

                        if (status === 'offline' || status === 'stopped') {
                            state.controlPanel.resources[identifier].data.resources = {
                                cpu_absolute: 0,
                                memory_bytes: 0,
                                disk_bytes: state.controlPanel.resources[identifier].data.resources?.disk_bytes || 0,
                                network_rx_bytes: 0,
                                network_tx_bytes: 0,
                                uptime: 0
                            };

                            const offlineMsg = '<span style="color: #ef4444; font-weight: bold;">Server marked as offline.</span><br>';
                            state.controlPanel.websocket.logs.push(offlineMsg);
                            if (state.controlPanel.websocket.logs.length > 500) state.controlPanel.websocket.logs.shift();

                            appendConsoleLog(identifier, false);
                        }

                        state.controlPanel.resources[identifier].timestamp = Date.now();

                        const serverId = state.controlPanel.selectedServerId;
                        if (serverId && state.serverDetailsCache[serverId]) {
                            const cached = state.serverDetailsCache[serverId].data;
                            if (cached.identifier === identifier) {
                                state.serverDetailsCache[serverId].data.status = status;
                                state.serverDetailsCache[serverId].timestamp = Date.now();
                            }
                        }

                        refreshServerDetailsModalResources(identifier);
                        updateServerManagement();
                    }
                    break;
                }
                case 'console output':
                case 'install output':
                case 'daemon message': {
                    let log = data.args[0];
                    if (log) {
                        let { html, isOverwrite, isNoise } = ansiToHtml(log);
                        if (isNoise) return;
                        const isDaemon = data.event === 'daemon message' || log.includes('[Bot-Hosting Daemon]');

                        if (isDaemon) {
                            const upperLog = log.toUpperCase();
                            let color = '#3b82f6';
                            if (upperLog.includes('ERROR') || upperLog.includes('FAILED')) color = '#ef4444';
                            else if (upperLog.includes('WARN')) color = '#eab308';

                            html = `<span style="color: ${color}; font-weight: bold;">${html}</span>`;
                        }

                        if (isOverwrite && state.controlPanel.websocket.logs.length > 0) {
                            state.controlPanel.websocket.logs[state.controlPanel.websocket.logs.length - 1] = html;
                            appendConsoleLog(identifier, true);
                        } else {
                            state.controlPanel.websocket.logs.push(html);
                            if (state.controlPanel.websocket.logs.length > 500) {
                                state.controlPanel.websocket.logs.shift();
                            }
                            appendConsoleLog(identifier, false);
                        }

                        const historyKey = `bh-console-lines-${identifier}`;
                        let historyLines = _ls.json(historyKey, []);
                        if (isOverwrite && historyLines.length > 0) {
                            historyLines[historyLines.length - 1] = html;
                        } else {
                            historyLines.push(html);
                        }
                        if (historyLines.length > 10) historyLines = historyLines.slice(-10);
                        _ls.set(historyKey, JSON.stringify(historyLines));
                    }
                    break;
                }
            }
        },

        close: function () {
            state.controlPanel.websocket.wasManuallyDisconnected = true;
            if (state.controlPanel.websocket.autoCloseTimeout) {
                clearTimeout(state.controlPanel.websocket.autoCloseTimeout);
                state.controlPanel.websocket.autoCloseTimeout = null;
            }
            if (state.controlPanel.websocket.delayedCloseTimeout) {
                clearTimeout(state.controlPanel.websocket.delayedCloseTimeout);
                state.controlPanel.websocket.delayedCloseTimeout = null;
            }
            state.controlPanel.websocket.delayedCloseIdentifier = null;

            if (state.controlPanel.websocket.instance) {
                state.controlPanel.websocket.instance.close();
            }
            state.controlPanel.websocket.instance = null;
            state.controlPanel.websocket.identifier = null;
            state.controlPanel.websocket.connected = false;
            state.controlPanel.websocket.logs = [];

            if (state.pipWindow) {
                state.pipWindow.close();
                state.pipWindow = null;
            }
        },

        scheduleClose: function () {
            if (state.controlPanel.websocket.delayedCloseTimeout) {
                clearTimeout(state.controlPanel.websocket.delayedCloseTimeout);
            }

            const identifier = state.controlPanel.websocket.identifier;
            if (!identifier) return;

            if (state.pipWindow) return;

            const osrc = localStorage.getItem('OSRC') === 'true';
            state.controlPanel.websocket.delayedCloseIdentifier = identifier;
            state.controlPanel.websocket.wasManuallyDisconnected = true;
            state.controlPanel.websocket.delayedCloseTimeout = setTimeout(() => {
                if (state.controlPanel.websocket.identifier === identifier && !state.pipWindow) {
                    this.close();
                }
            }, osrc ? 900000 : 30000);
        },

        scheduleCloseLegacy: function () {
            if (state.controlPanel.websocket.autoCloseTimeout) clearTimeout(state.controlPanel.websocket.autoCloseTimeout);
            state.controlPanel.websocket.autoCloseTimeout = setTimeout(() => {
                this.close();
                const modal = document.getElementById('bh-server-details-modal');
                if (modal) {
                    const details = state.serverDetailsCache[state.controlPanel.selectedServerId]?.data;
                    if (details?.identifier) refreshServerDetailsModalResources(details.identifier);
                }
            }, 120000);
        },

        toggle: async function (identifier) {
            if (state.controlPanel.websocket.identifier === identifier && (state.controlPanel.websocket.connected || state.controlPanel.websocket.isConnecting)) {
                this.close();
                state.controlPanel.websocket.wasManuallyDisconnected = true;
                showToast('Console connection closed', 'info');
                refreshServerDetailsModalResources(identifier);
            } else {
                state.controlPanel.websocket.wasManuallyDisconnected = false;
                showToast('Connecting to console...', 'info');
                if (await this.connect(identifier)) showToast('Console connected!', 'success');
                else showToast('Failed to connect to console', 'error');
                refreshServerDetailsModalResources(identifier);
            }
        },

        resetTimer: function () {
            if (state.controlPanel.websocket.autoCloseTimeout) {
                clearTimeout(state.controlPanel.websocket.autoCloseTimeout);
                state.controlPanel.websocket.autoCloseTimeout = null;
            }
        }
    };

    async function fetchWebsocketDetails(identifier) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(`https://control.bot-hosting.net/api/client/servers/${identifier}/websocket`, {
                method: 'GET', headers: getControlPanelHeaders()
            });
            return (response && response.ok) ? response.data?.data : null;
        } catch (e) { return null; }
    }

    async function sendServerSignal(identifier, signal) {
        if (!identifier || state.controlPanelStatus !== 'up') return;
        if (state.controlPanel.websocket.identifier !== identifier || !state.controlPanel.websocket.connected) {
            if (!(await WSManager.connect(identifier))) {
                showToast('Failed to connect to console', 'error');
                return;
            }
        }
        try {
            WSManager.send('set state', signal);
            showToast(`Signal ${signal} sent`, 'success');
        } catch (e) { showToast('Failed to send power signal', 'error'); }
    }

    let lastStopClickTime = 0;

    async function handlePowerAction(identifier, signal, btn) {
        if (state.controlPanelStatus !== 'up' || !identifier) return;

        if (signal === 'stop') {
            const now = Date.now();
            if (now - lastStopClickTime < 3000 && hasPermission('control.stop')) {
                signal = 'kill';
                showToast('Force killing server...', 'warn');
            }
            lastStopClickTime = now;
        }

        const permMap = { 'start': 'control.start', 'stop': 'control.stop', 'restart': 'control.restart', 'kill': 'control.stop' };
        if (!hasPermission(permMap[signal])) {
            showToast(`No permission to ${signal} server`, 'error');
            return;
        }
        SoundManager.playButtonClick();

        if (signal === 'stop') {
            state.controlPanel.pendingStop[identifier] = Date.now();
        } else if (signal === 'kill') {
            state.controlPanel.pendingStop[identifier] = 'killing';
        }

        const modal = document.getElementById('bh-server-details-modal');
        const powerBtns = modal ? modal.querySelectorAll('.power-btn') : [];
        const originalHtml = btn ? btn.innerHTML : '';

        powerBtns.forEach(b => b.disabled = true);
        if (btn) DOMUpdater.render('<svg class="bh-spinner" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>', btn);

        try {
            await sendServerSignal(identifier, signal);
        } finally {
            setTimeout(() => {
                if (btn) DOMUpdater.render(originalHtml, btn);
                refreshServerDetailsModalResources(identifier);
            }, 1000);
        }
    }

    function appendConsoleLog(identifier) {
        const logs = state.controlPanel.websocket.logs;
        if (logs.length === 0) return;

        const lastLog = logs[logs.length - 1];
        const isOverwrite = arguments[1] === true;

        if (state.pipWindow && state.pipWindow.document) {
            const pipConsole = state.pipWindow.document.querySelector('.console-body');
            if (pipConsole) {
                if (isOverwrite) {
                    const lastPipLine = pipConsole.lastElementChild;
                    if (lastPipLine) DOMUpdater.render(lastLog, lastPipLine);
                } else {
                    const pipLine = state.pipWindow.document.createElement('div');
                    pipLine.className = 'console-line notranslate';
                    DOMUpdater.render(lastLog, pipLine);
                    pipConsole.appendChild(pipLine);
                    if (pipConsole.children.length > 500) {
                        pipConsole.removeChild(pipConsole.firstChild);
                    }
                    pipConsole.scrollTop = pipConsole.scrollHeight;
                }
            }
        }

        const modal = document.getElementById('bh-server-details-modal');
        if (!modal) return;

        const currentId = state.controlPanel.selectedServerId;
        const details = state.serverDetailsCache[currentId]?.data;
        if (details?.identifier !== identifier) return;

        const consoleBody = modal.querySelector('.console-body');
        if (!consoleBody) return;

        if (isOverwrite) {
            const lastLine = consoleBody.lastElementChild;
            if (lastLine) {
                DOMUpdater.render(lastLog, lastLine);
            }
        } else {
            const line = document.createElement('div');
            line.className = 'console-line notranslate';
            DOMUpdater.render(lastLog, line);
            consoleBody.appendChild(line);

            if (consoleBody.children.length > 500) {
                consoleBody.removeChild(consoleBody.firstChild);
            }
            consoleBody.scrollTop = consoleBody.scrollHeight;
        }
    }


    async function peelOffConsole() {
        if (!window.documentPictureInPicture) {
            showToast('Document PiP is not supported in this browser.', 'error');
            return;
        }

        if (state.pipWindow) {
            state.pipWindow.close();
            return;
        }

        try {
            const savedDims = _ls.json('bh-pip-dimensions', { width: 500, height: 600 });
            const pipWindow = await window.documentPictureInPicture.requestWindow({
                width: savedDims.width,
                height: savedDims.height,
            });

            const saveDims = () => {
                _ls.set('bh-pip-dimensions', JSON.stringify({
                    width: pipWindow.innerWidth,
                    height: pipWindow.innerHeight
                }));
            };

            pipWindow.addEventListener('resize', saveDims);
            pipWindow.addEventListener('pagehide', saveDims);

            state.pipWindow = pipWindow;

            [...document.styleSheets].forEach((styleSheet) => {
                try {
                    const cssRules = [...styleSheet.cssRules].map((rule) => rule.cssText).join('');
                    const style = document.createElement('style');
                    style.textContent = cssRules;
                    pipWindow.document.head.appendChild(style);
                } catch (e) {
                    const link = document.createElement('link');
                    if (styleSheet.href) {
                        link.rel = 'stylesheet';
                        link.href = styleSheet.href;
                        pipWindow.document.head.appendChild(link);
                    }
                }
            });

            const fontLink = pipWindow.document.createElement('link');
            fontLink.rel = 'stylesheet';
            fontLink.href = 'https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;700&family=Inter:wght@400;600;700&family=Poppins:wght@400;600;700&display=swap';
            pipWindow.document.head.appendChild(fontLink);

            const extraStyle = document.createElement('style');
            extraStyle.textContent = `
        body { margin: 0; background: #000; overflow: hidden; height: 100vh; display: flex; flex-direction: column; font-family: 'Poppins', 'Inter', system-ui, sans-serif; }
        .console-container { display: flex !important; flex-direction: column !important; position: relative !important; top: 0 !important; left: 0 !important; transform: none !important; width: 100% !important; height: 100vh !important; visibility: visible !important; opacity: 1 !important; border:none !important; overflow: hidden !important; }
        .console-header { display: none !important; }
        .console-body { flex: 1 !important; overflow-y: auto !important; height: 100vh !important; min-height: 100vh !important; background: #000 !important; padding: 1rem !important; }
        .console-line { font-family: var(--console-font, 'Consolas', 'Monaco', 'Courier New', monospace); font-size: var(--console-font-size, 0.85rem); line-height: 1.5; color: #e2e8f0; margin-bottom: 0.25rem; white-space: pre-wrap; word-break: break-all; }
        .console-input-container { display: none !important; }
        .pip-only { display: flex !important; }
        .main-only { display: none !important; }
      `;
            pipWindow.document.head.appendChild(extraStyle);

            const mainModal = document.getElementById('bh-server-details-modal');
            const consoleContainer = mainModal?.querySelector('.console-container')?.cloneNode(true);

            if (!consoleContainer) {
                pipWindow.close();
                return;
            }

            const header = consoleContainer.querySelector('.console-header');
            if (header) header.remove();

            const inputContainer = consoleContainer.querySelector('.console-input-container');
            if (inputContainer) inputContainer.remove();

            pipWindow.document.body.appendChild(consoleContainer);

            const pipConsoleBody = consoleContainer.querySelector('.console-body');
            if (pipConsoleBody && state.controlPanel.websocket.logs.length > 0) {
                DOMUpdater.render('', pipConsoleBody);
                state.controlPanel.websocket.logs.forEach(log => {
                    const line = document.createElement('div');
                    line.className = 'console-line notranslate';
                    DOMUpdater.render(log, line);
                    pipConsoleBody.appendChild(line);
                });
            }

            pipWindow.document.body.className = document.body.className;
            pipWindow.document.documentElement.className = document.documentElement.className;
            pipWindow.document.documentElement.setAttribute('style', document.documentElement.getAttribute('style'));

            setTimeout(() => {
                const finalBody = pipWindow.document.querySelector('.console-body');
                if (finalBody) finalBody.scrollTop = finalBody.scrollHeight;
            }, 50);

            pipWindow.addEventListener('pagehide', () => {
                state.pipWindow = null;
                //showToast('PiP Console closed', 'info');
            });

        } catch (err) {
            BnLog('ERROR', 'PiP Error:', err);
            showToast('Failed to open PiP window', 'error');
        }
    }

    function refreshServerDetailsModalResources(identifier) {
        const modal = document.getElementById('bh-server-details-modal');
        if (!modal) return;

        const cpSections = modal.querySelectorAll('.cp-only');
        const isUp = state.controlPanelStatus === 'up';
        cpSections.forEach(el => el.style.display = isUp ? '' : 'none');

        const statusBadge = modal.querySelector('.modal-title .status-badge');
        const statusDot = statusBadge?.querySelector('.status-dot');
        const statusText = statusBadge?.querySelector('.status-text');
        if (statusBadge) statusBadge.style.display = isUp ? '' : 'none';

        if (!isUp) return;

        const resources = state.controlPanel.resources[identifier]?.data?.attributes || state.controlPanel.resources[identifier]?.data || state.controlPanel.resources[identifier];
        if (!resources) return;

        const isInstalling2 = resources.is_installing || resources.current_state === 'installing';
        const isTransferring = resources.is_transferring;
        const isBlockedNow = isInstalling2 || isTransferring;
        const wasBlocked = modal.dataset.wasBlocked === 'true';

        if (wasBlocked && !isBlockedNow) {
            modal.dataset.wasBlocked = 'false';
            if (modal.dataset.serverId) {
                setTimeout(() => {
                    const currentModal = document.getElementById('bh-server-details-modal');
                    if (currentModal && currentModal === modal) {
                        const existingModal = document.getElementById('bh-server-details-modal');
                        if (existingModal) {
                            existingModal.classList.remove('visible');
                            setTimeout(() => existingModal.remove(), 300);
                        }
                        setTimeout(() => {
                            showServerDetails(modal.dataset.serverId, true);
                        }, 400);
                    }
                }, 1000);
                return;
            }
        }

        if (isBlockedNow) {
            modal.dataset.wasBlocked = 'true';
        }

        const status = getServerStatus(resources);

        if (status === 'stopped' || status === 'offline') {
            delete state.controlPanel.pendingStop[identifier];
        }
        if (statusBadge) {
            const badgeClass = (status === 'starting' || status === 'pending' || status === 'transferring') ? 'pending' : (status === 'running' ? 'running' : 'stopped');
            statusBadge.className = `status-badge ${badgeClass}`;
        }
        if (statusDot) {
            statusDot.className = `status-dot ${(status === 'starting' || status === 'pending') ? 'pending' : status}`;
        }
        if (statusText) {
            statusText.textContent = (status === 'stopped') ? 'OFFLINE' : status.toUpperCase();
        }

        const startBtn = modal.querySelector('.power-btn.start');
        const stopBtn = modal.querySelector('.power-btn.stop');
        const restartBtn = modal.querySelector('.power-btn.restart');

        const isConnected = state.controlPanel.websocket.identifier === identifier && state.controlPanel.websocket.connected;

        if (isConnected && window.innerWidth > 992) {
            modal.classList.add('has-console');
            const consoleBody = modal.querySelector('.console-body');
            if (consoleBody && consoleBody.children.length === 0 && state.controlPanel.websocket.logs.length > 0) {
                DOMUpdater.render('', consoleBody);
                state.controlPanel.websocket.logs.forEach(log => {
                    const el = document.createElement('div');
                    el.className = 'console-line notranslate';
                    DOMUpdater.render(log, el);
                    consoleBody.appendChild(el);
                });
                consoleBody.scrollTop = consoleBody.scrollHeight;
            }
        } else {
            modal.classList.remove('has-console');
        }

        const isInstalling = resources.is_installing || resources.current_state === 'installing';
        const isKilling = state.controlPanel.pendingStop[identifier];
        const isActuallyKilling = isKilling === 'killing';
        const isStuckRunning = isKilling && (status === 'running' || status === 'starting');
        const isWaitingForConsole = state.settings.autoConnectConsole && !isConnected && state.controlPanelStatus === 'up';

        if (startBtn) startBtn.disabled = isInstalling || isActuallyKilling || isWaitingForConsole || (status === 'running' || status === 'starting');
        if (stopBtn) {
            if (isStuckRunning || isActuallyKilling) {
                stopBtn.classList.add('kill');
                DOMUpdater.render('<i class="fas fa-skull"></i> <span>Kill</span>', stopBtn);
                stopBtn.setAttribute('onclick', `handlePowerAction('${identifier}', 'kill', this)`);
                stopBtn.title = isActuallyKilling ? "Killing server..." : "Force kill the server";
            } else {
                stopBtn.classList.remove('kill');
                DOMUpdater.render('<i class="fas fa-stop"></i> <span>Stop</span>', stopBtn);
                stopBtn.setAttribute('onclick', `handlePowerAction('${identifier}', 'stop', this)`);
                stopBtn.title = "Click twice to force kill";
            }
            stopBtn.disabled = isInstalling || isActuallyKilling || isWaitingForConsole || (status === 'stopped' || status === 'offline');
        }
        if (restartBtn) restartBtn.disabled = isInstalling || isActuallyKilling || isWaitingForConsole || (status === 'stopped' || status === 'offline' || status === 'pending');

        if (isInstalling) {
            modal.classList.remove('has-console');
        }

        const resourcesContainer = modal.querySelector('.resources-card');
        if (resourcesContainer) {
            if (resources.is_installing || resources.is_transferring) {
                DOMUpdater.render(`<div style="display: flex; align-items: center; gap: 0.75rem; color: var(--accent-warning); justify-content: center; padding: 1rem;"><svg class="bh-spinner" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg><span style="font-weight: 600;">Server is currently ${resources.is_installing ? 'installing' : 'being transferred'}...</span></div>`, resourcesContainer);
            } else {
                const items = resourcesContainer.querySelectorAll('.metric-item div');
                if (items.length >= 6) {
                    items[0].textContent = `${(resources.resources?.cpu_absolute || 0).toFixed(1)}%`;
                    items[1].textContent = `${(resources.resources?.memory_bytes / 1024 / 1024 || 0).toFixed(0)}MB`;
                    items[2].textContent = `${(resources.resources?.disk_bytes / 1024 / 1024 || 0).toFixed(0)}MB`;
                    items[3].textContent = formatFileSize(resources.resources?.network_rx_bytes || 0);
                    items[4].textContent = formatFileSize(resources.resources?.network_tx_bytes || 0);
                    items[5].textContent = formatUptime(resources.resources?.uptime);
                }
            }
        }
        const wsStatusBtn = modal.querySelector('.ws-status-toggle');
        if (wsStatusBtn) {
            const isConnecting = state.controlPanel.websocket.isConnecting;
            const isConnected = state.controlPanel.websocket.identifier === identifier && state.controlPanel.websocket.connected;
            const wasManuallyDisconnected = state.controlPanel.websocket.wasManuallyDisconnected;
            const autoConnect = state.settings.autoConnectConsole;

            wsStatusBtn.className = `ws-status-toggle cp-only ${isConnected ? 'connected' : ''} ${isConnecting ? 'connecting' : ''}`;

            if (isConnecting) {
                DOMUpdater.render('<svg class="bh-spinner" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>', wsStatusBtn);
            } else {
                DOMUpdater.render(isConnected ? '<i class="fas fa-plug-circle-check"></i>' : '<i class="fas fa-plug-circle-xmark"></i>', wsStatusBtn);
            }

            let display = 'none';
            const serverId = modal.dataset.serverId;
            const details = serverId ? state.serverDetailsCache[serverId]?.data : null;
            const isSuspended = details ? !!details.suspended : false;
            const isBlocked = isSuspended || isBlockedNow;

            if (state.controlPanelStatus === 'up' && !isSuspended && !isBlocked) {
                if (autoConnect) {
                    if (wasManuallyDisconnected && !isConnecting) {
                        display = 'flex';
                    }
                } else if (getServerStatus(resources) !== 'offline' && !isConnecting) {
                    display = 'flex';
                }
            }
            wsStatusBtn.style.setProperty('display', display, 'important');
        }
    }

    async function fetchUserData(force = false) {
        const CACHE_KEY = 'bh-user-cache';
        const CACHE_DURATION = 60000;

        const cached = _ls.json(CACHE_KEY, null);
        BnLog('INFO', `fetchUserData: force=${force}, cached=${!!cached}`);
        if (!force && cached && cached.timestamp && (Date.now() - cached.timestamp < CACHE_DURATION)) {
            state.user = cached.data;
            state.coinCollector.currentCoins = state.user.coins || 0;
            await loadActivityCache();
            loadStats();
            loadCoinProgress();
            updateUserProfile();
            return state.user;
        }

        const prevCoins = state.coinCollector.currentCoins;
        const prevStatus = state.apiStatus;
        try {
            const url = force ? `/api/me?_=${Date.now()}` : '/api/me';
            const response = await fetchWithRetry(url, {
                method: 'GET',
                headers: getHeaders()
            });

            if (response.ok) {
                const data = await response.json();
                state.user = data;
                if (data.avatar_url) window.__bh_cacheImage(data.avatar_url);
                state.coinCollector.currentCoins = state.user.coins || 0;

                _ls.set(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));

                await loadActivityCache();
                loadStats();
                loadCoinProgress();

                if (state.coinCollector.currentCoins !== prevCoins || state.apiStatus !== prevStatus) {

                }
                updateUserProfile();
                return state.user;
            } else {
                state.apiStatus = 'down';
                if (state.apiStatus !== prevStatus) { }
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch user data:', error);
            state.apiStatus = 'down';
            if (state.apiStatus !== prevStatus) { }
        }
        return null;
    }

    async function loadActivityCache() {
        if (!state.user || !state.user.id) return;
        const key = `bh-activity-cache-${state.user.id}`;

        let cached = await AsyncCache.get(key);

        if (!cached) {
            const lsCached = _ls.json(key, null);
            if (lsCached) {
                cached = lsCached;
                await AsyncCache.set(key, cached);
                localStorage.removeItem(key);
            } else {
                const legacy = _ls.json('bh-activity-cache', []);
                if (legacy && legacy.length > 0) {
                    BnLog('INFO', `Migrating ${legacy.length} legacy activity items to user ${state.user.id}`);
                    cached = legacy;
                    await AsyncCache.set(key, cached);
                } else {
                    cached = [];
                }
            }
        }

        BnLog('INFO', `Loading Activity Cache for User ${state.user.id}:`, cached.length, 'items');
        if (cached && Array.isArray(cached)) {
            state.transactions = cached;
            cleanupActivityCache();
        }
    }

    function saveActivityCache() {
        if (!state.user || !state.user.id) return;
        const key = `bh-activity-cache-${state.user.id}`;
        AsyncCache.set(key, state.transactions);
        BnLog('INFO', `Saved Activity Cache for User ${state.user.id}: ${state.transactions.length} items`);
    }

    function cleanupActivityCache() {
        if (!state.transactions || !Array.isArray(state.transactions)) return;
        let maxDays = state.settings.activityCacheDays;
        if (isNaN(maxDays) || maxDays <= 0) maxDays = 7;

        const now = Date.now();
        const cutoff = now - (maxDays * 24 * 60 * 60 * 1000);

        const initialCount = state.transactions.length;

        const sorted = [...state.transactions].sort((a, b) => parseInt(b.date) - parseInt(a.date));

        state.transactions = sorted.filter((t, index) => {
            const date = parseInt(t.date);
            if (isNaN(date)) return false;
            return date >= cutoff || index < 20;
        });

        if (state.transactions.length > 500) {
            state.transactions = state.transactions.slice(0, 500);
        }

        if (state.transactions.length !== initialCount) {
            BnLog('INFO', `Pruned ${initialCount - state.transactions.length} items from activity cache (Kept ${state.transactions.length})`);
            saveActivityCache();
        }
    }

    async function deleteActivityHistory() {
        if (!state.user || !state.user.id) return;
        const key = `bh-activity-cache-${state.user.id}`;
        await AsyncCache.remove(key);
        state.transactions = [];
        BnLog('INFO', `activity history deleted for User ${state.user.id}`);
        showToast('Activity history cleared!', 'success');
        updateDashboard(true);
    }
    //
    async function StartupCleanup() {
        BnLog('STARTUP', 'Cleaning up..');

        try {
            const maxDays = state.settings.activityCacheDays || 7;
            const now = Date.now();
            const cutoff = now - (maxDays * 24 * 60 * 60 * 1000);

            for (let i = 0; i < localStorage.length; i++) {
                const key = localStorage.key(i);
                if (key && key.startsWith('bh-activity-cache-') && key !== 'bh-activity-cache-days') {
                    localStorage.removeItem(key);
                }
            }

            const keys = await AsyncCache.keys();
            for (const key of keys) {
                if (key.startsWith('bh-activity-cache-')) {
                    const cached = await AsyncCache.get(key);
                    if (cached && Array.isArray(cached)) {
                        const initialCount = cached.length;
                        const filtered = cached.sort((a, b) => parseInt(b.date) - parseInt(a.date)).filter((t, index) => {
                            const date = parseInt(t.date);
                            return !isNaN(date) && (date >= cutoff || index < 20);
                        });
                        if (filtered.length !== initialCount) {
                            await AsyncCache.set(key, filtered);
                            BnLog('INFO', `Pruned ${initialCount - filtered.length} expired items from ${key} (Kept ${filtered.length})`);
                        }
                    }
                }
            }
        } catch (e) {
            BnLog('WARN', 'activity cleanup failed:', e);
        }

        cleanupActivityCache();
        if (window.__bh_gcImageCache) {
            try { window.__bh_gcImageCache(); } catch (e) { BnLog('WARN', 'Image cache cleanup failed:', e); }
        }

        try {
            const serverIds = state.serverCreator.servers.map(s => s.serverid.toString());
            for (let i = 0; i < localStorage.length; i++) {
                const key = localStorage.key(i);
                if (key && key.startsWith('bh-vfs-')) {
                    const sid = key.replace('bh-vfs-', '');
                    if (serverIds.length > 0 && !serverIds.includes(sid)) {
                        localStorage.removeItem(key);
                        BnLog('INFO', `Cleaned up stale VFS data for server ${sid}`);
                    }
                }
            }
        } catch (e) {
            BnLog('WARN', 'VFS cleanup failed:', e);
        }

        if (state.serverDetailsCache && Object.keys(state.serverDetailsCache).length > 100) {
            const keys = Object.keys(state.serverDetailsCache);
            const pruned = {};
            keys.sort((a, b) => (state.serverDetailsCache[b].timestamp || 0) - (state.serverDetailsCache[a].timestamp || 0))
                .slice(0, 50)
                .forEach(k => pruned[k] = state.serverDetailsCache[k]);
            state.serverDetailsCache = pruned;
            saveServerDetailsCache();
            BnLog('INFO', 'Pruned server details cache to 50 items');
        }

        BnLog('SUCCESS', 'cleanup complete.');
    }


    async function fetchTransactions(animate = false) {
        const prevStatus = state.apiStatus;
        try {
            const response = await fetchWithRetry('/api/transactions', {
                method: 'GET',
                headers: getHeaders()
            });

            if (response.ok) {
                const apiTransactions = await response.json();
                BnLog('INFO', `API returned ${apiTransactions.length} transactions.`);

                const existingTimestamps = new Set(state.transactions.map(t => t.date.toString()));
                const newItems = apiTransactions.filter(t => !existingTimestamps.has(t.date.toString()));

                if (newItems.length > 0) {
                    const beforeCount = state.transactions.length;
                    state.transactions = [...newItems, ...state.transactions];
                    state.transactions.sort((a, b) => parseInt(b.date) - parseInt(a.date));
                    BnLog('ACTIVITY', `Merged ${newItems.length} new transactions (De-duplicated ${apiTransactions.length - newItems.length} old ones). New total: ${state.transactions.length}`);
                    cleanupActivityCache();
                    saveActivityCache();
                    updateDashboard(animate);
                } else {
                    BnLog('ACTIVITY', `No new transactions (All ${apiTransactions.length} received were already in cache). Current total: ${state.transactions.length}`);
                }

                return true;
            } else {
                state.apiStatus = 'down';
                if (state.apiStatus !== prevStatus) updateDashboard(animate);
                return false;
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch transactions:', error);
            state.apiStatus = 'down';
            if (state.apiStatus !== prevStatus) updateDashboard(animate);
            return false;
        }
    }

    async function refreshTransactionsWithAnimation() {
        SoundManager.playButtonClick();

        const refreshBtn = document.querySelector('.refresh-btn');
        if (!refreshBtn) return;

        refreshBtn.classList.add('refreshing');
        refreshBtn.disabled = true;

        const icon = refreshBtn.querySelector('lord-icon');
        if (icon) {
            icon.setAttribute('trigger', 'loop');
            icon.setAttribute('state', 'loop-autorenew');

            const startLoop = () => {
                if (icon.playerInstance) {
                    icon.playerInstance.loop = true;
                }
                playIconFromStart(icon);
            };

            if (icon.playerInstance && icon.playerInstance.ready) {
                startLoop();
            } else {
                icon.addEventListener('ready', startLoop, { once: true });
            }
        }

        const success = await fetchTransactions(true);

        setTimeout(() => {
            refreshBtn.classList.remove('refreshing');
            refreshBtn.disabled = false;
            if (icon) {
                const stopLoop = () => {
                    if (icon.playerInstance) {
                        icon.playerInstance.loop = false;
                        icon.playerInstance.pause();
                    }
                };
                icon.setAttribute('trigger', 'hover');
                icon.setAttribute('state', 'hover-autorenew');
            }

            if (success) {
                SoundManager.playRefreshSuccess();
            } else {
                SoundManager.playRefreshError();
            }
        }, 800);
    }

    async function fetchServers(force = false) {
        if (state.serverCreator.isFetchingServers) return;
        state.serverCreator.isFetchingServers = true;
        updateServerManagement();

        const prevServerCount = state.serverCreator.servers.length;
        const prevStatus = state.apiStatus;

        BnLog('INFO', `fetchServers: force=${force}`);
        const cachedStr = localStorage.getItem('bh-servers-list-cache');
        if (!force && cachedStr) {
            try {
                const cache = JSON.parse(cachedStr);
                if (cache.timestamp && (Date.now() - cache.timestamp < 270000)) {
                    state.serverCreator.servers = cache.data || [];
                    state.serverCreator.lastFetchError = false;
                    state.apiStatus = 'up';
                    state.serverCreator.isFetchingServers = false;
                    if (state.serverCreator.servers.length !== prevServerCount || state.apiStatus !== prevStatus) {
                        //
                    }
                    updateServerManagement();
                    fetchAllServerDetails();
                    fetchControlPanelServers();
                    return;
                }
            } catch (e) {
                localStorage.removeItem('bh-servers-list-cache');
            }
        }

        try {
            const url = force ? `/api/servers?count=50&page=0&_=${Date.now()}` : '/api/servers?count=50&page=0';
            const response = await fetchWithRetry(url, {
                method: 'GET',
                headers: getHeaders()
            });

            if (response.ok) {
                const data = await response.json();
                state.serverCreator.servers = data.servers || [];

                _ls.set('bh-servers-list-cache', JSON.stringify({
                    timestamp: Date.now(),
                    data: state.serverCreator.servers
                }));

                state.serverCreator.lastFetchError = false;
                state.apiStatus = 'up';
                if (state.serverCreator.servers.length !== prevServerCount || state.apiStatus !== prevStatus) {
                    //
                }
                updateServerManagement();
                fetchAllServerDetails();
                fetchControlPanelServers();
            } else {
                state.serverCreator.lastFetchError = true;
                state.apiStatus = 'down';
                if (state.apiStatus !== prevStatus) { }
                updateServerManagement();
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch servers:', error);
            state.serverCreator.lastFetchError = true;
            state.apiStatus = 'down';
            if (state.apiStatus !== prevStatus) { }
            updateServerManagement();
        } finally {
            state.serverCreator.isFetchingServers = false;
            setTimeout(() => updateServerManagement(), 500);
        }
    }

    let fetchQueue = [];
    let isProcessingQueue = false;

    function saveServerDetailsCache() {
        try {
            AsyncCache.set('bh-server-details-cache', state.serverDetailsCache);
        } catch (e) {
            BnLog('ERROR', 'Failed to save server details cache:', e);
            if (e.name === 'QuotaExceededError' || e.code === 22) {
                const keys = Object.keys(state.serverDetailsCache);
                if (keys.length > 0) {
                    keys.sort((a, b) => (state.serverDetailsCache[a].timestamp || 0) - (state.serverDetailsCache[b].timestamp || 0));
                    const toRemove = keys.slice(0, Math.ceil(keys.length / 2));
                    toRemove.forEach(k => delete state.serverDetailsCache[k]);
                    BnLog('INFO', `Quota error, Pruned ${toRemove.length} server cache entries`);
                    try {
                        AsyncCache.set('bh-server-details-cache', state.serverDetailsCache);
                    } catch (e2) {
                        BnLog('ERROR', 'second save attempt failed after pruning:', e2);
                    }
                }
            }
        }
    }

    async function fetchAllServerDetails() {
        const servers = state.serverCreator.servers;
        const now = Date.now();
        const CACHE_DURATION = 3600000;

        for (const server of servers) {
            if (!server.serverid) continue;

            const cached = state.serverDetailsCache[server.serverid];
            const isCachedValid = cached && (now - cached.timestamp < CACHE_DURATION);
            const isInQueue = fetchQueue.includes(server.serverid);

            if (!isCachedValid && !isInQueue) {
                fetchQueue.push(server.serverid);
            }
        }

        if (isProcessingQueue) return;
        isProcessingQueue = true;

        while (fetchQueue.length > 0) {
            const serverId = fetchQueue.shift();

            const cached = state.serverDetailsCache[serverId];
            if (cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
                continue;
            }

            try {
                const details = await fetchServerDetails(serverId);
                if (details) {
                    let attrs = details.attributes || (details.data && details.data.attributes) || details;

                    if (attrs.identifier && state.controlPanelStatus === 'up') {
                        const pteroDetails = await fetchPterodactylServerDetails(attrs.identifier);
                        if (pteroDetails) {
                            attrs = { ...attrs, ...(pteroDetails.attributes || pteroDetails), meta: pteroDetails.meta };
                        }
                    } else if (attrs.identifier && state.controlPanel.servers?.length) {
                        const pteroServer = state.controlPanel.servers.find(
                            s => (s.attributes?.identifier || s.identifier) === attrs.identifier
                        );
                        if (pteroServer) {
                            const pteroAttrs = pteroServer.attributes || pteroServer;
                            attrs.server_owner = pteroAttrs.server_owner;
                        }
                    }

                    state.serverDetailsCache[serverId] = {
                        data: attrs,
                        timestamp: Date.now()
                    };
                    saveServerDetailsCache();

                    const isSuspended = !!attrs.suspended;

                    if (isSuspended) {
                        if (!state.serverDetailsCache[serverId].notifiedSuspension) {
                            showToast(`${attrs.name || 'Server'} is suspended`, 'error');
                            state.serverDetailsCache[serverId].notifiedSuspension = true;
                        }
                        updateServerManagement();
                    }
                }
            } catch (err) {
                BnLog('ERROR', "Background fetch error:", err);
            }

            if (fetchQueue.length > 0) {
                await new Promise(r => setTimeout(r, 3000));
            }
        }

        isProcessingQueue = false;
    }

    async function unsuspendServer(serverId) {
        const btn = document.getElementById('unsuspend-btn');
        if (btn) {
            btn.disabled = true;
            DOMUpdater.render('<svg class="bh-spinner" style="font-size: 1.2em; margin-right: 0.1rem; vertical-align: middle;" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg> Unsuspending...', btn);
        }

        try {
            const response = await fetch('/api/servers/unsuspend', {
                method: 'PATCH',
                headers: getHeaders(),
                body: JSON.stringify({ id: parseInt(serverId) })
            });

            const data = await response.json();

            if (data.error) {
                showToast(data.message || 'Failed to unsuspend server', 'error');
            } else {
                showToast('Server unsuspended successfully!', 'success');
                delete state.serverDetailsCache[serverId];
                const existingModal = document.getElementById('bh-server-details-modal');
                if (existingModal) {
                    existingModal.classList.remove('visible');
                    setTimeout(() => existingModal.remove(), 300);
                }
                fetchUserData(true);
                setTimeout(() => {
                    showServerDetails(serverId, true);
                }, 400);
                fetchServers();
            }
        } catch (e) {
            showToast('Error unsuspending server', 'error');
        }

        if (btn) {
            btn.disabled = false;
            DOMUpdater.render('Unsuspend Server', btn);
        }
    }

    async function fetchServerDetails(serverId) {
        try {
            const response = await fetchWithRetry(`/api/servers/${serverId}`, {
                method: 'GET',
                headers: getHeaders()
            });

            if (response.ok) {
                return await response.json();
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch server details:', error);
        }
        return null;
    }
    //
    let lastCoinStatusCheck = 0;
    async function checkCoinStatus(force = false) {
        const now = Date.now();
        if (!force && (now - lastCoinStatusCheck < 30000)) {
            return state.coinCollector.lastCoinStatus;
        }
        lastCoinStatusCheck = now;
        try {
            const response = await fetchWithRetry('/api/freeCoinsStatus', {
                method: 'GET',
                headers: getHeaders()
            });

            if (response.ok) {
                const data = await response.json();
                state.coinCollector.lastCoinStatus = data;

                if (data.timeLeft !== undefined) {
                    state.coinCollector.timeUntilReset = data.timeLeft;
                    saveCoinProgress();

                    if (!state.coinCollector.resetTimerInterval && data.timeLeft > 0) {
                        startResetTimer();
                    }
                }

                return data;
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to check coin status:', error);
        }
        return null;
    }

    async function claimCoins(captchaResponse = null) {
        state.coinCollector.totalAttempts++;
        updateCoinCollectorUI();
        const payload = captchaResponse ? { hCaptchaResponse: captchaResponse } : {};

        try {
            const response = await fetch('/api/freeCoins', {
                method: 'POST',
                headers: getHeaders(),
                body: JSON.stringify(payload)
            });

            const data = await response.json();

            if (data.error || data.message === 'Must solve captcha.' || data.success === false) {
                return { success: false, error: data };
            } else {
                return { success: true, data };
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to claim coins:', error);
            return { success: false, error: { message: 'Network error' } };
        }
    }

    function createCustomHCaptcha() {
        const existingModal = document.getElementById('bh-custom-captcha-modal');
        if (existingModal) existingModal.remove();

        const modal = document.createElement('div');
        modal.id = 'bh-custom-captcha-modal';
        modal.className = 'bananaa-captcha-modal';
        DOMUpdater.render(`
      <div class="captcha-modal-overlay"></div>
      <div class="captcha-modal-container">
        <div class="captcha-modal-header">
          <div class="captcha-modal-icon">
            <i class="fas fa-shield-alt"></i>
          </div>
          <div class="captcha-modal-title">
            <h3>Security Check</h3>
            <p>Complete the CAPTCHA to continue collecting coins</p>
          </div>
          <button class="captcha-modal-close" id="bh-captcha-close">
            <i class="fas fa-times"></i>
          </button>
        </div>
        
        <div class="captcha-modal-body">
          <div class="captcha-loading" id="captcha-loading">
            <div class="vroom"></div>
            <p>Loading security check...</p>
          </div>
          <div id="bh-custom-hcaptcha-container" class="captcha-widget-container" style="display: none;"></div>
        </div>
        
        <div class="captcha-modal-footer">
          <button class="btn btn-secondary" id="bh-captcha-cancel">
            <i class="fas fa-arrow-left"></i>
            <span class="btn-text">Cancel</span>
          </button>
          <button class="btn btn-primary" id="bh-captcha-submit" style="display: none;">
            <i class="fas fa-check"></i>
            <span class="btn-text">Verify & Continue</span>
          </button>
        </div>
      </div>
    `, modal);

        document.body.appendChild(modal);
        updateModalTextColors();

        setTimeout(() => {
            modal.classList.add('visible');
        }, 50);

        window.onHcaptchaLoad = () => {
            if (document.getElementById('captcha-loading')) {
                document.getElementById('captcha-loading').style.display = 'none';
            }
            if (document.getElementById('bh-custom-hcaptcha-container')) {
                document.getElementById('bh-custom-hcaptcha-container').style.display = 'block';
            }
            renderHCaptcha();
        };

        if (!window.hcaptcha) {
            const script = document.createElement('script');
            script.src = 'https://js.hcaptcha.com/1/api.js?render=explicit&onload=onHcaptchaLoad';
            script.async = true;
            script.defer = true;
            document.head.appendChild(script);
        } else {
            window.onHcaptchaLoad();
        }

        document.getElementById('bh-captcha-close').onclick = closeCaptchaModal;
        document.getElementById('bh-captcha-cancel').onclick = closeCaptchaModal;

        function closeCaptchaModal() {
            modal.classList.remove('visible');
            setTimeout(() => {
                if (modal.parentNode) modal.parentNode.removeChild(modal);
                state.coinCollector.waitingForCaptcha = false;
                SoundManager.stopCaptchaPulse();
                //showToast('CAPTCHA cancelled', 'warn');
                setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
            }, 300);
        }

        return modal;
    }

    function renderHCaptcha() {
        const container = document.getElementById('bh-custom-hcaptcha-container');
        if (!container || !window.hcaptcha) return;

        try {
            state.coinCollector.hCaptchaWidgetId = hcaptcha.render(container, {
                sitekey: CONFIG.HCAPTCHA_SITEKEY,
                theme: document.documentElement.getAttribute('data-theme') === 'dark' ? 'dark' : 'light',
                size: 'normal',
                callback: function (response) {
                    handleHcaptchaSolved(response, true);
                },
                'expired-callback': function () {
                    const submitBtn = document.getElementById('bh-captcha-submit');
                    if (submitBtn) submitBtn.style.display = 'none';
                }
            });

            document.getElementById('bh-captcha-submit').onclick = () => {
                const response = hcaptcha.getResponse(state.coinCollector.hCaptchaWidgetId);
                if (response) {
                    handleHcaptchaSolved(response);
                } else {
                    showToast('Please complete the CAPTCHA first', 'warn');
                }
            };
        } catch (error) {
            BnLog('ERROR', 'Failed to render hCaptcha:', error);
            showToast('Failed to load CAPTCHA', 'error');
        }
    }

    function handleHcaptchaSolved(response, isAuto = false) {
        const modal = document.getElementById('bh-custom-captcha-modal');
        const submitBtn = document.getElementById('bh-captcha-submit');

        if (!isAuto) {
            if (modal) {
                modal.classList.remove('visible');
                setTimeout(() => {
                    if (modal.parentNode) modal.parentNode.removeChild(modal);
                }, 300);
            }
        } else {
            if (submitBtn) {
                submitBtn.style.display = 'flex';
                submitBtn.disabled = true;
                DOMUpdater.render('<svg class="bh-spinner" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg> Verifying...', submitBtn);
            }
        }

        state.coinCollector.waitingForCaptcha = false;
        state.coinCollector.captchaClaimInProgress = true;
        SoundManager.stopCaptchaPulse();

        showToast('Verifying CAPTCHA...', 'info');

        setTimeout(() => {
            claimCoins(response).then(async result => {
                if (result.success) {
                    if (isAuto && modal) {
                        modal.classList.remove('visible');
                        setTimeout(() => {
                            if (modal.parentNode) modal.parentNode.removeChild(modal);
                        }, 300);
                    }
                    const added = (result.data.coinsClaimed || (state.coinCollector.coinsCollected + 1)) - state.coinCollector.coinsCollected;
                    state.coinCollector.coinsCollected = result.data.coinsClaimed || (state.coinCollector.coinsCollected + 1);

                    if (added > 0) {
                        state.stats.totalCoinsCollected += added;
                        saveStats();
                    }

                    if (result.data.captcha === true) {
                        state.coinCollector.nextCoinRequiresCaptcha = true;
                    }
                    updateCaptchaPRD();
                    saveCoinProgress();
                    updateCoinCollectorUI();
                    showToast(`+1 Coin Total: ${state.coinCollector.coinsCollected}/${CONFIG.MAX_COINS_PER_DAY}`, 'coins');
                    state.coinCollector.captchaClaimInProgress = false;

                    await fetchUserData(true);

                    if (state.coinCollector.coinsCollected >= CONFIG.MAX_COINS_PER_DAY) {
                        updateCoinCollectorUI();
                        SoundManager.playAllCoinsClaimed();
                        showToast(`All done! Got all coins today!`, 'success');
                        sendOSNotification('allCoins', 'BananaBurner', 'All coins collected for today!');
                        stopCoinCollector();
                        return;
                    }

                    setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
                } else {
                    const error = result.error || {};
                    if (error.message && error.message.includes('ratelimited')) {
                        showToast('Going too fast! Waiting 15 seconds', 'warn');
                        setTimeout(attemptCoinCollection, 15000);
                        state.coinCollector.captchaClaimInProgress = false;
                    } else if (error.coinsClaimed === 10) {
                        state.coinCollector.coinsCollected = error.coinsClaimed || 10;
                        updateCoinCollectorUI();
                        SoundManager.playAllCoinsClaimed();
                        showToast(`Max coins reached! ${state.coinCollector.coinsCollected}/${CONFIG.MAX_COINS_PER_DAY} today`, 'success');
                        stopCoinCollector();
                        state.coinCollector.captchaClaimInProgress = false;
                    } else {
                        if (isAuto) {
                            if (submitBtn) {
                                submitBtn.disabled = false;
                                DOMUpdater.render('Confirm', submitBtn);
                                submitBtn.style.display = 'flex';
                            }
                            showToast('CAPTCHA verification failed, try again.', 'error');
                            state.coinCollector.captchaClaimInProgress = false;
                        } else {
                            showToast('CAPTCHA verification failed. Retrying..', 'error');
                            state.coinCollector.captchaClaimInProgress = false;
                            setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
                        }
                    }
                }
            });
        }, isAuto ? 1000 : 2500);
    }

    function handleCaptchaError(reason = 'Unknown') {
        BnLog('INFO', `Captcha required: ${reason}`);
        updateCoinCollectorUI();

        showToast('CAPTCHA required to continue', 'info');
        state.coinCollector.waitingForCaptcha = true;

        SoundManager.playCaptchaRequired();
        sendOSNotification('captcha', 'BananaBurner', 'Captcha needs solving!');

        createCustomHCaptcha();

        setTimeout(() => {
            if (state.coinCollector.waitingForCaptcha) {
                state.coinCollector.waitingForCaptcha = false;
                SoundManager.stopCaptchaPulse();
                showToast('CAPTCHA timed out', 'error');
                const modal = document.getElementById('bh-custom-captcha-modal');
                if (modal) modal.remove();
                setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
            }
        }, 300000);
    }

    async function attemptCoinCollection() {
        if (!state.coinCollector.running) return;

        if (!state.coinCollector.initialLoadComplete) {
            await InitialCheck();
            return;
        }

        const status = await checkCoinStatus(true);

        if (!status) {
            setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
            return;
        }

        state.coinCollector.coinsCollected = status.coinsClaimed || 0;
        updateCaptchaPRD();
        updateCoinCollectorUI();

        if (state.coinCollector.coinsCollected >= CONFIG.MAX_COINS_PER_DAY) {
            SoundManager.playAllCoinsClaimed();
            showToast(`All done! Got all coins today!`, 'success');
            stopCoinCollector();
            return;
        }

        if (!status.claimable) {
            const waitTime = status.timeLeft ? Math.min(status.timeLeft, CONFIG.NORMAL_COIN_INTERVAL) : CONFIG.NORMAL_COIN_INTERVAL;
            setTimeout(attemptCoinCollection, waitTime);
            return;
        }

        await claimNormalCoins();
    }

    async function claimNormalCoins() {
        if (state.coinCollector.nextCoinRequiresCaptcha) {
            state.coinCollector.nextCoinRequiresCaptcha = false;
            handleCaptchaError('Clientside frequency');
            return;
        }

        const result = await claimCoins();

        if (result.success) {
            const added = (result.data.coinsClaimed || (state.coinCollector.coinsCollected + 1)) - state.coinCollector.coinsCollected;
            state.coinCollector.coinsCollected = result.data.coinsClaimed || state.coinCollector.coinsCollected + 1;

            if (added > 0) {
                state.stats.totalCoinsCollected += added;
                saveStats();
            }

            if (result.data.captcha === true) {
                state.coinCollector.nextCoinRequiresCaptcha = true;
            }
            updateCaptchaPRD();
            saveCoinProgress();
            updateCoinCollectorUI();
            SoundManager.playCoinCollect();
            showToast(`Nice! +1 Coin! Total: ${state.coinCollector.coinsCollected}/${CONFIG.MAX_COINS_PER_DAY}`, 'coins');
            await fetchUserData(true);

            if (state.coinCollector.coinsCollected >= CONFIG.MAX_COINS_PER_DAY) {
                updateCoinCollectorUI();
                SoundManager.playAllCoinsClaimed();
                showToast(`All done! Got all coins today!`, 'success');
                stopCoinCollector();
                return;
            }

            setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
        } else {
            const error = result.error || {};
            if (error.message && error.message.includes('Must solve captcha.')) {
                handleCaptchaError('Serverside requirement');
            } else if (error.coinsClaimed === 10) {
                state.coinCollector.coinsCollected = error.coinsClaimed || 10;
                updateCoinCollectorUI();
                SoundManager.playAllCoinsClaimed();
                showToast(`Max coins reached!`, 'success');
                stopCoinCollector();
            } else {
                setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
            }
        }
    }

    async function InitialCheck() {
        if (state.coinCollector.nextCoinRequiresCaptcha) {
            state.coinCollector.nextCoinRequiresCaptcha = false;
            handleCaptchaError('Initial Load Clientside frequency');
            return;
        }

        const result = await claimCoins();

        if (result.success) {
            const added = (result.data.coinsClaimed || 1) - state.coinCollector.coinsCollected;
            state.coinCollector.coinsCollected = result.data.coinsClaimed || 1;

            if (added > 0) {
                state.stats.totalCoinsCollected += added;
                saveStats();
            }

            if (result.data.captcha === true) {
                state.coinCollector.nextCoinRequiresCaptcha = true;
            }
            updateCaptchaPRD();
            saveCoinProgress();
            updateCoinCollectorUI();
            SoundManager.playCoinCollect();
            showToast(`Got a coin! Total: ${state.coinCollector.coinsCollected}/${CONFIG.MAX_COINS_PER_DAY}`, 'coins');
            await fetchUserData(true);
            state.coinCollector.initialLoadComplete = true;
            setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
        } else {
            const error = result.error || {};
            if (error.message && error.message.includes('Must solve captcha.')) {
                handleCaptchaError('Initial Load Serverside requirement');
            } else if (error.coinsClaimed === 10) {
                state.coinCollector.coinsCollected = error.coinsClaimed || 10;
                updateCoinCollectorUI();
                SoundManager.playAllCoinsClaimed();
                showToast(`Max coins reached!`, 'success');
                //sendOSNotification('allCoins', 'BananaBurner', 'All coins collected for today!');
                stopCoinCollector();
            } else {
                const status = await checkCoinStatus(true);
                if (status) {
                    state.coinCollector.coinsCollected = status.coinsClaimed || 0;
                    updateCoinCollectorUI();
                    state.coinCollector.initialLoadComplete = true;
                    setTimeout(attemptCoinCollection, CONFIG.NORMAL_COIN_INTERVAL);
                }
            }
        }
    }

    function startCoinCollector() {
        SoundManager.playButtonClick();
        if (state.coinCollector.running) return;

        state.coinCollector.running = true;
        loadCoinProgress();
        state.coinCollector.totalAttempts = 0;
        state.coinCollector.waitingForCaptcha = false;
        state.coinCollector.captchaClaimInProgress = false;
        state.coinCollector.initialLoadComplete = false;
        state.coinCollector.nextCoinRequiresCaptcha = false;
        updateCaptchaPRD();

        state.toastQueue.length = 0;
        const existingToasts = document.querySelectorAll('.bh-toast');
        existingToasts.forEach(toast => toast.remove());
        state.showingToasts = 0;

        fetchUserData();
        updateCoinCollectorUI();

        attemptCoinCollection();
    }

    function stopCoinCollector() {
        SoundManager.playButtonClick();
        if (!state.coinCollector.running) return;

        state.coinCollector.running = false;
        state.coinCollector.waitingForCaptcha = false;
        state.coinCollector.captchaClaimInProgress = false;
        SoundManager.stopCaptchaPulse();

        if (state.coinCollector.resetTimerInterval) {
            clearInterval(state.coinCollector.resetTimerInterval);
            state.coinCollector.resetTimerInterval = null;
        }

        showToast(`Stopped. Got ${state.coinCollector.coinsCollected}/${CONFIG.MAX_COINS_PER_DAY} coins today`, 'info');
        updateCoinCollectorUI();
    }

    function calculateServerCost() {
        const cfg = state.serverCreator.config;
        const plan = cfg.plan;
        const billing = cfg.billing;
        const monthlyCost = PLANS[plan]?.coinsPerMonth || 0;

        return billing === 'weekly' ? Math.ceil(monthlyCost / 4) : monthlyCost;
    }

    function updateServerCostDisplay() {
        const costDisplay = document.getElementById('bh-server-cost');
        if (!costDisplay) return;

        const cost = calculateServerCost();
        const billingSelect = document.getElementById('bh-server-billing');
        const billing = billingSelect ? billingSelect.value : 'monthly';
        const period = billing === 'weekly' ? 'week' : 'month';

        costDisplay.textContent = `${cost} coins per ${period}`;

        const userCoins = state.coinCollector.currentCoins;
        if (userCoins < cost) {
            costDisplay.style.color = 'var(--accent-error)';
            costDisplay.style.setProperty('border', '1px solid var(--accent-error)', 'important');
            DOMUpdater.render(`${cost} coins per ${period} <span style="color: var(--accent-error); font-size: 0.8em;"></span>`, costDisplay);
        } else {
            costDisplay.style.color = 'var(--text-primary)';
            costDisplay.style.setProperty('border', '1px solid var(--border-light)', 'important');
        }
    }

    function getServerPayload() {
        const cfg = state.serverCreator.config;

        return {
            plan: cfg.plan,
            billing: cfg.billing,
            name: cfg.name,
            egg: cfg.egg
        };
    }

    async function attemptServerCreation() {
        if (!state.serverCreator.running) return;

        state.serverCreator.attempts++;
        updateServerCreatorUI();

        try {
            const response = await fetch('/api/servers/create', {
                method: 'POST',
                headers: getHeaders(),
                body: JSON.stringify(getServerPayload())
            });

            const data = await response.json();

            if (!data.error) {
                const newId = (data.id || data.serverid)?.toString();
                const cost = calculateServerCost();

                state.stats.totalServersCreated++;
                state.stats.totalCoinsSpent += cost;
                state.stats.totalCreationTime += state.serverCreator.elapsed;
                state.stats.highestCreationTime = Math.max(state.stats.highestCreationTime, state.serverCreator.elapsed);
                saveStats();

                SoundManager.playServerCreate();
                showToast('Server created! 🎉', 'success');
                sendOSNotification('serverCreated', 'BananaBurner', 'Server created successfully!');
                stopServerCreator();

                await fetchServers(true);

                if (newId) {
                    showNewServerPopup(newId);
                } else {
                    checkForNewServer();
                }

                fetchUserData();

                state.serverCreator.config = {
                    name: 'My-Server',
                    egg: '16',
                    billing: 'weekly',
                    plan: 'Starter'
                };
            } else if (data.message && data.message.includes('not have enough coins')) {
                showToast('Not enough coins', 'warn');
                stopServerCreator();
            }
        } catch (error) {
            BnLog('ERROR', 'Server creation error:', error);
        }
    }

    function startServerCreatorTimer() {
        state.serverCreator.startTime = Date.now();

        if (state.serverCreator.timerInterval) {
            clearInterval(state.serverCreator.timerInterval);
        }

        state.serverCreator.timerInterval = setInterval(() => {
            if (state.serverCreator.running) {
                state.serverCreator.elapsed = Math.floor((Date.now() - state.serverCreator.startTime) / 1000);
                updateServerCreatorUI();
            }
        }, 1000);
    }

    function stopServerCreatorTimer() {
        if (state.serverCreator.timerInterval) {
            clearInterval(state.serverCreator.timerInterval);
            state.serverCreator.timerInterval = null;
        }
    }

    function startServerCreator() {
        SoundManager.playButtonClick();
        if (state.serverCreator.running) return;

        const cost = calculateServerCost();
        if (state.coinCollector.currentCoins < cost) {
            showToast(`Not enough coins! Need ${cost} but have ${state.coinCollector.currentCoins}`, 'error');
            return;
        }

        checkControlPanelStatus();
        checkApiStatus();

        state.serverCreator.running = true;
        state.serverCreator.attempts = 0;
        state.serverCreator.elapsed = 0;

        state.serverCreator.initialServerIds = state.serverCreator.servers.map(s => s.serverid);

        startServerCreatorTimer();
        showToast('Server creation started!', 'info');

        updateServerCreatorUI();
        attemptServerCreation();

        state.serverCreator.creationInterval = setInterval(attemptServerCreation, 10000);
    }

    function stopServerCreator() {
        SoundManager.playButtonClick();
        if (!state.serverCreator.running) return;

        state.serverCreator.running = false;
        clearInterval(state.serverCreator.creationInterval);
        stopServerCreatorTimer();

        showToast(`Stopped after ${state.serverCreator.attempts} tries`, 'info');
        updateServerCreatorUI();
    }

    function checkForNewServer() {
        if (!state.serverCreator.initialServerIds) return;

        const newServer = state.serverCreator.servers.find(s =>
            !state.serverCreator.initialServerIds.includes(s.serverid)
        );

        if (newServer) {
            showNewServerPopup(newServer);
        }
    }

    function showNewServerPopup(serverOrId) {
        const serverId = typeof serverOrId === 'object' ? (serverOrId.serverid || serverOrId.id) : serverOrId;
        showServerDetails(serverId).then(() => {

            const modal = document.getElementById('bh-server-details-modal');
            if (modal) {
                const title = modal.querySelector('.modal-header h3');
                if (title) {
                    DOMUpdater.render('New Server Created!', title);
                    title.style.color = 'var(--accent-success)';
                }
            }
        });
    }
    function formatTime(seconds) {
        const hrs = Math.floor(seconds / 3600);
        const mins = Math.floor((seconds % 3600) / 60);
        const secs = seconds % 60;
        return `${String(hrs).padStart(2, '0')}:${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
    }

    const VIEW_TO_PATH = {
        'dashboard': '/panel/',
        'coins': '/panel/earn',
        'servers': '/panel/create',
        'manage': '/panel/manageserver',
        'market': '/panel/market',
        'wiki': '/panel/wiki',
        'uptime': '/panel/status'
    };

    function navigateTo(view, pushState = true) {
        if (typeof SoundManager !== 'undefined') SoundManager.playButtonClick();
        if (state.currentView === view) return;

        if (pushState && VIEW_TO_PATH[view]) {
            const currentPath = window.location.pathname;
            const newPath = VIEW_TO_PATH[view];
            if (currentPath !== newPath) {
                history.pushState({ view }, '', newPath);
            }
        }

        const content = document.getElementById('bh-main-content');
        if (content) {
            content.style.transition = 'opacity 0.2s ease, transform 0.2s ease';
            content.style.opacity = '0';
            content.style.transform = 'translateX(20px)';

            setTimeout(() => {
                state.currentView = view;
                content.style.opacity = '1';
                content.style.transform = 'translateX(0)';

                setTimeout(() => {
                    if (state.currentView === view) {
                        content.style.transform = '';
                        content.style.transition = '';
                    }
                }, 200);
            }, 200);
        } else {
            state.currentView = view;
        }

        document.querySelectorAll('.nav-item').forEach(item => {
            item.classList.remove('active');
        });
        const targetItem = document.querySelector(`[data-view="${view}"]`);
        if (targetItem) {
            targetItem.classList.add('active');
        }
    }

    window.addEventListener('popstate', (e) => {
        const path = window.location.pathname;
        const view = Object.entries(VIEW_TO_PATH).find(([v, p]) => p === path)?.[0] || 'dashboard';
        navigateTo(view, false);
    });

    function handleInitialRouting() {
        const path = window.location.pathname;
        const view = Object.entries(VIEW_TO_PATH).find(([v, p]) => p === path)?.[0] || 'dashboard';
        if (view !== 'dashboard') {
            state.currentView = view;
        }
    }

    let lastRenderedView = null;

    function updateMainContent(animate = true) {
        const content = document.getElementById('bh-main-content');
        if (!content) return;

        if (lastRenderedView !== state.currentView) {
            content.innerHTML = '';
            lastRenderedView = state.currentView;
        }

        let activityScroll = 0;
        const activityList = content.querySelector('.activity-list');
        if (activityList) activityScroll = activityList.scrollTop;

        let activeId = null;
        let activeIdType = null;
        const activeEl = content.querySelector('.context-menu-active');
        if (activeEl) {
            activeId = activeEl.getAttribute('data-server-id') || activeEl.getAttribute('data-activity-id');
            activeIdType = activeEl.getAttribute('data-server-id') ? 'server' : 'activity';
        }

        let html = '';
        try {
            switch (state.currentView) {
                case 'dashboard':
                    html = renderDashboard(animate);
                    break;
                case 'coins':
                    html = renderCoinCollector();
                    setTimeout(() => {
                        checkCoinStatus();
                    }, 100);
                    break;
                case 'servers':
                    html = renderServerCreator();
                    break;
                case 'manage':
                    html = renderServerManagement();
                    break;
                case 'uptime':
                    html = renderUptimeMonitor();
                    break;
                case 'market':
                    html = renderMarket();
                    break;
                case 'wiki':
                    html = renderWiki();
                    break;
            }
        } catch (err) {
            BnLog('ERROR', `View crash in [${state.currentView}]:`, err);
            html = `
                <div class="error-boundary-container" style="display: flex; flex-direction: column; align-items: center; justify-content: center; height: 100%; min-height: 400px; padding: 2rem; text-align: center;">
                    <div style="background: var(--bg-secondary); border: 1px solid var(--border-light); border-radius: var(--border-radius, 12px); padding: 3rem; max-width: 600px; box-shadow: var(--shadow-md, 0 4px 6px -1px rgba(0, 0, 0, 0.1)); animation: fadeIn 0.3s ease-out;">
                        <i class="fas fa-exclamation-triangle" style="font-size: 3rem; color: var(--accent-error); margin-bottom: 1.5rem;"></i>
                        <h2 style="color: var(--text-primary); margin: 0 0 1rem 0; font-size: 1.5rem;">Module Crashed</h2>
                        <p style="color: var(--text-secondary); margin: 0 0 2rem 0; line-height: 1.6;">
                            An unexpected error occurred while rendering the <strong>${state.currentView}</strong> view. The application is still running, but this specific module failed to load.
                        </p>
                        <div style="background: var(--bg-tertiary, rgba(0,0,0,0.2)); padding: 1rem; border-radius: 8px; text-align: left; overflow-x: auto; margin-bottom: 2rem;">
                            <code style="color: var(--accent-error); font-family: var(--console-font, monospace); font-size: 0.85rem;">${escapeHTML(err.toString())}</code>
                        </div>
                        <button class="btn btn-primary" onclick="state.currentView = 'dashboard'" style="padding: 0.75rem 2rem;">
                            <i class="fas fa-arrow-left"></i> Return to Dashboard
                        </button>
                    </div>
                </div>
            `;
        }

        DOMUpdater.render(html, content);

        if (activityScroll > 0) {
            requestAnimationFrame(() => {
                const newActivityList = content.querySelector('.activity-list');
                if (newActivityList) newActivityList.scrollTop = activityScroll;
            });
        }

        if (activeId) {
            const selector = activeIdType === 'server' ? `[data-server-id="${activeId}"]` : `[data-activity-id="${activeId}"]`;
            const newActiveEl = content.querySelector(selector);
            if (newActiveEl) newActiveEl.classList.add('context-menu-active');
        }

        if (state.currentView === 'dashboard') {
            setupQuickActionListeners();
            setTimeout(() => refreshPluginWidgets(), 50);
        } else if (state.currentView === 'coins') {
            updateCoinCollectorUI();
            setupActionIcons();
            initNitroAds();
        } else if (state.currentView === 'servers') {
            updateServerCreatorUI();
            setupActionIcons();
            setTimeout(() => {
                updateServerCostDisplay();
                const planSelect = document.getElementById('bh-server-plan');
                const billingSelect = document.getElementById('bh-server-billing');
                if (planSelect) {
                    planSelect.addEventListener('change', updateServerCostDisplay);
                }
                if (billingSelect) {
                    billingSelect.addEventListener('change', updateServerCostDisplay);
                }
            }, 100);
        }
    }

    function refreshUI(animate = false) {
        const content = document.getElementById('bh-main-content');
        if (content) {
            if (state._aprilFools?.triggered && state.currentView === 'dashboard') {
                triggerAprilFoolsReveal(true);
                return;
            }

            updateMainContent(animate);
            if (typeof applyAprilFoolsOverlay === 'function' && state.currentView === 'dashboard') {
                applyAprilFoolsOverlay();
            }
            emitPluginEvent('dashboardRendered');
        }
    }

    function updateDashboard(animate = false) {
        if (state.currentView === 'dashboard') {
            refreshUI(animate);
        }
    }

    function updateModuleStatus(module, running) {
        const statusEl = document.querySelector(`.module-card:has([onclick*="${module}"]) .module-status, .module-card .module-status`);
        const allModuleCards = document.querySelectorAll('.module-card');

        allModuleCards.forEach(card => {
            const header = card.querySelector('.module-header h2');
            if (header) {
                const isCoinModule = header.textContent.includes('Coin');
                const isServerModule = header.textContent.includes('Server Creator');

                if ((module === 'Coin' && isCoinModule) || (module === 'Server' && isServerModule)) {
                    const status = card.querySelector('.module-status');
                    if (status) {
                        status.className = `module-status ${running ? 'running' : 'stopped'}`;
                        DOMUpdater.render(`
                            <span class="status-dot"></span>
                            <span class="status-text">${running ? 'Running' : 'Stopped'}</span>
                        `, status);
                    }
                }
            }
        });
    }

    class ExtensionBridge {
        constructor() {
            this.listeners = {};
            window.addEventListener('message', this.handleMessage.bind(this));
        }

        sendMessage(message) {
            window.postMessage({ type: 'FROM_PAGE', nonce: resolveBridgeNonce(), ...message }, '*');
        }

        on(action, callback) {
            if (!this.listeners[action]) {
                this.listeners[action] = [];
            }
            this.listeners[action].push(callback);
        }

        handleMessage(event) {
            if (event.source !== window || !event.data || event.data.type !== 'FROM_EXTENSION') {
                return;
            }
            const { action, payload } = event.data;
            if (this.listeners[action]) {
                this.listeners[action].forEach(callback => callback(payload));
            }
        }
    }

    const extensionBridge = new ExtensionBridge();

    extensionBridge.on('extensionUpdateStatus', (status) => {
        if (CONFIG.DEBUG) BnLog('UPDATE', 'Extension update status received:', status);
        state.extensionUpdateStatus = status;
        updateSettingsUI();
    });

    function checkExtensionUpdate() {
        extensionBridge.sendMessage({ action: 'checkExtensionUpdate' });
        showToast('Checking for updates...', 'info');
    }

    function updateCoinCollectorUI() {
        updateModuleStatus('Coin', state.coinCollector.running);

        if (state.currentView !== 'coins') return;

        const currentCoinsEl = document.getElementById('bh-current-coins');
        const collectedEl = document.getElementById('bh-coins-collected');
        const attemptsEl = document.getElementById('bh-attempts');
        const progressBar = document.getElementById('bh-progress-bar');
        const startBtn = document.getElementById('bh-coin-start');
        const stopBtn = document.getElementById('bh-coin-stop');
        const resetTimerEl = document.getElementById('bh-reset-timer');

        if (currentCoinsEl) currentCoinsEl.textContent = state.coinCollector.currentCoins;
        if (collectedEl) collectedEl.textContent = state.coinCollector.coinsCollected;
        if (attemptsEl) attemptsEl.textContent = state.coinCollector.totalAttempts;
        if (progressBar) {
            const percentage = (state.coinCollector.coinsCollected / CONFIG.MAX_COINS_PER_DAY) * 100;
            progressBar.style.width = `${percentage}%`;
        }
        if (startBtn) startBtn.disabled = state.coinCollector.running;
        if (stopBtn) stopBtn.disabled = !state.coinCollector.running;
        if (resetTimerEl) {
            resetTimerEl.textContent = formatTimeUntilReset(state.coinCollector.timeUntilReset);
        }
    }

    function updateServerCreatorUI() {
        updateModuleStatus('Server', state.serverCreator.running);

        if (state.currentView !== 'servers') return;

        const attemptsEl = document.getElementById('bh-server-attempts');
        const startBtn = document.getElementById('bh-server-start');
        const stopBtn = document.getElementById('bh-server-stop');
        const timerEl = document.getElementById('bh-server-timer');

        const nameInput = document.getElementById('bh-server-name');
        const eggSelect = document.getElementById('bh-server-egg');
        const billingSelect = document.getElementById('bh-server-billing');
        const planSelect = document.getElementById('bh-server-plan');

        const isRunning = state.serverCreator.running;

        const isNameValid = state.serverCreator.config.name.length >= 3;

        if (attemptsEl) attemptsEl.textContent = state.serverCreator.attempts;
        if (startBtn) startBtn.disabled = isRunning || !isNameValid;
        if (stopBtn) stopBtn.disabled = !isRunning;

        if (nameInput) {
            nameInput.disabled = isRunning;
            if (!isNameValid && state.serverCreator.config.name.length >= 0) {
                nameInput.style.setProperty('border', '1px solid var(--accent-error)', 'important');
                nameInput.style.color = 'var(--accent-error)';
            } else {
                nameInput.style.setProperty('border', '1px solid var(--border-light)', 'important');
                nameInput.style.color = 'var(--text-primary)';
            }
            nameInput.style.opacity = isRunning ? '0.6' : '1';
            //nameInput.style.background = isRunning ? 'rgba(0,0,0,0.1)' : 'var(--bg-primary)';
        }
        if (eggSelect) eggSelect.disabled = isRunning;
        if (billingSelect) billingSelect.disabled = isRunning;
        if (planSelect) planSelect.disabled = isRunning;

        if (timerEl) {
            timerEl.textContent = formatTime(state.serverCreator.elapsed);
        }

        const statusNotice = document.getElementById('bh-server-status-notice');
        const isApiDown = state.apiStatus === 'down';
        const isCpDown = state.controlPanelStatus === 'down' && state.controlPanelWasUp;

        if (isApiDown || isCpDown) {
            if (!statusNotice) {
                const moduleBody = document.querySelector('.module-body');
                if (moduleBody) {
                    const notice = document.createElement('div');
                    notice.id = 'bh-server-status-notice';
                    notice.className = 'status-notice warning';
                    DOMUpdater.render(`
            <div class="status-notice-content">
              <i class="fas fa-exclamation-triangle"></i>
              <div class="status-notice-text">
                <strong>Service Status: ${isApiDown ? 'API Issues' : 'Control Panel Issues'}</strong>
                <p>Server creation may not work as expected while services are experiencing issues.</p>
              </div>
            </div>
          `, notice);
                    moduleBody.insertBefore(notice, moduleBody.firstChild);
                }
            } else {
                const title = statusNotice.querySelector('strong');
                if (title) title.textContent = `Service Status: ${isApiDown ? 'API Issues' : 'Control Panel Issues'}`;
            }
        } else if (statusNotice) {
            statusNotice.remove();
        }
    }

    function censorText(text, asHtml = true) {
        if (!state.settings.privacyMode) return text;

        if (state.settings.alwaysHide) {
            return '–';
        }

        const censorChar = '•';
        const originalText = String(text);
        const length = originalText.length;
        const censored = censorChar.repeat(Math.min(length, 12));

        if (!asHtml) return censored;

        return `<span class="privacy-censored" data-original="${originalText}" data-censored="${censored}" style="cursor: help; border-bottom: 1px dashed var(--text-secondary);">${censored}</span>`;
    }

    document.addEventListener('mouseover', (e) => {
        const el = e.target.closest('.privacy-censored');
        if (el && !state.settings.alwaysHide) {
            el.textContent = el.dataset.original;
        }
    });

    document.addEventListener('mouseout', (e) => {
        const el = e.target.closest('.privacy-censored');
        if (el) {
            el.textContent = el.dataset.censored;
        }
    });

