    let profileModalAffiliateInterval = null;

    async function fetchAffiliateData() {
        try {
            const response = await fetch('/api/affiliate', {
                method: 'GET',
                headers: getHeaders()
            });
            if (response.ok) {
                return await response.json();
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch affiliate data:', error);
        }
        return null;
    }

    async function generateSFTPPassword() {
        try {
            const response = await fetch('/api/newPassword', {
                method: 'POST',
                headers: getHeaders()
            });
            if (response.ok) {
                const data = await response.json();
                if (data.password) {
                    localStorage.setItem('bh-sftp-password', data.password);

                    const sftpModal = document.getElementById('bh-sftp-details-modal');
                    if (sftpModal) {
                        const serverId = sftpModal.dataset.serverId;
                        if (serverId) showSFTPDetailsModal(serverId, true);
                    }

                    return data.password;
                }
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to generate SFTP password:', error);
        }
        return null;
    }

    function copyToClipboardWithFeedback(text, label, element) {
        navigator.clipboard.writeText(text);
        showToast(`${label} copied!`, 'success');

        const icon = element.querySelector('i.fa-copy');
        if (icon) {
            const originalClass = icon.className;
            icon.className = 'fas fa-check';
            icon.style.color = '#10b981';

            setTimeout(() => {
                icon.className = originalClass;
                icon.style.color = '';
            }, 3000);
        }
    }

