        if (!details) {
            if (CONFIG.DEBUG) BnLog('ERROR', 'Details not found in cache for:', serverId);
            return showToast('Server details not found', 'error');
        }

        const sftp = details.sftp_details || {};
        const savedPassword = localStorage.getItem('bh-sftp-password');
        const username = `${censorText(state.user?.id || 'unknown', false)}.${censorText(details.identifier || 'unknown', false)}`;
        const usernameHtml = `${censorText(state.user?.id || 'unknown')}.${censorText(details.identifier || 'unknown')}`;
        const node = (state.controlPanel.servers.find(s => s.attributes?.identifier === details.identifier)?.attributes?.node || details.node || server?.node || '???');
        const port = sftp.port || 2022;
        const address = `sftp://${node}.bot-hosting.net:${port}`;

        const existing = document.getElementById('bh-sftp-details-modal');
        if (existing) existing.remove();

        const modal = document.createElement('div');
        modal.id = 'bh-sftp-details-modal';
        modal.className = 'bananaa-modal';
        modal.dataset.serverId = serverId;
        modal.style.zIndex = '11000';

