              <div onclick="copyToClipboardWithFeedback('${address}', 'SFTP Address', this)" style="cursor: pointer; background: var(--modal-tertiary-bg, rgba(255,255,255,0.05)); padding: 0.75rem; border-radius: 8px; border: 1px solid var(--border-light); display: flex; align-items: center; justify-content: space-between; transition: background 0.2s;" onmouseover="this.style.background='var(--bg-tertiary)'" onmouseout="this.style.background='var(--modal-tertiary-bg, rgba(255,255,255,0.05))'">
                <code style="color: var(--modal-text-primary); font-family: monospace;">${address}</code>
                <i class="fas fa-copy" style="color: var(--modal-text-secondary); font-size: 1.1rem;"></i>
              </div>
