    async function submitChangePlan(serverId, newPlan, newBilling) {
        try {
            const res = await fetchWithRetry('https://legacybot-hosting.net/api/servers/changePlan', {
                method: 'POST',
                headers: {
                    ...getHeaders(),
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    id: parseInt(serverId),
                    plan: newPlan,
                    planCycle: newBilling
                })
            });

            const data = await res.json().catch(() => ({}));

            if (res.ok && data.success) {
                showToast('Plan changed successfully!', 'success');

                const server = state.serverCreator.servers.find(s => s.serverid === serverId);
                if (server) {
                    server.plan = data.plan?.name || newPlan;
                }

                if (state.serverDetailsCache[serverId]) {
                    state.serverDetailsCache[serverId].data = {
                        ...state.serverDetailsCache[serverId].data,
                        plan: data.plan,
                        billing: data.billing,
                        nextRenewal: data.nextRenewal
                    };
                    state.serverDetailsCache[serverId].timestamp = Date.now();
                    saveServerDetailsCache();
                }

                fetchServers(true);
                fetchUserData();
                return true;
            } else {
                showToast(data.message || 'Failed to change plan', 'error');
                return false;
            }
        } catch (e) {
            BnLog('ERROR', 'Plan change error:', e);
            showToast('Network error while changing plan', 'error');
            return false;
        }
    }

    async function submitDeleteServer(serverId) {
        try {
            const res = await fetchWithRetry('https://legacy.bot-hosting.net/api/servers/delete', {
                method: 'POST',
                headers: {
                    ...getHeaders(),
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    id: Number(serverId)
                })
            });

            const data = await res.json().catch(() => ({}));

            if (res.ok && (data.success || data.ok)) {
                showToast('Server deleted successfully', 'success');

                state.serverCreator.servers = state.serverCreator.servers.filter(s => s.serverid !== serverId);
                if (state.serverDetailsCache[serverId]) {
                    delete state.serverDetailsCache[serverId];
                    saveServerDetailsCache();
                }
                fetchServers(true);
                fetchUserData();
                return true;
            } else {
                showToast(data.message || 'Failed to delete server', 'error');
                return false;
            }
        } catch (e) {
            BnLog('ERROR', 'Delete server error:', e);
            showToast('Network error while deleting server', 'error');
            return false;
        }
    }

    async function submitChangeSoftware(serverId, eggId) {
        try {
            const res = await fetchWithRetry('https://legacy.bot-hosting.net/api/servers/changeSoftware', {
                method: 'POST',
                headers: {
                    ...getHeaders(),
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    id: serverId,
                    egg: Number(eggId)
                })
            });

            const data = await res.json().catch(() => ({}));

            if (res.ok && !data.error) {
                showToast('Language changed successfully!', 'success');
                fetchServers(true);
                return true;
            } else {
                showToast(data.message || 'Failed to change language', 'error');
                return false;
            }
        } catch (e) {
            BnLog('ERROR', 'Software change error:', e);
            showToast('Network error while changing language', 'error');
            return false;
        }
    }

    let currentFileBrowserPath = '/';
    let currentFileBrowserIdentifier = null;
    let editorView = null;
    let selectedFiles = new Set();
    let lastClickedFileIndex = -1;

    async function renameServerFile(identifier, root, from, to) {
        if (!identifier || state.controlPanelStatus !== 'up') return false;

        const serverId = state.controlPanel.selectedServerId;
        const node = vfsResolve(serverId, (root === '/' ? '' : root) + '/' + from);
        if (node) {
            vfsRemove(serverId, (root === '/' ? '' : root) + '/' + from);
            const parent = vfsResolve(serverId, root);
            if (parent) {
                parent.children[to] = { ...node, attributes: { ...node.attributes, name: to }, fullPath: (root === '/' ? '' : root) + '/' + to };
            }
            vfsInvalidate(serverId, root);
            if (currentFileBrowserIdentifier === identifier && currentFileBrowserPath === root) {
                loadFileBrowser(identifier, root);
            }
        }

        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/rename`,
                {
                    method: 'PUT',
                    headers: getControlPanelHeaders(),
                    body: JSON.stringify({ root, files: [{ from, to }] })
                }
            );

            if (response && (response.ok || response.status === 204)) return true;

            vfsEnqueue(serverId, root);

            if (response && response.data && response.data.errors) {
                let errorMsg = response.data.errors[0]?.detail || 'Failed to rename file';
                errorMsg = errorMsg.replace(/An error occurred on the remote host:\s*/i, '');
                errorMsg = errorMsg.replace(/\.?\s*\(request\s*id:\s*[a-f0-9-]+\)/i, '');
                errorMsg = errorMsg.replace(/DaemonConnectionException:\s*/i, '');
                showToast(errorMsg.trim(), 'error');
            } else {
                showToast('Failed to rename file/folder', 'error');
            }
            return false;
        } catch (error) {
            vfsEnqueue(serverId, root);
            BnLog('ERROR', 'Failed to rename file:', error);
            return false;
        }
    }

    async function createNewServerFile(identifier, directory, fileName) {
        if (!identifier || state.controlPanelStatus !== 'up') return false;
        try {
            const filePath = directory === '/' ? '/' + fileName : directory + '/' + fileName;
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/write?file=${encodeURIComponent(filePath)}`,
                {
                    method: 'POST',
                    headers: { ...getControlPanelHeaders(), 'Content-Type': 'text/plain' },
                    body: ''
                }
            );
            if (response && (response.ok || response.status === 204)) {
                const serverId = state.controlPanel.selectedServerId;
                const parent = vfsResolve(serverId, directory);
                if (parent) {
                    if (!parent.children) parent.children = {};
                    parent.children[fileName] = {
                        type: 'file',
                        lastSynced: Date.now(),
                        fullPath: filePath,
                        attributes: { name: fileName, is_file: true, size: 0, modified_at: new Date().toISOString() }
                    };
                }
                vfsInvalidate(serverId, directory);
                return true;
            }
            return false;
        } catch (error) {
            BnLog('ERROR', 'Failed to create file:', error);
            return false;
        }
    }

    async function createNewServerFolder(identifier, directory, folderName) {
        if (!identifier || state.controlPanelStatus !== 'up') return false;

        const serverId = state.controlPanel.selectedServerId;
        const parent = vfsResolve(serverId, directory);
        if (parent) {
            if (!parent.children) parent.children = {};
            parent.children[folderName] = {
                type: 'folder',
                children: {},
                lastSynced: 0,
                fullPath: (directory === '/' ? '' : directory) + '/' + folderName,
                attributes: { name: folderName, is_file: false }
            };
            const serverId = state.controlPanel.selectedServerId;
            vfsInvalidate(serverId, directory);
            if (currentFileBrowserIdentifier === identifier && currentFileBrowserPath === directory) {
                loadFileBrowser(identifier, directory);
            }
        }

        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/create-folder`,
                {
                    method: 'POST',
                    headers: getControlPanelHeaders(),
                    body: JSON.stringify({ root: directory, name: folderName })
                }
            );
            if (response && (response.ok || response.status === 204)) return true;

            vfsEnqueue(serverId, directory);
            return false;
        } catch (error) {
            vfsEnqueue(serverId, directory);
            BnLog('ERROR', 'Failed to create folder:', error);
            return false;
        }
    }

    async function fetchServerFiles(identifier, directory = '/') {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/list?directory=${encodeURIComponent(directory)}`,
                { method: 'GET', headers: getControlPanelHeaders() }
            );
            if (response && response.ok) {
                return response.data?.data || [];
            }
            return response;
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch files:', error);
        }
        return null;
    }

    async function fetchFileContents(identifier, filePath, returnFullResponse = false) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/contents?file=${encodeURIComponent(filePath)}`,
                { method: 'GET', headers: getControlPanelHeaders() }
            );
            if (returnFullResponse) return response;
            if (response && response.ok) {
                return response.data;
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to fetch file contents:', error);
        }
        return null;
    }

    async function saveFileContents(identifier, filePath, content, onProgress = null) {
        if (!identifier || state.controlPanelStatus !== 'up') return false;

        const fileName = filePath.split('/').pop();
        const dirPath = filePath.split('/').slice(0, -1).join('/') || '/';

        try {
            const signResponse = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/upload`
            );

            if (signResponse?.data?.attributes?.url) {
                const uploadUrl = signResponse.data.attributes.url;

                return new Promise((resolve) => {
                    const xhr = new XMLHttpRequest();
                    xhr.open('POST', `${uploadUrl}&directory=${encodeURIComponent(dirPath)}`, true);

                    if (onProgress && xhr.upload) {
                        xhr.upload.onprogress = (e) => {
                            if (e.lengthComputable) {
                                const percent = Math.round((e.loaded / e.total) * 100);
                                onProgress(percent);
                            }
                        };
                    }

                    const formData = new FormData();
                    formData.append('files', new File([content], fileName));

                    xhr.onload = () => {
                        if (xhr.status >= 200 && xhr.status < 300) {
                            const serverId = state.controlPanel.selectedServerId;
                            const parent = vfsResolve(serverId, dirPath);
                            if (parent && !parent.children[fileName]) {
                                if (!parent.children) parent.children = {};
                                parent.children[fileName] = {
                                    type: 'file',
                                    children: null,
                                    lastSynced: Date.now(),
                                    fullPath: filePath,
                                    attributes: { name: fileName, is_file: true, size: content.length, modified_at: new Date().toISOString() }
                                };
                                if (currentFileBrowserIdentifier === identifier && currentFileBrowserPath === dirPath) {
                                    loadFileBrowser(identifier, dirPath);
                                }
                            }
                            emitPluginEvent('fileSaved', { identifier, filePath });
                            resolve(true);
                        } else {
                            throw new Error(`Upload failed: ${xhr.status}`);
                        }
                    };

                    xhr.onerror = () => resolve(false);
                    xhr.ontimeout = () => resolve(false);
                    xhr.timeout = 60000;
                    xhr.send(formData);
                }).catch(() => false);
            }
        } catch (e) {
            BnLog('WARN', 'Upload failed, falling back to Write:', e);
        }

        try {
            let progress = 0;
            const progressInterval = setInterval(() => {
                if (progress < 90) {
                    progress += (90 - progress) * 0.1;
                    if (onProgress) onProgress(Math.round(progress));
                }
            }, 200);

            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/write?file=${encodeURIComponent(filePath)}`,
                {
                    method: 'POST',
                    headers: { ...getControlPanelHeaders(), 'Content-Type': 'text/plain' },
                    body: content
                }
            );

            clearInterval(progressInterval);
            const success = response && (response.ok || response.status === 204);
            if (success) {
                emitPluginEvent('fileSaved', { identifier, filePath });
            }
            return success;
        } catch (error) {
            BnLog('ERROR', 'Method B (Write) failed:', error);
            return false;
        }
    }

    async function deleteServerFile(identifier, root, files) {
        if (!identifier || state.controlPanelStatus !== 'up') return false;

        const serverId = state.controlPanel.selectedServerId;
        files.forEach(file => vfsRemove(serverId, (root === '/' ? '' : root) + '/' + file));
        if (currentFileBrowserIdentifier === identifier && currentFileBrowserPath === root) {
            loadFileBrowser(identifier, root);
        }

        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/delete`,
                {
                    method: 'POST',
                    headers: getControlPanelHeaders(),
                    body: JSON.stringify({ root, files })
                }
            );
            if (response && (response.ok || response.status === 204)) return true;

            vfsEnqueue(serverId, root);
            return false;
        } catch (error) {
            vfsEnqueue(serverId, root);
            BnLog('ERROR', 'Failed to delete file:', error);
            return false;
        }
    }

    async function compressServerFiles(identifier, root, files) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/compress`,
                {
                    method: 'POST',
                    headers: getControlPanelHeaders(),
                    body: JSON.stringify({ root, files })
                }
            );
            if (response && response.ok) {
                return response.data?.attributes || true;
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to compress files:', error);
        }
        return null;
    }

    async function decompressServerFile(identifier, root, file) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/decompress`,
                {
                    method: 'POST',
                    headers: getControlPanelHeaders(),
                    body: JSON.stringify({ root, file })
                }
            );
            if (response && response.ok) {
                return true;
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to decompress file:', error);
        }
        return null;
    }

    async function getDownloadUrl(identifier, filePath) {
        if (!identifier || state.controlPanelStatus !== 'up') return null;
        try {
            const response = await callProxyFetch(
                `https://control.bot-hosting.net/api/client/servers/${identifier}/files/download?file=${encodeURIComponent(filePath)}`,
                { method: 'GET', headers: getControlPanelHeaders() }
            );
            if (response && response.ok) {
                return response.data?.attributes?.url;
            }
        } catch (error) {
            BnLog('ERROR', 'Failed to get download URL:', error);
        }
        return null;
    }

    function getFileIcon(file) {
        if (file.attributes.is_file === false) return { icon: 'fa-folder', class: 'folder' };
        const name = file.attributes.name.toLowerCase();
        if (name.endsWith('.js') || name.endsWith('.mjs') || name.endsWith('.cjs')) return { icon: 'fa-file-code', class: 'file-js' };
        if (name.endsWith('.py')) return { icon: 'fa-file-code', class: 'file-py' };
        if (name.endsWith('.json')) return { icon: 'fa-file-code', class: 'file-json' };
        if (name.endsWith('.txt') || name.endsWith('.log')) return { icon: 'fa-file-lines', class: 'file-txt' };
        if (name.endsWith('.md')) return { icon: 'fa-file-lines', class: 'file-md' };
        if (name.endsWith('.html') || name.endsWith('.htm')) return { icon: 'fa-file-code', class: 'file-js' };
        if (name.endsWith('.css')) return { icon: 'fa-file-code', class: 'file-py' };
        if (name.endsWith('.yml') || name.endsWith('.yaml')) return { icon: 'fa-file-code', class: 'file-json' };
        return { icon: 'fa-file', class: 'file-default' };
    }

    function isEditableFile(filename) {
        const editable = ['.js', '.mjs', '.cjs', '.py', '.json', '.txt', '.md', '.html', '.htm', '.css', '.yml', '.yaml', '.xml', '.sh', '.bat', '.env', '.gitignore', '.dockerignore', '.toml', '.ini', '.cfg', '.conf', '.log'];
        return editable.some(ext => filename.toLowerCase().endsWith(ext));
    }

    function formatFileSize(bytes) {
        if (bytes === 0) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
    }

    // !
    function formatNumber(num) {
        if (num === null || num === undefined) return '0';
        return num.toLocaleString();
    }

    // Virtual File System
    function vfsSave(serverId) {
        try {
            const data = JSON.stringify(state.vfs[serverId]);
            if (data.length < 2 * 1024 * 1024) { // 2MBlimit per server
                _ls.set(`bh-vfs-${serverId}`, data);
            }
        } catch (e) {
            BnLog('VFS', `Save failed for ${serverId}:`, e);
        }
    }

    function vfsLoad(serverId) {
        const data = _ls.get(`bh-vfs-${serverId}`);
        if (data) {
            try {
                return JSON.parse(data);
            } catch (e) {
                return null;
            }
        }
        return null;
    }

    function vfsGetRoot(serverId) {
        if (!state.vfs[serverId]) {
            const loaded = vfsLoad(serverId);
            state.vfs[serverId] = loaded || {
                type: 'folder',
                children: {},
                lastSynced: 0,
                fullPath: '/'
            };
        }
        return state.vfs[serverId];
    }

    function vfsResolve(serverId, path) {
        if (!path || path === '/') return vfsGetRoot(serverId);
        const parts = path.split('/').filter(Boolean);
        let current = vfsGetRoot(serverId);

        for (const part of parts) {
            if (!current.children || !current.children[part]) return null;
            current = current.children[part];
        }
        return current;
    }

    function vfsUpdate(serverId, path, items) {
        let node = vfsResolve(serverId, path);
        if (!node && path !== '/') {
            const parts = path.split('/').filter(Boolean);
            const name = parts.pop();
            const parentPath = '/' + (parts.join('/') || '');
            const parent = vfsResolve(serverId, parentPath);
            if (parent) {
                if (!parent.children) parent.children = {};
                parent.children[name] = { type: 'folder', children: {}, lastSynced: 0, fullPath: path };
                node = parent.children[name];
            }
        }

        if (node) {
            const newChildren = {};
            const oldChildren = node.children || {};

            items.forEach(item => {
                const name = item.attributes.name;
                const isFolder = item.object === 'directory';
                const fullPath = (path === '/' ? '' : path) + '/' + name;

                if (oldChildren[name]) {
                    newChildren[name] = {
                        ...oldChildren[name],
                        type: isFolder ? 'folder' : 'file',
                        attributes: item.attributes,
                        fullPath: fullPath
                    };
                } else {
                    newChildren[name] = {
                        type: isFolder ? 'folder' : 'file',
                        children: isFolder ? {} : null,
                        lastSynced: isFolder ? 0 : Date.now(),
                        attributes: item.attributes,
                        fullPath: fullPath
                    };
                }
            });

            node.children = newChildren;
            node.lastSynced = Date.now();
            vfsSave(serverId);
        }
    }

    function vfsRemove(serverId, path) {
        const parts = path.split('/').filter(Boolean);
        if (parts.length === 0) return;
        const name = parts.pop();
        const parentPath = '/' + (parts.join('/') || '');
        const parent = vfsResolve(serverId, parentPath);
        if (parent && parent.children) {
            delete parent.children[name];
            vfsSave(serverId);
        }
    }
    function vfsInvalidate(serverId, path) {
        const node = vfsResolve(serverId, path);
        if (node) {
            node.lastSynced = 0;
            vfsSave(serverId);
        }
    }

    function vfsIsStale(node) {
        if (!node || node.type !== 'folder') return true;
        const STALE_MS = 5 * 60 * 1000;
        return Date.now() - node.lastSynced > STALE_MS;
    }

    function vfsSearch(serverId, query) {
        const results = [];
        const root = state.vfs[serverId];
        if (!root) return results;

        const traverse = (node) => {
            if (node.children) {
                for (const name in node.children) {
                    const child = node.children[name];
                    if (name.toLowerCase().includes(query.toLowerCase())) {
                        results.push(child);
                    }
                    traverse(child);
                    if (child.type === 'folder') traverse(child);
                }
            }
        };
        traverse(root);
        return results;
    }


    let vfsCrawlerInterval = null;
    let vfsQueue = [];
    const VFS_SYNC_INTERVAL = 3000;

    function vfsEnqueue(serverId, path) {
        if (!vfsQueue.some(item => item.serverId === serverId && item.path === path)) {
            vfsQueue.push({ serverId, path });
        }
    }

    async function vfsProcessQueue() {
        if (vfsQueue.length === 0) return;

        const { serverId, path } = vfsQueue.shift();
        const identifier = state.serverDetailsCache[serverId]?.data?.identifier;
        if (!identifier) return;

        const node = vfsResolve(serverId, path);
        if (node && !vfsIsStale(node)) return;

        try {
            const fetchResult = await fetchServerFiles(identifier, path);
            if (Array.isArray(fetchResult)) {
                vfsUpdate(serverId, path, fetchResult);

                if (currentFileBrowserIdentifier === identifier && currentFileBrowserPath === path) {
                    renderFileBrowserUI(identifier, path, fetchResult);
                }

                fetchResult.forEach(item => {
                    if (item.object === 'directory') {
                        const subPath = (path === '/' ? '' : path) + '/' + item.attributes.name;
                        const blacklist = ['node_modules', '.git', '__pycache__', '.venv', 'venv', 'env', '.cache', '.github', '.npm', '.yarn', '.pytest_cache', '.mypy_cache', '.idea', '.vscode', 'dist', 'build'];
                        if (!blacklist.includes(item.attributes.name)) {
                            vfsEnqueue(serverId, subPath);
                        }
                    }
                });
            }
        } catch (e) {
            BnLog('VFS', `Crawler failed for ${path}:`, e);
        }
    }

    function vfsStartCrawler() {
        if (!state.settings.vfsEnabled || vfsCrawlerInterval) return;
        vfsCrawlerInterval = setInterval(vfsProcessQueue, VFS_SYNC_INTERVAL);
    }

    function vfsStopCrawler() {
        if (vfsCrawlerInterval) {
            clearInterval(vfsCrawlerInterval);
            vfsCrawlerInterval = null;
        }
    }

    function renderFileBrowserUI(identifier, directory, files) {
        if (!files || state.isDeploying) return;

        currentFileBrowserIdentifier = identifier;
        currentFileBrowserPath = directory;

        const modal = document.getElementById('bh-server-details-modal');
        if (!modal) return;
        const panelBody = modal.querySelector('.files-panel .pullout-panel-body');
        if (!panelBody) return;

        const serverId = state.controlPanel.selectedServerId;

        files.sort((a, b) => {
            if (a.attributes.is_file !== b.attributes.is_file) {
                return a.attributes.is_file ? 1 : -1;
            }
            return a.attributes.name.localeCompare(b.attributes.name);
        });

        const pathParts = directory.split('/').filter(p => p);
        let breadcrumb = `
            <button class="breadcrumb-item" onclick="loadFileBrowser('${identifier}', '/')" title="Root" style="display: inline-flex; align-items: center; justify-content: center; width: 24px; height: 24px; padding: 0;">
                <svg viewBox="0 0 24 24" style="width: 16px; height: 16px; fill: currentColor;"><path d="M10 20v-6h4v6h5v-8h3L12 3 2 12h3v8z"/></svg>
            </button>`;

        let currentPath = '';
        pathParts.forEach((part, idx) => {
            currentPath += '/' + part;
            const escapedPath = currentPath.replace(/'/g, "\\'");
            breadcrumb += `
                <svg class="breadcrumb-separator" viewBox="0 0 24 24" style="width: 14px; height: 14px; fill: none; stroke: var(--text-secondary); stroke-width: 2.5; stroke-linecap: round; stroke-linejoin: round; opacity: 0.4; flex-shrink: 0;"><path d="M9 18l6-6-6-6"/></svg>
                <button class="breadcrumb-item" onclick="loadFileBrowser('${identifier}', '${escapedPath}')">${escapeHTML(part)}</button>`;
        });

        const canCreate = hasPermission('file.create');
        const canDelete = hasPermission('file.delete');
        const canArchive = hasPermission('file.archive');

        const vfsEnabled = state.settings.vfsEnabled;
        const showSearchInitial = vfsEnabled && (panelBody.dataset.searchActive === 'true');

        DOMUpdater.render(`
      <style>
        .file-browser-path { display: flex; align-items: center; gap: 2px; overflow-x: auto; overflow-y: hidden; scrollbar-width: none; -ms-overflow-style: none; }
        .file-browser-path::-webkit-scrollbar { display: none; }
        .breadcrumb-item { background: none; border: none; color: var(--text-secondary); font-size: 0.72rem; padding: 2px 5px; border-radius: 4px; cursor: pointer; white-space: nowrap; transition: color 0.15s, background 0.15s; flex-shrink: 0; }
        .breadcrumb-item:hover { background: rgba(var(--text-primary-rgb, 127,127,127), 0.08); color: var(--accent-primary); }
        .breadcrumb-separator { font-size: 0.5rem; opacity: 0.3; color: var(--text-secondary); flex-shrink: 0; }
        .fb-actions-row { display: flex; align-items: center; gap: 2px; padding: 4px 0; }
        .fb-btn { display: inline-flex; align-items: center; justify-content: center; width: 28px; height: 28px; border: none; background: transparent; color: var(--text-secondary); border-radius: 6px; cursor: pointer; transition: background 0.15s, color 0.15s; flex-shrink: 0; }
        .fb-btn svg { width: 20px; height: 20px; fill: currentColor; stroke: none; }
        .fb-btn:hover { background: rgba(var(--text-primary-rgb, 255,255,255), 0.1); color: var(--text-primary); }
        .fb-btn:active { background: rgba(var(--text-primary-rgb, 255,255,255), 0.15); }
        .fb-btn.active { color: var(--accent-primary); background: rgba(var(--accent-primary-rgb, 34,211,238), 0.15); }
        .fb-btn.danger:hover { color: var(--accent-error, #ef4444); background: rgba(239,68,68,0.15); }
        .fb-divider { width: 1px; height: 16px; background: var(--border-light); margin: 0 4px; opacity: 0.8; }
        .file-search-container { transition: all 0.25s cubic-bezier(0.4,0,0.2,1); overflow: hidden; }
        .file-search-input-wrapper { position: relative; width: 100%; }
        #file-search-input { width: 100%; padding: 5px 10px 5px 28px; background: var(--input-bg, rgba(255,255,255,0.03)); border: 1px solid var(--border-light); border-radius: 6px; color: var(--text-primary); font-size: 0.75rem; outline: none; transition: border-color 0.2s, box-shadow 0.2s; }
        #file-search-input:focus { background: rgba(var(--accent-primary-rgb, 34,211,238), 0.06) !important; border-color: var(--accent-primary) !important; box-shadow: 0 0 0 2px rgba(var(--accent-primary-rgb, 34,211,238), 0.12); }
        .search-shortcut-hint { position: absolute; right: 8px; top: 50%; transform: translateY(-50%); font-size: 0.6rem; color: var(--text-secondary); opacity: 0.4; background: rgba(255,255,255,0.04); padding: 1px 4px; border-radius: 3px; pointer-events: none; }
        
        .fb-btn.refreshing svg {
            animation: fa-spin 1s linear infinite;
            color: var(--accent-primary);
        }
        
        @keyframes fa-spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
      </style>
      <div class="file-browser">
        <div class="file-browser-header" style="display: flex; flex-direction: column; gap: 4px; padding-bottom: 6px; border-bottom: 1px solid var(--border-light); border-radius: 0 !important;">
          <div class="file-browser-path" id="file-browser-path">
            ${breadcrumb}
          </div>
          <div class="fb-actions-row">
            <div id="file-selection-info" style="display: none; align-items: center; gap: 6px; flex: 1; min-width: 0;">
              <input type="checkbox" id="file-select-all-cb" class="file-select-cb" onchange="toggleSelectAllFiles(this)" style="margin: 0;">
              <span id="file-selection-count" style="font-size: 0.6rem; font-weight: 700; text-transform: uppercase; letter-spacing: 0.04em; color: var(--accent-primary);">0 SELECTED</span>
            </div>
            <div id="file-selection-actions" style="display: none; align-items: center; gap: 2px;">
              ${canArchive ? `<button class="fb-btn" onclick="handleBulkArchive('${identifier}')" title="Archive selected"><svg viewBox="0 0 24 24"><path d="M20.54 5.23l-1.39-1.68C18.88 3.21 18.47 3 18 3H6c-.47 0-.88.21-1.16.55L3.46 5.23C3.17 5.57 3 6.01 3 6.5V19c0 1.1.8 2 2 2h14c1.2 0 2-.9 2-2V6.5c0-.49-.17-.93-.46-1.27zM12 17.5L6.5 12H10v-2h4v2h3.5L12 17.5zM5.12 5l.81-1h12.02l1 1H5.12z"/></svg></button>` : ''}
              <button class="fb-btn" onclick="handleBulkMove('${identifier}')" title="Move selected"><svg viewBox="0 0 24 24"><path d="M10 9h4V6h3l-5-5-5 5h3v3zm-1 1H6V7l-5 5 5 5v-3h3v-4zm14 2l-5-5v3h-3v4h3v3l5-5zm-9 3h-4v3H7l5 5 5-5h-3v-3z"/></svg></button>
              ${canDelete ? `<button class="fb-btn danger" onclick="handleBulkDelete('${identifier}')" title="Delete selected"><svg viewBox="0 0 24 24"><path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/></svg></button>` : ''}
            </div>
            <div id="file-creation-actions" style="display: flex; align-items: center; gap: 2px;">
              ${canCreate ? `
                <button class="fb-btn" onclick="handleNewFile('${identifier}', '${directory.replace(/'/g, "\\'")}')" title="New File"><svg viewBox="0 0 24 24"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm-1 7V3.5L18.5 9H13zm-1 4.5h-2v2H8.5v-2h-2v-1.5h2v-2h1.5v2h2v1.5z"/></svg></button>
                <button class="fb-btn" onclick="handleNewFolder('${identifier}', '${directory.replace(/'/g, "\\'")}')" title="New Folder"><svg viewBox="0 0 24 24"><path d="M20 6h-8l-2-2H4c-1.11 0-1.99.89-1.99 2L2 18c0 1.11.89 2 2 2h16c1.11 0 2-.89 2-2V8c0-1.11-.89-2-2-2zm-1 8h-3v3h-2v-3h-3v-2h3v-3h2v3h3v2z"/></svg></button>
                <div class="fb-divider"></div>
                <button class="fb-btn" onclick="handleFileUpload('${identifier}', '${directory.replace(/'/g, "\\'")}')" title="Upload"><svg viewBox="0 0 24 24"><path d="M9 16h6v-6h4l-7-7-7 7h4zm-4 2h14v2H5z"/></svg></button>
              ` : ''}
              <button class="fb-btn ${state.fbRefreshing ? 'refreshing' : ''}" id="fb-refresh-btn" onclick="loadFileBrowser('${identifier}', '${directory.replace(/'/g, "\\'")}', true)" title="Refresh (${navigator.platform.includes('Mac') ? '⌘' : 'Ctrl'}+R)">
                <svg viewBox="0 0 24 24"><path d="M17.65 6.35C16.2 4.9 14.21 4 12 4c-4.42 0-7.99 3.58-7.99 8s3.57 8 7.99 8c3.73 0 6.84-2.55 7.73-6h-2.08c-.82 2.33-3.04 4-5.65 4-3.31 0-6-2.69-6-6s2.69-6 6-6c1.66 0 3.14.69 4.22 1.78L13 11h7V4l-2.35 2.35z"/></svg>
              </button>
            </div>
            ${vfsEnabled ? `<button class="fb-btn ${panelBody.dataset.searchActive === 'true' ? 'active' : ''}" id="vfs-search-toggle" onclick="toggleFileSearchUI()" title="Search (${navigator.platform.includes('Mac') ? '⌘' : 'Ctrl'}+F)" style="margin-left: auto; margin-right: 1px;"><svg viewBox="0 0 24 24"><path d="M15.5 14h-.79l-.28-.27C15.41 12.59 16 11.11 16 9.5 16 5.91 13.09 3 9.5 3S3 5.91 3 9.5 5.91 16 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/></svg></button>` : ''}
          </div>
          ${vfsEnabled ? `
            <div class="file-search-container" id="file-search-wrapper" style="${showSearchInitial ? 'max-height: 40px; opacity: 1;' : 'max-height: 0; opacity: 0;'}">
              <div class="file-search-input-wrapper">
                <i class="fas fa-search" style="position: absolute; left: 9px; top: 50%; transform: translateY(-50%); color: var(--text-secondary); font-size: 0.65rem; opacity: 0.45;"></i>
                <input type="text" id="file-search-input" placeholder="Search files..."
                       oninput="handleFileSearch(this.value, '${identifier}', '${directory.replace(/'/g, "\\'")}')"> 
                <span class="search-shortcut-hint">ESC</span>
              </div>
            </div>
          ` : ''}
        </div>
        <div class="file-list">
          ${(() => {
                const serverId = state.controlPanel.selectedServerId;
                const details = state.serverDetailsCache[serverId]?.data;
                const isNode = isNodeServer(details);
                const isPython = isPythonServer(details);
                const isRoot = directory === '/';
                const boilerplate = ['package-lock.json', 'node_modules', '.pnpm-lock.yaml', '__pycache__'];
                const meaningfulFiles = files.filter(f => !boilerplate.includes(f.attributes.name));
                const isEmpty = meaningfulFiles.length === 0;
                if (!isEmpty) return '';
                if (isNode && isRoot) {
                    state._templatePickerActive = true;
                    return renderTemplatePicker(identifier, NODE_TEMPLATES, { name: 'Codump', url: 'https://github.com/codump' });
                }
                if (isPython && isRoot) {
                    state._templatePickerActive = true;
                    return renderTemplatePicker(identifier, PYTHON_TEMPLATES, { name: 'greenysoka', url: 'https://github.com/greenysoka' });
                }
                return '<div class="files-loading" style="padding: 1rem;"><span>No files yet</span></div>';
            })()}
          ${(state._templatePickerActive ? (state._templatePickerActive = false, []) : files).length > 0 ? renderFileList(identifier, directory, files) : ''}
        </div>
      </div>
    `, panelBody);

    }

    document.addEventListener('keydown', (e) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'f') {
            const modal = document.getElementById('bh-server-details-modal');
            const fileBrowser = modal?.querySelector('#file-browser-path');
            if (modal && fileBrowser && state.settings.vfsEnabled) {
                e.preventDefault();
                e.stopPropagation();
                e.stopImmediatePropagation();
                toggleFileSearchUI();
            }
        }
        if ((e.ctrlKey || e.metaKey) && (e.key === 'r' || e.key === 'R' || e.code === 'KeyR')) {
            const modal = document.getElementById('bh-server-details-modal');
            const filesPanel = modal?.querySelector('.files-panel');
            if (modal && filesPanel && (filesPanel.classList.contains('visible') || filesPanel.style.display === 'block')) {
                e.preventDefault();
                e.stopPropagation();
                e.stopImmediatePropagation();

                const now = Date.now();
                const cooldown = 5000;
                const timePassed = now - (state.lastFileRefresh || 0);

                if (timePassed < cooldown) {
                    const remaining = Math.ceil((cooldown - timePassed) / 1000);
                    showToast(`Please wait ${remaining}s between refreshes`, 'warn');
                    return;
                }

                if (currentFileBrowserIdentifier) {
                    loadFileBrowser(currentFileBrowserIdentifier, currentFileBrowserPath || '/', true);
                    showToast('Refreshing files...', 'info');
                }
            }
        }

        if ((e.ctrlKey || e.metaKey) && (e.key === 'i' || e.key === 'I' || e.code === 'KeyI')) {
            const modal = document.getElementById('bh-server-details-modal');
            const filesPanel = modal?.querySelector('.files-panel');
            if (modal && filesPanel && (filesPanel.classList.contains('visible') || filesPanel.style.display === 'block')) {
                e.preventDefault();
                e.stopPropagation();
                e.stopImmediatePropagation();

                if (!hasPermission('file.create')) {
                    showToast('You do not have permission to create files', 'error');
                    return;
                }

                if (e.shiftKey) {
                    handleNewFolder(currentFileBrowserIdentifier, currentFileBrowserPath || '/');
                } else {
                    handleNewFile(currentFileBrowserIdentifier, currentFileBrowserPath || '/');
                }
            }
        }

        if ((e.key === 'Delete' || e.key === 'Backspace')) {
            const modal = document.getElementById('bh-server-details-modal');
            const filesPanel = modal?.querySelector('.files-panel');
            if (modal && filesPanel && filesPanel.classList.contains('visible')) {
                if (selectedFiles.size > 0 &&
                    document.activeElement.tagName !== 'INPUT' &&
                    document.activeElement.tagName !== 'TEXTAREA') {

                    e.preventDefault();
                    e.stopPropagation();
                    handleBulkDelete(currentFileBrowserIdentifier);
                }
            }
        }
        if (e.key === 'Escape') {
            const modal = document.getElementById('bh-server-details-modal');
            const panelBody = modal?.querySelector('.files-panel .pullout-panel-body');
            if (panelBody?.dataset.searchActive === 'true') {
                toggleFileSearchUI(false);
            }
        }
    }, true);

    window.toggleFileSearchUI = (forceShow) => {
        const modal = document.getElementById('bh-server-details-modal');
        if (!modal) return;
        const panelBody = modal.querySelector('.files-panel .pullout-panel-body');
        const wrapper = modal.querySelector('#file-search-wrapper');
        const input = modal.querySelector('#file-search-input');
        const toggleBtn = modal.querySelector('#vfs-search-toggle');
        if (!wrapper || !input) return;

        const isVisible = panelBody.dataset.searchActive === 'true';
        const shouldShow = forceShow !== undefined ? forceShow : !isVisible;

        if (shouldShow) {
            panelBody.dataset.searchActive = 'true';
            wrapper.style.maxHeight = '50px';
            wrapper.style.opacity = '1';
            wrapper.style.marginTop = '0';
            if (toggleBtn) toggleBtn.classList.add('active');
            setTimeout(() => input.focus(), 100);
        } else {
            panelBody.dataset.searchActive = 'false';
            wrapper.style.maxHeight = '0';
            wrapper.style.opacity = '0';
            wrapper.style.marginTop = '-0.6rem';
            if (toggleBtn) toggleBtn.classList.remove('active');
            if (input.value) {
                input.value = '';
                handleFileSearch('', currentFileBrowserIdentifier, currentFileBrowserPath);
            }
        }
    };
    window.toggleFileSearchUI = toggleFileSearchUI;

    function handleFileSearch(query, identifier, directory) {
        const modal = document.getElementById('bh-server-details-modal');
        if (!modal) return;
        const fileList = modal.querySelector('.file-list');
        if (!fileList) return;

        if (!query || query.trim() === '') {
            loadFileBrowser(identifier, directory);
            return;
        }

        const serverId = state.controlPanel.selectedServerId;
        const results = vfsSearch(serverId, query);

        const files = results.map(node => ({
            object: node.type === 'folder' ? 'directory' : 'file',
            attributes: node.attributes,
            fullPath: node.fullPath
        }));

        DOMUpdater.render(renderFileList(identifier, directory, files), fileList);
    }
    window.handleFileSearch = handleFileSearch;

    function renderFileList(identifier, directory, files) {
        if (files.length === 0) return '<div class="files-loading" style="padding: 1rem;"><span>No results found</span></div>';

        return files.map((file, index) => {
            const icon = getFileIcon(file);
            const isDir = !file.attributes.is_file;
            const size = file.attributes.is_file ? formatFileSize(file.attributes.size) : '';
            const fileName = file.attributes.name;
            const filePath = file.fullPath || (directory === '/' ? '/' + fileName : directory + '/' + fileName);
            const isSearchResult = !!file.fullPath && file.fullPath !== (directory === '/' ? '/' + fileName : directory + '/' + fileName);

            return `
              <div class="file-item ${isSearchResult ? 'search-result' : ''}" 
                   data-path="${escapeHTML(filePath)}" 
                   data-name="${escapeHTML(fileName)}"
                   data-is-dir="${isDir}"
                   data-index="${index}"
                   data-is-editable="${isEditableFile(fileName)}"
                   onclick="handleFileClick(event, '${identifier}', '${filePath.replace(/'/g, "\\'")}', ${isDir}, ${index})"
                   oncontextmenu="showFileContextMenu(event, '${identifier}', '${filePath.replace(/'/g, "\\'")}', '${fileName.replace(/'/g, "\\'")}', ${isDir})">
                <input type="checkbox" class="file-select-cb" data-file-name="${escapeHTML(fileName)}" onclick="event.stopPropagation(); toggleFileSelection('${fileName.replace(/'/g, "\\'")}', ${index}, event)">
                <div class="file-item-icon ${icon.class}">
                  <i class="fas ${icon.icon}"></i>
                </div>
                <div class="file-item-info">
                  <div class="file-item-name notranslate">${escapeHTML(fileName)}</div>
                  ${isSearchResult ? `<div class="file-item-path" style="font-size: 0.7rem; opacity: 0.5; margin-top: 0.1rem;">${escapeHTML(filePath)}</div>` : ''}
                  ${size ? `<div class="file-item-meta">${size}</div>` : ''}
                </div>
                <div class="file-item-actions">
                  <button onclick="event.stopPropagation(); showFileContextMenu(event, '${identifier}', '${filePath.replace(/'/g, "\\'")}', '${fileName.replace(/'/g, "\\'")}', ${isDir})">
                    <i class="fas fa-ellipsis-v"></i>
                  </button>
                </div>
              </div>
            `;
        }).join('');
    }
    ;

    async function loadFileBrowser(identifier, directory = '/', forceRefresh = false) {
        if (state.isDeploying) return;

        const serverId = state.controlPanel.selectedServerId;

        if (forceRefresh) {
            const now = Date.now();
            const cooldown = 5000;
            const timePassed = now - (state.lastFileRefresh || 0);

            if (timePassed < cooldown) {
                const remaining = Math.ceil((cooldown - timePassed) / 1000);
                showToast(`Please wait ${remaining}s between refreshes`, 'warn');
                return;
            }

            state.lastFileRefresh = now;
            state.fbRefreshing = true;
            const refreshBtn = document.getElementById('fb-refresh-btn');
            if (refreshBtn) refreshBtn.classList.add('refreshing');
            if (state.settings.vfsEnabled && serverId) vfsInvalidate(serverId, directory);
        }

        currentFileBrowserIdentifier = identifier;
        currentFileBrowserPath = directory;
        selectedFiles.clear();
        lastClickedFileIndex = -1;

        const modal = document.getElementById('bh-server-details-modal');
        if (!modal) return;

        const panelBody = modal.querySelector('.files-panel .pullout-panel-body');
        if (!panelBody) return;

        if (!panelBody._dragInitialized) {
            panelBody._dragInitialized = true;

            panelBody.addEventListener('dragover', (e) => {
                if (!e.dataTransfer || !e.dataTransfer.types.includes('Files')) return;
                e.preventDefault();
                e.stopPropagation();
                if (!panelBody.querySelector('.drag-drop-overlay')) {
                    const canUpload = hasPermission('file.create');
                    const overlay = document.createElement('div');
                    overlay.className = `drag-drop-overlay ${canUpload ? '' : 'no-permission'}`;
                    DOMUpdater.render(canUpload ? `
                        <div class="drag-drop-content">
                            <i class="fas fa-cloud-upload-alt"></i>
                            <span>Drop files to upload</span>
                        </div>
                    ` : `
                        <div class="drag-drop-content">
                            <i class="fas fa-lock" style="color: var(--accent-error, #ef4444);"></i>
                            <span style="color: var(--accent-error, #ef4444);">No permission to upload files</span>
                        </div>
                    `, overlay);
                    panelBody.style.position = 'relative';
                    panelBody.appendChild(overlay);
                }
            });

            panelBody.addEventListener('dragleave', (e) => {
                e.preventDefault();
                e.stopPropagation();
                if (!panelBody.contains(e.relatedTarget)) {
                    const overlay = panelBody.querySelector('.drag-drop-overlay');
                    if (overlay) overlay.remove();
                }
            });

            panelBody.addEventListener('drop', async (e) => {
                e.preventDefault();
                e.stopPropagation();
                const overlay = panelBody.querySelector('.drag-drop-overlay');
                if (overlay) overlay.remove();

                if (!hasPermission('file.create')) return;

                if (state.isUploading) {
                    showToast('An upload is already in progress', 'warn');
                    return;
                }

                const files = Array.from(e.dataTransfer.files);
                if (files.length === 0) return;

                handleFileUpload(currentFileBrowserIdentifier, currentFileBrowserPath, files);
            });
        }

        const details = state.serverDetailsCache[serverId]?.data;

        if (details) {
            const stateDesc = getSidebarState(details);
            if (stateDesc) {
                renderSidebarStateMessage(panelBody, stateDesc, details);
                return;
            }
        }

        const vfsEnabled = state.settings.vfsEnabled;
        const cachedNode = vfsEnabled ? vfsResolve(serverId, directory) : null;

        if (vfsEnabled && cachedNode && cachedNode.children) {
            const files = Object.values(cachedNode.children).map(child => ({
                object: child.type === 'folder' ? 'directory' : 'file',
                attributes: child.attributes
            }));
            renderFileBrowserUI(identifier, directory, files);

            if (!vfsIsStale(cachedNode) && directory !== '/' && !forceRefresh) {
                state.fbRefreshing = false;
                return;
            }

            fetchServerFiles(identifier, directory).then(fetchResult => {
                state.fbRefreshing = false;
                if (Array.isArray(fetchResult)) {
                    vfsUpdate(serverId, directory, fetchResult);
                    if (currentFileBrowserIdentifier === identifier && currentFileBrowserPath === directory) {
                        renderFileBrowserUI(identifier, directory, fetchResult);
                    }
                } else {
                    renderFileBrowserUI(identifier, directory, files);
                }
            });
            return;
        }

        if (!forceRefresh) {
            DOMUpdater.render(`
          <div class="files-loading">
            <svg class="bh-spinner" style="font-size: 1.5rem;" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>
            <span>Loading files...</span>
          </div>
        `, panelBody);
        }

        const fetchResult = await fetchServerFiles(identifier, directory);
        state.fbRefreshing = false;

        const refreshBtn = document.getElementById('fb-refresh-btn');
        if (refreshBtn) refreshBtn.classList.remove('refreshing');

        if (fetchResult && (fetchResult.status === 403 || fetchResult.status === 401)) {
            DOMUpdater.render(`
        <div class="empty-state">
          <div class="empty-icon">
            <i class="fas fa-lock" style="font-size: 2rem; color: var(--text-secondary); margin-bottom: 1rem; opacity: 0.5;"></i>
          </div>
          <h3>Permission Denied</h3>
          <p>You do not have permission to view files for this server.</p>
        </div>
      `, panelBody);
            return;
        }

        const files = Array.isArray(fetchResult) ? fetchResult : null;

        if (!files) {
            DOMUpdater.render(`
        <div class="files-error">
          <i class="fas fa-exclamation-triangle"></i>
          <span class="files-error-message">Failed to load files</span>
          <div class="files-sftp-fallback" onclick="window.showSFTPDetailsModal('${serverId}')">
            <i class="fas fa-key"></i>
            <span>Use SFTP Instead</span>
            <p>Direct file management is unavailable. Connect via SFTP for better reliability.</p>
          </div>
        </div>
      `, panelBody);
            return;
        }

        vfsUpdate(serverId, directory, files);
        vfsStartCrawler();
        vfsEnqueue(serverId, directory);
        renderFileBrowserUI(identifier, directory, files);
    }


    function toggleFileSelection(fileName, index, event) {
        const checkboxes = document.querySelectorAll('.file-list .file-select-cb');

        if (event?.shiftKey && lastClickedFileIndex >= 0) {
            event.preventDefault?.();
            window.getSelection()?.removeAllRanges();
            const start = Math.min(lastClickedFileIndex, index);
            const end = Math.max(lastClickedFileIndex, index);

            const shouldDeselect = selectedFiles.has(fileName);

            for (let i = start; i <= end; i++) {
                if (checkboxes[i]) {
                    const name = checkboxes[i].dataset.fileName;
                    if (shouldDeselect) {
                        selectedFiles.delete(name);
                        checkboxes[i].checked = false;
                    } else {
                        selectedFiles.add(name);
                        checkboxes[i].checked = true;
                    }
                }
            }
        } else {
            const isSelected = selectedFiles.has(fileName);
            if (isSelected) {
                selectedFiles.delete(fileName);
                if (checkboxes[index]) checkboxes[index].checked = false;
            } else {
                selectedFiles.add(fileName);
                if (checkboxes[index]) checkboxes[index].checked = true;
            }
        }
        lastClickedFileIndex = index;
        updateFileSelectionUI();
    }

    function toggleSelectAllFiles(selectAllCb) {
        const checkboxes = document.querySelectorAll('.file-list .file-select-cb');
        checkboxes.forEach(cb => {
            cb.checked = selectAllCb.checked;
            const name = cb.dataset.fileName;
            if (selectAllCb.checked) {
                selectedFiles.add(name);
            } else {
                selectedFiles.delete(name);
            }
        });
        updateFileSelectionUI();
    }

    function updateFileSelectionUI() {
        const pathEl = document.getElementById('file-browser-path');
        const infoEl = document.getElementById('file-selection-info');
        const actionsEl = document.getElementById('file-selection-actions');
        const countEl = document.getElementById('file-selection-count');
        const selectAllCb = document.getElementById('file-select-all-cb');
        const creationActions = document.getElementById('file-creation-actions');
        const searchToggle = document.getElementById('vfs-search-toggle');

        const isSelecting = selectedFiles.size > 0;
        if (infoEl) infoEl.style.display = isSelecting ? 'flex' : 'none';
        if (actionsEl) actionsEl.style.display = isSelecting ? 'flex' : 'none';
        if (creationActions) creationActions.style.display = isSelecting ? 'none' : 'flex';
        if (searchToggle) searchToggle.style.display = isSelecting ? 'none' : 'inline-flex';
        if (countEl) countEl.textContent = `${selectedFiles.size} SELECTED`;
        if (selectAllCb) {
            const allCbs = document.querySelectorAll('.file-list .file-select-cb');
            selectAllCb.checked = selectedFiles.size > 0 && selectedFiles.size === allCbs.length;
            selectAllCb.indeterminate = selectedFiles.size > 0 && selectedFiles.size < allCbs.length;
        }
        document.querySelectorAll('.file-item').forEach(item => {
            const name = item.dataset.name;
            item.classList.toggle('selected', selectedFiles.has(name));
        });
    }

    async function handleBulkDelete(identifier) {
        if (selectedFiles.size === 0) return;
        openConfirmModal('Delete Items', `Are you sure you want to delete ${selectedFiles.size} item(s)? This action cannot be undone.`, async () => {
            showToast(`Deleting ${selectedFiles.size} item(s)...`, 'info');
            const success = await deleteServerFile(identifier, currentFileBrowserPath, [...selectedFiles]);
            if (success) {
                showToast('Deleted successfully!', 'success');
                loadFileBrowser(identifier, currentFileBrowserPath);
            } else {
                showToast('Failed to delete some items', 'error');
            }
        }, 'Delete', true);
    }

    async function handleBulkArchive(identifier) {
        if (selectedFiles.size === 0) return;
        showToast(`Archiving ${selectedFiles.size} item(s)...`, 'info');
        const result = await compressServerFiles(identifier, currentFileBrowserPath, [...selectedFiles]);
        if (result) {
            showToast('Archive created successfully!', 'success');
            const serverId = state.controlPanel.selectedServerId;
            vfsInvalidate(serverId, currentFileBrowserPath);
            loadFileBrowser(identifier, currentFileBrowserPath);
        } else {
            showToast('Failed to create archive', 'error');
        }
    }

    function showConfirmModal(options) {
        return new Promise((resolve) => {
            openConfirmModal(
                options.title || 'Confirm',
                options.message || 'Are you sure?',
                () => resolve(true),
                options.confirmText || 'Confirm',
                options.isDanger !== undefined ? options.isDanger : true
            );
        });
    }

    function openConfirmModal(title, message, onConfirm, confirmText = 'Confirm', isDanger = true, onCancel = null, isHTML = false) {
        const modal = document.createElement('div');
        modal.className = 'bananaa-modal';
        modal.style.zIndex = '2147483647';

        DOMUpdater.render(`
      <div class="modal-overlay"></div>
      <div class="modal-container" style="max-width: 400px; border: 1px solid var(--border-light); background: var(--modal-bg-primary);">
        <div class="modal-header" style="margin: 0; padding: 1.25rem 1.5rem; border-bottom: 1px solid rgba(255,255,255,0.05); background: var(--modal-bg-secondary);">
        <div class="modal-title">
            <h3 style="margin: 0; color: var(--modal-text-primary); font-size: 1.1rem;">${isHTML ? title : sanitizeHTML(title)}</h3>
          </div>
          <button class="modal-close" style="background: transparent; border: none; color: var(--modal-text-primary); cursor: pointer;"><i class="fas fa-times"></i></button>
        </div>
        <div class="modal-body" style="padding: 1.5rem;">
          <div style="margin: 0; color: var(--modal-text-secondary); line-height: 1.5;">${isHTML ? message : sanitizeHTML(message)}</div>
        </div>
        <div class="modal-footer" style="padding: 1rem 1.5rem; background: var(--modal-bg-secondary); border-top: 1px solid var(--border-light); display: flex; justify-content: flex-end; gap: 0.75rem;">
          <button class="btn btn-secondary btn-cancel" style="padding: 0.5rem 1.25rem; border-radius: 8px;">Cancel</button>
          <button class="btn ${isDanger ? 'btn-danger' : 'btn-primary'} btn-confirm" style="padding: 0.5rem 1.25rem; border-radius: 8px;">${sanitizeHTML(confirmText)}</button>
        </div>
      </div>
    `, modal);

        document.body.appendChild(modal);
        updateModalTextColors();
        void modal.offsetHeight;
        requestAnimationFrame(() => modal.classList.add('visible'));

        const close = () => {
            window.removeEventListener('keydown', escHandler, true);
            modal.classList.remove('visible');
            setTimeout(() => modal.remove(), 300);
            if (onCancel) onCancel();
        };

        modal.querySelector('.modal-overlay').onclick = close;
        modal.querySelector('.modal-close').onclick = close;
        modal.querySelector('.btn-cancel').onclick = close;

        const confirmBtn = modal.querySelector('.btn-confirm');
        confirmBtn.onclick = () => {
            onConfirm();
            close();
        };

        const escHandler = (e) => {
            if (e.key === 'Escape') {
                e.preventDefault();
                e.stopPropagation();
                close();
            }
            if (e.key === 'Enter') {
                e.preventDefault();
                e.stopPropagation();
                if (document.activeElement) document.activeElement.blur();
                confirmBtn.click();
            }
        };
        window.addEventListener('keydown', escHandler, true);
    }

    function handleBulkMove(identifier) {
        if (selectedFiles.size === 0) return;
        openMoveModal(identifier, [...selectedFiles], currentFileBrowserPath);
    }

