    async function deployTemplate(identifier, templateId) {
        const template = ALL_TEMPLATES.find(t => t.id === templateId);
        if (!template) return;

        const panelBody = document.querySelector('#bh-server-details-modal .files-panel .pullout-panel-body');
        if (!panelBody) return;

        if (template.blankFiles) {
            state.isDeploying = true;
            DOMUpdater.render(`
                <div class="template-deploy-progress">
                    <svg class="bh-spinner" style="font-size: 1.5rem; color: var(--accent-primary);" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>
                    <span>Creating blank project...</span>
                </div>
            `, panelBody);
            try {
                for (const [filePath, content] of Object.entries(template.blankFiles)) {
                    await saveFileContents(identifier, filePath, content);
                }
                showToast('Blank project created!', 'success');
            } catch (e) {
                showToast('Failed to create blank project', 'error');
            } finally {
                state.isDeploying = false;
                loadFileBrowser(identifier, '/');
            }
            return;
        }

        DOMUpdater.render(`
            <div class="template-deploy-progress">
                <div class="template-deploy-icon">
                    <i class="fas fa-download" style="font-size: 1.3rem; color: var(--accent-primary);"></i>
                </div>
                <div class="template-deploy-info">
                    <h4>Deploying ${template.name}...</h4>
                    <p id="template-deploy-status">Cleaning up...</p>
                </div>
                <div class="template-deploy-bar-container">
                    <div class="template-deploy-bar" id="template-deploy-bar" style="width: 0%;"></div>
                </div>
                <span id="template-deploy-count" style="font-size: 0.75rem; color: var(--text-secondary);">0 / ?</span>
            </div>
        `, panelBody);

        try {
            state.isDeploying = true;
            try {
                await deleteServerFile(identifier, '/', ['package-lock.json']);
            } catch (e) { /* */ }
            const [owner, repo] = template.repo.split('/');
            const treeResponse = await fetch(`https://api.github.com/repos/${owner}/${repo}/git/trees/main?recursive=1`);
            if (!treeResponse.ok) throw new Error('Failed to fetch repo tree');
            const treeData = await treeResponse.json();

            const blobs = treeData.tree.filter(item => {
                if (item.type !== 'blob') return false;
                if (item.size > 1048576) return false;
                for (const skip of template.skip) {
                    if (skip.endsWith('/') && item.path.startsWith(skip)) return false;
                    if (item.path === skip) return false;
                }
                return true;
            });

            const dirs = new Set();
            blobs.forEach(b => {
                const parts = b.path.split('/');
                for (let i = 1; i < parts.length; i++) {
                    dirs.add(parts.slice(0, i).join('/'));
                }
            });

            const sortedDirs = [...dirs].sort((a, b) => a.split('/').length - b.split('/').length);
            for (const dir of sortedDirs) {
                const parentParts = dir.split('/');
                const folderName = parentParts.pop();
                const parentDir = '/' + parentParts.join('/');
                await createNewServerFolder(identifier, parentDir || '/', folderName);
            }

            const statusEl = document.getElementById('template-deploy-status');
            const barEl = document.getElementById('template-deploy-bar');
            const countEl = document.getElementById('template-deploy-count');

            let completed = 0;
            const total = blobs.length;

            for (const blob of blobs) {
                if (statusEl) statusEl.textContent = blob.path;
                if (countEl) countEl.textContent = `${completed} / ${total}`;

                const blobResponse = await fetch(blob.url);
                if (!blobResponse.ok) {
                    BnLog('ERROR', `Failed to fetch blob: ${blob.path}`);
                    completed++;
                    continue;
                }
                const blobData = await blobResponse.json();
                const content = atob(blobData.content.replace(/\n/g, ''));
                await saveFileContents(identifier, '/' + blob.path, content);

                completed++;
                const pct = Math.round((completed / total) * 100);
                if (barEl) barEl.style.width = pct + '%';
                if (countEl) countEl.textContent = `${completed} / ${total}`;
            }

            vfsInvalidate(identifier, '/');
            DOMUpdater.render(`
                <div class="template-deploy-success">
                    <div class="success-icon"><i class="fas fa-check-circle"></i></div>
                    <h3>Deployed!</h3>
                    <p>${template.name} has been set up on your server.</p>
                    <div class="success-actions" style="display: flex; gap: 0.75rem; margin-top: 1.5rem; justify-content: center;">
                        <button class="btn btn-secondary" onclick="loadFileBrowser('${identifier}', '/')">
                            <i class="fas fa-server"></i>Enter
                        </button>
                        ${template.readmeUrl ? `
                        <a href="${template.readmeUrl}" target="_blank" class="btn btn-primary" style="text-decoration: none;">
                            <i class="fas fa-book"></i>Docs
                        </a>
                        ` : ''}
                    </div>
                </div>
            `, panelBody);
            state.isDeploying = false;
            showToast(`${template.name} deployed successfully!`, 'success');

        } catch (error) {
            state.isDeploying = false;
            BnLog('ERROR', 'Template deploy failed:', error);
            showToast('Failed to deploy template: ' + error.message, 'error');
            loadFileBrowser(identifier, '/');
        }
    }

    window.__deployTemplate = deployTemplate;

    const UPLOAD_MAX_CONCURRENT = 3;
    const UPLOAD_MAX_FILE_SIZE = 100 * 1024 * 1024;

    async function handleFileUpload(identifier, directory, droppedFiles) {
        if (!hasPermission('file.create')) {
            showToast('No permission to upload files', 'error');
            return;
        }

        const cancelledUploads = new Set();

        const cancelUpload = (idx) => {
            const controller = state.activeUploads.get(idx);
            if (controller) {
                controller.abort();
                state.activeUploads.delete(idx);
                const statusEl = document.getElementById(`upload-status-${idx}`);
                const barEl = document.getElementById(`upload-bar-${idx}`);
                const cancelBtn = document.getElementById(`upload-cancel-${idx}`);
                if (statusEl) DOMUpdater.render('<i class="fas fa-ban" style="color: var(--text-secondary);"></i>', statusEl);
                if (barEl) {
                    barEl.style.width = '100%';
                    barEl.style.background = 'var(--text-secondary)';
                }
                if (cancelBtn) cancelBtn.style.display = 'none';
                showToast('Upload cancelled', 'info');
            } else {
                cancelledUploads.add(idx);
                const statusEl = document.getElementById(`upload-status-${idx}`);
                const barEl = document.getElementById(`upload-bar-${idx}`);
                const cancelBtn = document.getElementById(`upload-cancel-${idx}`);
                if (statusEl) DOMUpdater.render('<i class="fas fa-ban" style="color: var(--text-secondary);"></i>', statusEl);
                if (barEl) {
                    barEl.style.width = '100%';
                    barEl.style.background = 'var(--text-secondary)';
                }
                if (cancelBtn) cancelBtn.style.display = 'none';
                showToast('Upload cancelled', 'info');
            }
        };
        window.__cancelUpload = cancelUpload;

        const processUploadFiles = async (files) => {
            if (files.length === 0) return;

            const oversized = files.filter(f => f.size > UPLOAD_MAX_FILE_SIZE);
            const valid = files.filter(f => f.size <= UPLOAD_MAX_FILE_SIZE);

            if (oversized.length > 0) {
                const names = oversized.map(f => f.name).join(', ');
                showToast(`${oversized.length} file(s) exceed 100MB and must be uploaded via SFTP: ${names}`, 'error');
            }

            if (valid.length === 0) return;

            const panelBody = document.querySelector('#bh-server-details-modal .files-panel .pullout-panel-body');
            if (!panelBody) return;

            const fileRows = valid.map((f, i) => `
                <div class="upload-file-row" id="upload-row-${i}">
                    <div class="upload-file-icon"><i class="fas fa-file"></i></div>
                    <div class="upload-file-info">
                        <div class="upload-file-name" title="${f.name}">${f.name}</div>
                        <div class="upload-file-size">${formatFileSize(f.size)}</div>
                    </div>
                    <div class="upload-file-status" id="upload-status-${i}">
                        <i class="fas fa-clock" style="color: var(--text-secondary);"></i>
                    </div>
                    <button class="upload-cancel-btn" id="upload-cancel-${i}" onclick="__cancelUpload(${i})" title="Cancel Upload">
                        <i class="fas fa-times"></i>
                    </button>
                    <div class="upload-file-bar-container">
                        <div class="upload-file-bar" id="upload-bar-${i}"></div>
                    </div>
                </div>
            `).join('');

            DOMUpdater.render(`
                <div class="upload-overlay">
                    <div class="upload-overlay-header">
                        <i class="fas fa-cloud-upload-alt" style="font-size: 1.2rem; color: var(--accent-primary);"></i>
                        <div>
                            <h4>Uploading ${valid.length} file${valid.length > 1 ? 's' : ''}...</h4>
                            <span id="upload-overall-status" style="font-size: 0.75rem; color: var(--text-secondary);">Starting...</span>
                        </div>
                    </div>
                    <div class="upload-file-list">
                        ${fileRows}
                    </div>
                </div>
            `, panelBody);

            let completed = 0;
            let failed = 0;

            const uploadOne = async (file, index) => {
                if (cancelledUploads.has(index)) {
                    completed++;
                    const overallEl = document.getElementById('upload-overall-status');
                    if (overallEl) overallEl.textContent = `${completed} / ${valid.length} complete`;
                    return;
                }

                const statusEl = document.getElementById(`upload-status-${index}`);
                const barEl = document.getElementById(`upload-bar-${index}`);
                const cancelBtn = document.getElementById(`upload-cancel-${index}`);

                if (statusEl) DOMUpdater.render('<svg class="bh-spinner" style="color: var(--accent-primary);" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>', statusEl);
                if (barEl) barEl.style.width = '10%';

                const controller = new AbortController();
                state.activeUploads.set(index, controller);

                try {
                    if (statusEl) DOMUpdater.render('<svg class="bh-spinner" style="color: var(--accent-primary);" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>', statusEl);
                    const signResponse = await callProxyFetch(
                        `https://control.bot-hosting.net/api/client/servers/${identifier}/files/upload`,
                        { signal: controller.signal }
                    );

                    if (!signResponse?.data?.attributes?.url) throw new Error('Failed to get upload URL');
                    const uploadUrl = signResponse.data.attributes.url;

                    if (barEl) barEl.style.width = '30%';
                    if (statusEl) DOMUpdater.render('<svg class="bh-spinner" style="color: var(--accent-primary);" viewBox="0 0 50 50"><circle class="path" cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle></svg>', statusEl);

                    const formData = new FormData();
                    formData.append('files', file);

                    const xhr = new XMLHttpRequest();
                    xhr.open('POST', `${uploadUrl}&directory=${encodeURIComponent(directory)}`, true);

                    if (controller.signal) {
                        controller.signal.addEventListener('abort', () => xhr.abort());
                    }

                    xhr.upload.onprogress = (e) => {
                        if (e.lengthComputable && barEl) {
                            const percent = (e.loaded / e.total) * 70;
                            barEl.style.width = `${30 + percent}%`;
                        }
                    };

                    const uploadPromise = new Promise((resolve, reject) => {
                        xhr.onload = () => {
                            if (xhr.status >= 200 && xhr.status < 300) resolve();
                            else reject(new Error(`Upload failed with status ${xhr.status}`));
                        };
                        xhr.onerror = () => reject(new Error('Network error during upload'));
                        xhr.onabort = () => reject(new Error('Upload aborted'));
                        xhr.send(formData);
                    });

                    await uploadPromise;

                    const serverId = state.controlPanel.selectedServerId;
                    const parent = vfsResolve(serverId, directory);
                    if (parent) {
                        const filePath = (directory === '/' ? '/' : directory + '/') + file.name;
                        if (!parent.children) parent.children = {};
                        parent.children[file.name] = {
                            type: 'file',
                            lastSynced: Date.now(),
                            fullPath: filePath,
                            attributes: { name: file.name, is_file: true, size: file.size, modified_at: new Date().toISOString() }
                        };
                    }

                    if (barEl) barEl.style.width = '100%';
                    if (barEl) barEl.style.background = 'var(--accent-success, #10b981)';
                    if (statusEl) DOMUpdater.render('<i class="fas fa-check-circle" style="color: var(--accent-success, #10b981);"></i>', statusEl);
                    if (cancelBtn) cancelBtn.style.display = 'none';

                    emitPluginEvent('fileSaved', { identifier, filePath: (directory === '/' ? '/' : directory + '/') + file.name });

                } catch (err) {
                    if (err.name === 'AbortError' || err.message === 'Upload aborted') {
                        BnLog('UPLOAD', `Upload aborted: ${file.name}`);
                    } else {
                        BnLog('ERROR', `Upload failed: ${file.name}`, err);
                        failed++;
                        if (barEl) barEl.style.width = '100%';
                        if (barEl) barEl.style.background = '#ef4444';
                        if (statusEl) DOMUpdater.render('<i class="fas fa-times-circle" style="color: #ef4444;"></i>', statusEl);
                        if (cancelBtn) cancelBtn.style.display = 'none';
                    }
                } finally {
                    state.activeUploads.delete(index);
                }

                completed++;
                const overallEl = document.getElementById('upload-overall-status');
                if (overallEl) overallEl.textContent = `${completed} / ${valid.length} complete`;
            };

            const queue = [...valid.entries()];
            const workers = [];
            state.isUploading = true;
            for (let w = 0; w < Math.min(UPLOAD_MAX_CONCURRENT, queue.length); w++) {
                workers.push((async () => {
                    while (queue.length > 0) {
                        const next = queue.shift();
                        if (next) await uploadOne(next[1], next[0]);
                    }
                })());
            }
            await Promise.all(workers);
            state.isUploading = false;

            if (failed > 0) {
                showToast(`${failed} file(s) failed to upload`, 'error');
            } else if (completed > 0) {
                showToast(`${valid.length} file${valid.length > 1 ? 's' : ''} uploaded successfully!`, 'success');
            }

            setTimeout(() => {
                const overlay = panelBody.querySelector('.upload-overlay');
                if (overlay) {
                    overlay.style.opacity = '0';
                    overlay.style.transform = 'translateY(10px)';
                    setTimeout(() => {
                        overlay.remove();
                        const serverId = state.controlPanel.selectedServerId;
                        vfsInvalidate(serverId, directory);
                        loadFileBrowser(identifier, directory);
                    }, 400);
                }
            }, 3000);
        };

        if (droppedFiles && droppedFiles.length > 0) {
            await processUploadFiles(droppedFiles);
            return;
        }

        const input = document.createElement('input');
        input.type = 'file';
        input.multiple = true;
        input.style.display = 'none';
        document.body.appendChild(input);

        input.onchange = async () => {
            const files = Array.from(input.files);
            input.remove();
            await processUploadFiles(files);
        };

        input.click();
    }
    window.handleFileUpload = handleFileUpload;

