    function handleFileClick(event, identifier, filePath, isDir, index) {
        if (event.target.closest('.file-item-actions')) return;
        if (event.target.closest('.file-select-cb')) return;

        const fileName = filePath.split('/').pop();

        if (event.shiftKey || event.metaKey || event.ctrlKey) {
            event.preventDefault();
            window.getSelection()?.removeAllRanges();
            toggleFileSelection(fileName, index, event);
            return;
        }

        if (isDir) {
            loadFileBrowser(identifier, filePath);
        } else {
            if (isEditableFile(fileName)) {
                openFileEditor(identifier, filePath);
            }
        }
    }

    window.handleFileClick = handleFileClick;

    let activeContextMenu = null;

    function showContextMenu(event, items) {
        if (event) {
            if (state.devMode && event.ctrlKey) {
                return;
            }
            event.preventDefault();
            event.stopPropagation();
        }

        const closeContextMenu = () => {
            document.querySelectorAll('.bh-context-submenu').forEach(s => s.remove());
            if (activeContextMenu) {
                activeContextMenu.remove();
                activeContextMenu = null;
            }
            const overlay = document.querySelector('.bh-context-menu-overlay');
            if (overlay) overlay.remove();

            document.body.style.overflow = '';
            document.querySelectorAll('.context-menu-active').forEach(el => {
                el.classList.remove('context-menu-active');
            });

            document.removeEventListener('click', closeHandler);
            window.removeEventListener('blur', closeHandler);
        };

        const closeHandler = (e) => {
            if (e.type === 'blur' || (activeContextMenu && !activeContextMenu.contains(e.target))) {
                closeContextMenu();
            }
        };

        if (activeContextMenu) {
            closeContextMenu();
        }

        document.body.style.overflow = 'hidden';

        const overlay = document.createElement('div');
        overlay.className = 'bh-context-menu-overlay';
        overlay.style.cssText = 'position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background: transparent; z-index: 2147483646; cursor: default;';
        overlay.onclick = closeContextMenu;
        overlay.oncontextmenu = (e) => {
            e.preventDefault();
            e.stopPropagation();
            closeContextMenu();

            const target = document.elementFromPoint(e.clientX, e.clientY);
            if (target) {
                const newEvent = new MouseEvent('contextmenu', {
                    bubbles: true,
                    cancelable: true,
                    clientX: e.clientX,
                    clientY: e.clientY,
                    button: 2
                });
                target.dispatchEvent(newEvent);
            }
        };
        document.body.appendChild(overlay);

        const triggerElement = event?.currentTarget;
        if (triggerElement) {
            triggerElement.classList.add('context-menu-active');
            const container = triggerElement.closest('.file-item, .detail-card, .server-card, .upload-file-row, .activity-item, .market-item');
            if (container) container.classList.add('context-menu-active');
        }

        const menu = document.createElement('div');
        menu.className = 'file-context-menu bh-context-menu';
        menu.style.zIndex = '2147483647';

        items.forEach(item => {
            if (item.type === 'divider') {
                const divider = document.createElement('div');
                divider.className = 'context-menu-divider';
                menu.appendChild(divider);
                return;
            }
            const div = document.createElement('div');
            div.className = `context-menu-item ${item.isDanger ? 'danger' : ''} ${item.submenu ? 'has-submenu' : ''}`;
            DOMUpdater.render(`<i class="${escapeHTML(item.icon)}"></i> ${escapeHTML(item.label)}${item.submenu ? '<i class="fas fa-chevron-right" style="margin-left: auto; font-size: 0.65rem; opacity: 0.5;"></i>' : ''}`, div);

            if (item.submenu) {
                let submenuEl = null;
                let submenuTimeout = null;

                const openSubmenu = () => {
                    clearTimeout(submenuTimeout);
                    menu.querySelectorAll('.bh-context-submenu').forEach(s => s.remove());

                    submenuEl = document.createElement('div');
                    submenuEl.className = 'file-context-menu bh-context-menu bh-context-submenu';
                    submenuEl.style.zIndex = '2147483647';
                    submenuEl.style.position = 'fixed';

                    item.submenu.forEach(sub => {
                        if (sub.type === 'divider') {
                            const d = document.createElement('div');
                            d.className = 'context-menu-divider';
                            submenuEl.appendChild(d);
                            return;
                        }
                        const subDiv = document.createElement('div');
                        subDiv.className = `context-menu-item ${sub.isDanger ? 'danger' : ''} ${sub.isActive ? 'submenu-active' : ''}`;
                        DOMUpdater.render(`<i class="${escapeHTML(sub.icon)}"></i> ${escapeHTML(sub.label)}`, subDiv);
                        subDiv.onclick = (e) => {
                            e.stopPropagation();
                            closeContextMenu();
                            if (sub.onClick) sub.onClick();
                        };
                        submenuEl.appendChild(subDiv);
                    });

                    document.body.appendChild(submenuEl);

                    const parentRect = div.getBoundingClientRect();
                    const subRect = submenuEl.getBoundingClientRect();
                    const spaceRight = window.innerWidth - parentRect.right;
                    const spaceLeft = parentRect.left;

                    if (spaceRight >= subRect.width + 10) {
                        submenuEl.style.left = (parentRect.right + 4) + 'px';
                    } else if (spaceLeft >= subRect.width + 10) {
                        submenuEl.style.left = (parentRect.left - subRect.width - 4) + 'px';
                    } else {
                        submenuEl.style.left = (window.innerWidth - subRect.width - 10) + 'px';
                    }

                    submenuEl.style.top = parentRect.top + 'px';
                    const finalRect = submenuEl.getBoundingClientRect();
                    if (finalRect.bottom > window.innerHeight) {
                        submenuEl.style.top = (window.innerHeight - finalRect.height - 10) + 'px';
                    }

                    submenuEl.onmouseenter = () => {
                        clearTimeout(submenuTimeout);
                    };
                    submenuEl.onmouseleave = () => {
                        closeSubmenu();
                    };
                };

                const closeSubmenu = () => {
                    submenuTimeout = setTimeout(() => {
                        if (submenuEl) {
                            submenuEl.remove();
                            submenuEl = null;
                            div.classList.remove('submenu-active');
                        }
                    }, 100);
                };

                div.onmouseenter = () => {
                    openSubmenu();
                    div.classList.add('submenu-active');
                };
                div.onmouseleave = closeSubmenu;
            } else {
                div.onclick = (e) => {
                    e.stopPropagation();
                    closeContextMenu();
                    if (item.onClick) item.onClick();
                };
            }
            menu.appendChild(div);
        });

        menu.style.left = event.clientX + 'px';
        menu.style.top = event.clientY + 'px';

        document.body.appendChild(menu);
        activeContextMenu = menu;

        const rect = menu.getBoundingClientRect();
        if (rect.right > window.innerWidth) {
            menu.style.left = (window.innerWidth - rect.width - 10) + 'px';
        }
        if (rect.bottom > window.innerHeight) {
            menu.style.top = (window.innerHeight - rect.height - 10) + 'px';
        }

        setTimeout(() => {
            document.addEventListener('click', closeHandler);
            window.addEventListener('blur', closeHandler);
        }, 10);
    }

    function showFileContextMenu(event, identifier, filePath, fileName, isDir) {

        const editable = !isDir && isEditableFile(fileName);
        const canDelete = hasPermission('file.delete');
        const canUpdate = hasPermission('file.update');
        const canArchive = hasPermission('file.archive');

        const isArchive = !isDir && (
            fileName.endsWith('.zip') ||
            fileName.endsWith('.tar') ||
            fileName.endsWith('.tar.gz') ||
            fileName.endsWith('.tgz') ||
            fileName.endsWith('.tar.bz2') ||
            fileName.endsWith('.rar') ||
            fileName.endsWith('.7z')
        );

        const items = [];
        if (editable) items.push({ label: 'Edit', icon: 'fas fa-edit', onClick: () => openFileEditor(identifier, filePath) });
        if (!isDir) items.push({ label: 'Download', icon: 'fas fa-download', onClick: () => downloadFile(identifier, filePath) });
        if (canUpdate) items.push({ label: 'Rename', icon: 'fas fa-i-cursor', onClick: () => handleRenameFile(identifier, filePath, fileName) });
        items.push({ label: 'Move', icon: 'fas fa-arrows-alt', onClick: () => handleMoveFile(identifier, filePath, fileName) });

        if (canArchive) {
            if (isArchive) {
                items.push({ label: 'Unarchive', icon: 'fas fa-file-export', onClick: () => handleUnarchiveFile(identifier, filePath, fileName) });
            } else {
                items.push({ label: 'Archive', icon: 'fas fa-file-zipper', onClick: () => archiveFile(identifier, filePath, fileName) });
            }
        }

        if (canDelete) {
            items.push({ type: 'divider' });
            items.push({ label: 'Delete', icon: 'fas fa-trash', isDanger: true, onClick: () => deleteFile(identifier, filePath, fileName) });
        }

        showContextMenu(event, items);
    }

    async function handleRenameFile(identifier, filePath, oldName) {
        if (activeContextMenu) activeContextMenu.remove();

        const isDir = !oldName.includes('.');
        const title = isDir ? 'Rename Folder' : 'Rename File';

        openInputModal(title, 'Enter new name', async (newName) => {
            const trimmedName = newName.trim();
            if (!trimmedName || trimmedName === oldName) return;

            const root = filePath.substring(0, filePath.lastIndexOf('/')) || '/';
            showToast('Renaming...', 'info');
            const success = await renameServerFile(identifier, root, oldName, trimmedName);
            if (success) {
                showToast('Renamed successfully!', 'success');
                loadFileBrowser(identifier, root);
            } else {
                showToast('Failed to rename', 'error');
            }
        }, 'Rename', oldName);
    }

    function handleMoveFile(identifier, filePath, fileName) {
        if (activeContextMenu) activeContextMenu.remove();
        const root = filePath.substring(0, filePath.lastIndexOf('/')) || '/';
        openMoveModal(identifier, [fileName], root);
    }

    window.showFileContextMenu = showFileContextMenu;
