    window.handlePowerAction = handlePowerAction;
    window.navigateTo = navigateTo;
    window.unsuspendServer = unsuspendServer;
    window.toggleTheme = toggleTheme;
    window.ejectScript = ejectScript;
    function handleConsoleContextMenu(event) {
        const selection = window.getSelection();
        const selectedText = selection.toString().trim();
        const items = [];

        if (selectedText) {
            event.preventDefault();
            event.stopPropagation();

            items.push({
                icon: 'fas fa-copy',
                label: 'Copy Selection',
                onClick: () => {
                    navigator.clipboard.writeText(selectedText);
                    showToast('Text copied to clipboard!', 'success');
                }
            });

            showContextMenu(event, items);
        }
    }

    window.handleConsoleContextMenu = handleConsoleContextMenu;
    window.showContextMenu = showContextMenu;
    window.showServerDetails = showServerDetails;
    window.openControlPanel = openControlPanel;
    window.fetchServers = fetchServers;
    window.fetchTransactions = fetchTransactions;
    window.refreshTransactionsWithAnimation = refreshTransactionsWithAnimation;
    window.startCoinCollector = startCoinCollector;
    window.stopCoinCollector = stopCoinCollector;
    window.startServerCreator = startServerCreator;
    window.stopServerCreator = stopServerCreator;
    window.toggleBananaMode = toggleBananaMode;
    window.checkControlPanelStatus = checkControlPanelStatus;
    window.updateServerCostDisplay = updateServerCostDisplay;
